export default "<template>\r\n  <div class=\"demo-edge-lifecycle\">\r\n    <!-- 事件日志面板 -->\r\n    <div class=\"demo-edge-lifecycle__log\">\r\n      <div class=\"demo-edge-lifecycle__log-header\">\r\n        <h4>事件日志</h4>\r\n        <button class=\"demo-edge-lifecycle__clear-btn\" @click=\"clearLogs\" title=\"清除日志\">\r\n          清除\r\n        </button>\r\n      </div>\r\n      <div class=\"demo-edge-lifecycle__log-content\">\r\n        <div v-for=\"(log, index) in logs\" :key=\"index\" class=\"demo-edge-lifecycle__log-item\">\r\n          {{ log }}\r\n        </div>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- 画布容器 -->\r\n    <div class=\"demo-edge-lifecycle__canvas\">\r\n      <div class=\"demo-edge-lifecycle__tip\">\r\n        💡 鼠标悬停到节点上会显示连接桩，拖拽连接桩来创建连线。选中连线后按 Delete 或 Backspace 删除。\r\n      </div>\r\n      <div class=\"demo-edge-lifecycle__controls\">\r\n        <label class=\"demo-edge-lifecycle__checkbox\">\r\n          <input type=\"checkbox\" v-model=\"allowAdd\" />\r\n          允许创建连线\r\n        </label>\r\n        <label class=\"demo-edge-lifecycle__checkbox\">\r\n          <input type=\"checkbox\" v-model=\"allowRemove\" />\r\n          允许删除连线\r\n        </label>\r\n      </div>\r\n      <FlowDesignerLayout\r\n        @ready=\"handleReady\"\r\n        :before-edge-add=\"handleBeforeEdgeAdd\"\r\n        :after-edge-add=\"handleAfterEdgeAdd\"\r\n        :before-edge-remove=\"handleBeforeEdgeRemove\"\r\n        :after-edge-remove=\"handleAfterEdgeRemove\"\r\n      />\r\n    </div>\r\n  </div>\r\n</template>\r\n\r\n<script setup lang=\"ts\">\r\nimport { ref } from 'vue'\r\nimport FlowDesignerLayout from '@/components/FlowDesigner/FlowDesignerLayout.vue'\r\nimport type { FlowDesigner } from '@/components/FlowDesigner/core'\r\nimport type { Graph } from '@antv/x6'\r\nimport type {\r\n  BeforeEdgeAddEvent,\r\n  AfterEdgeAddEvent,\r\n  BeforeEdgeRemoveEvent,\r\n  AfterEdgeRemoveEvent\r\n} from '@/components/FlowDesigner/types/events'\r\n\r\nconst logs = ref<string[]>([])\r\nconst allowAdd = ref(true)\r\nconst allowRemove = ref(true)\r\nconst designerRef = ref<FlowDesigner>()\r\n\r\nfunction addLog(message: string) {\r\n  const timestamp = new Date().toLocaleTimeString()\r\n  logs.value.push(`[${timestamp}] ${message}`)\r\n}\r\n\r\nfunction clearLogs() {\r\n  logs.value = []\r\n}\r\n\r\nfunction handleReady(designer: FlowDesigner, graph: Graph) {\r\n  designerRef.value = designer\r\n  addLog('✅ 画布初始化完成')\r\n\r\n  // 定义连接桩配置\r\n  const ports = {\r\n    groups: {\r\n      top: {\r\n        position: 'top',\r\n        attrs: {\r\n          circle: {\r\n            r: 4,\r\n            magnet: true,\r\n            stroke: '#5F95FF',\r\n            strokeWidth: 1,\r\n            fill: '#fff',\r\n            style: {\r\n              visibility: 'hidden',\r\n            },\r\n          },\r\n        },\r\n      },\r\n      right: {\r\n        position: 'right',\r\n        attrs: {\r\n          circle: {\r\n            r: 4,\r\n            magnet: true,\r\n            stroke: '#5F95FF',\r\n            strokeWidth: 1,\r\n            fill: '#fff',\r\n            style: {\r\n              visibility: 'hidden',\r\n            },\r\n          },\r\n        },\r\n      },\r\n      bottom: {\r\n        position: 'bottom',\r\n        attrs: {\r\n          circle: {\r\n            r: 4,\r\n            magnet: true,\r\n            stroke: '#5F95FF',\r\n            strokeWidth: 1,\r\n            fill: '#fff',\r\n            style: {\r\n              visibility: 'hidden',\r\n            },\r\n          },\r\n        },\r\n      },\r\n      left: {\r\n        position: 'left',\r\n        attrs: {\r\n          circle: {\r\n            r: 4,\r\n            magnet: true,\r\n            stroke: '#5F95FF',\r\n            strokeWidth: 1,\r\n            fill: '#fff',\r\n            style: {\r\n              visibility: 'hidden',\r\n            },\r\n          },\r\n        },\r\n      },\r\n    },\r\n    items: [\r\n      { id: 'port-top', group: 'top' },\r\n      { id: 'port-right', group: 'right' },\r\n      { id: 'port-bottom', group: 'bottom' },\r\n      { id: 'port-left', group: 'left' },\r\n    ],\r\n  }\r\n\r\n  // 使用 designer.addCell 添加带连接桩的节点\r\n  const node1 = graph.createNode({\r\n    id: 'node1',\r\n    shape: 'rect',\r\n    x: 100,\r\n    y: 100,\r\n    width: 100,\r\n    height: 60,\r\n    label: '节点1',\r\n    ports,\r\n    attrs: {\r\n      body: { fill: '#5F95FF', stroke: '#2563EB' },\r\n      label: { fill: '#fff' },\r\n    },\r\n  })\r\n  designer.addCell(node1)\r\n\r\n  const node2 = graph.createNode({\r\n    id: 'node2',\r\n    shape: 'rect',\r\n    x: 300,\r\n    y: 100,\r\n    width: 100,\r\n    height: 60,\r\n    label: '节点2',\r\n    ports,\r\n    attrs: {\r\n      body: { fill: '#10B981', stroke: '#059669' },\r\n      label: { fill: '#fff' },\r\n    },\r\n  })\r\n  designer.addCell(node2)\r\n\r\n  const node3 = graph.createNode({\r\n    id: 'node3',\r\n    shape: 'rect',\r\n    x: 100,\r\n    y: 220,\r\n    width: 100,\r\n    height: 60,\r\n    label: '节点3',\r\n    ports,\r\n    attrs: {\r\n      body: { fill: '#F59E0B', stroke: '#D97706' },\r\n      label: { fill: '#fff' },\r\n    },\r\n  })\r\n  designer.addCell(node3)\r\n\r\n  const node4 = graph.createNode({\r\n    id: 'node4',\r\n    shape: 'rect',\r\n    x: 300,\r\n    y: 220,\r\n    width: 100,\r\n    height: 60,\r\n    label: '节点4',\r\n    ports,\r\n    attrs: {\r\n      body: { fill: '#EF4444', stroke: '#DC2626' },\r\n      label: { fill: '#fff' },\r\n    },\r\n  })\r\n  designer.addCell(node4)\r\n\r\n  addLog('📦 已添加 4 个带连接桩的节点')\r\n  addLog('💡 拖拽节点边缘的圆点来创建连线')\r\n  graph.centerContent()\r\n}\r\n\r\n/**\r\n * :before-edge-add 钩子函数\r\n * 返回 false 可阻止连线创建\r\n */\r\nfunction handleBeforeEdgeAdd(event: BeforeEdgeAddEvent): boolean {\r\n  addLog(`🔵 beforeEdgeAdd 触发`)\r\n  addLog(`  源节点: ${event.sourceCell?.id}`)\r\n  addLog(`  目标节点: ${event.targetCell?.id}`)\r\n  addLog(`  允许创建: ${allowAdd.value}`)\r\n\r\n  if (!allowAdd.value) {\r\n    addLog(`❌ 连线创建被阻止`)\r\n    return false // 返回 false 阻止操作\r\n  }\r\n\r\n  addLog(`✅ 允许创建连线`)\r\n  return true // 返回 true 允许操作\r\n}\r\n\r\n/**\r\n * :after-edge-add 钩子函数\r\n */\r\nfunction handleAfterEdgeAdd(event: AfterEdgeAddEvent): void {\r\n  addLog(`🟢 afterEdgeAdd 触发`)\r\n  addLog(`  连线ID: ${event.edgeId}`)\r\n  addLog(`  连线已成功添加到画布`)\r\n}\r\n\r\n/**\r\n * :before-edge-remove 钩子函数\r\n * 返回 false 可阻止连线删除\r\n */\r\nfunction handleBeforeEdgeRemove(event: BeforeEdgeRemoveEvent): boolean {\r\n  addLog(`🟡 beforeEdgeRemove 触发`)\r\n  addLog(`  连线ID: ${event.edgeId}`)\r\n  addLog(`  来源: ${event.source}`)\r\n  addLog(`  允许删除: ${allowRemove.value}`)\r\n\r\n  if (!allowRemove.value) {\r\n    addLog(`❌ 连线删除被阻止`)\r\n    return false // 返回 false 阻止操作\r\n  }\r\n\r\n  addLog(`✅ 允许删除连线`)\r\n  return true // 返回 true 允许操作\r\n}\r\n\r\n/**\r\n * :after-edge-remove 钩子函数\r\n */\r\nfunction handleAfterEdgeRemove(event: AfterEdgeRemoveEvent): void {\r\n  addLog(`🔴 afterEdgeRemove 触发`)\r\n  addLog(`  连线ID: ${event.edgeId}`)\r\n  addLog(`  连线已从画布中移除`)\r\n}\r\n</script>\r\n\r\n<style scoped>\r\n.demo-edge-lifecycle {\r\n  display: flex;\r\n  height: 100%; /* 修改：从固定高度改为 100%，支持全屏 */\r\n  min-height: 450px; /* 添加：最小高度，非全屏时保持合理尺寸 */\r\n  gap: 16px;\r\n}\r\n\r\n.demo-edge-lifecycle__log {\r\n  width: 320px;\r\n  border: 1px solid #e8e8e8;\r\n  border-radius: 8px;\r\n  padding: 16px;\r\n  background: #fafafa;\r\n  overflow: hidden;\r\n  display: flex;\r\n  flex-direction: column;\r\n}\r\n\r\n.demo-edge-lifecycle__log-header {\r\n  display: flex;\r\n  justify-content: space-between;\r\n  align-items: center;\r\n  margin-bottom: 12px;\r\n}\r\n\r\n.demo-edge-lifecycle__log h4 {\r\n  margin: 0;\r\n  font-size: 14px;\r\n  color: #1a1a2e;\r\n  font-weight: 600;\r\n}\r\n\r\n.demo-edge-lifecycle__clear-btn {\r\n  padding: 2px 8px;\r\n  font-size: 12px;\r\n  color: #666;\r\n  background: #fff;\r\n  border: 1px solid #d9d9d9;\r\n  border-radius: 4px;\r\n  cursor: pointer;\r\n  transition: all 0.2s;\r\n  user-select: none;\r\n}\r\n\r\n.demo-edge-lifecycle__clear-btn:hover {\r\n  color: #1890ff;\r\n  border-color: #1890ff;\r\n}\r\n\r\n.demo-edge-lifecycle__log-content {\r\n  flex: 1;\r\n  overflow-y: auto;\r\n  font-size: 12px;\r\n  line-height: 1.8;\r\n}\r\n\r\n.demo-edge-lifecycle__log-item {\r\n  padding: 4px 0;\r\n  color: #555;\r\n  font-family: 'Monaco', 'Menlo', 'Consolas', monospace;\r\n  border-bottom: 1px solid #f0f0f0;\r\n}\r\n\r\n.demo-edge-lifecycle__log-item:last-child {\r\n  border-bottom: none;\r\n}\r\n\r\n.demo-edge-lifecycle__canvas {\r\n  flex: 1;\r\n  border: 1px solid #e8e8e8;\r\n  border-radius: 8px;\r\n  overflow: hidden;\r\n  background: #fff;\r\n  display: flex;\r\n  flex-direction: column;\r\n}\r\n\r\n.demo-edge-lifecycle__tip {\r\n  padding: 10px 16px;\r\n  background: #e6f7ff;\r\n  border-bottom: 1px solid #91d5ff;\r\n  font-size: 13px;\r\n  color: #0050b3;\r\n}\r\n\r\n.demo-edge-lifecycle__controls {\r\n  display: flex;\r\n  gap: 16px;\r\n  align-items: center;\r\n  padding: 10px 16px;\r\n  background: #fff;\r\n  border-bottom: 1px solid #e8e8e8;\r\n}\r\n\r\n.demo-edge-lifecycle__checkbox {\r\n  display: flex;\r\n  align-items: center;\r\n  gap: 6px;\r\n  font-size: 13px;\r\n  color: #666;\r\n  cursor: pointer;\r\n}\r\n\r\n.demo-edge-lifecycle__checkbox input {\r\n  cursor: pointer;\r\n}\r\n\r\n/* 连接桩样式 - 鼠标悬停时显示 */\r\n:deep(.x6-node:hover .x6-port-body) {\r\n  visibility: visible !important;\r\n}\r\n\r\n:deep(.x6-port-body) {\r\n  transition: all 0.2s;\r\n}\r\n\r\n:deep(.x6-node:hover .x6-port-body circle) {\r\n  stroke: #1677ff;\r\n  stroke-width: 2;\r\n  fill: #fff;\r\n}\r\n</style>\r\n"