export default "<template>\r\n  <div class=\"node-approval\" :class=\"{ 'node-approval--selected': isSelected }\">\r\n    <div class=\"body\">\r\n      <img v-if=\"!isSelected\" :src=\"approvalSvg\" />\r\n      <img v-if=\"isSelected\" :src=\"approvalSvgHover\" />\r\n      <div class=\"info\">\r\n        <div class=\"name\">{{ label || '审批人节点' }}</div>\r\n      </div>\r\n    </div>\r\n  </div>\r\n</template>\r\n\r\n<script setup lang=\"ts\">\r\nimport { ref, onMounted, onUnmounted, computed, inject } from 'vue'\r\nimport type { Node, Graph } from '@antv/x6'\r\nimport type { FlowNodeData } from '../types/flow.types'\r\nimport approvalSvg from '../icons/approval.svg';\r\nimport approvalSvgHover from '../icons/approval-hover.svg';\r\n\r\nconst props     = defineProps<{ node: Node }>()\r\nconst getGraph  = inject<() => Graph>('getGraph')\r\n\r\nconst nodeData   = ref<FlowNodeData>(props.node.getData() ?? {})\r\nconst isSelected = ref(false)\r\nconst label = ref('')\r\n\r\nconst updateNodeData = () => {\r\n  nodeData.value = props.node.getData() ?? {}\r\n  label.value = props.node.getProp('label');\r\n}\r\n\r\nonMounted(() => {\r\n  props.node.on('change:data', updateNodeData)\r\n  const graph = getGraph?.()\r\n  if (graph) {\r\n    graph.on('cell:selected',   ({ cell }) => { if (cell.id === props.node.id) isSelected.value = true  })\r\n    graph.on('cell:unselected', ({ cell }) => { if (cell.id === props.node.id) isSelected.value = false })\r\n  }\r\n})\r\n\r\nonUnmounted(() => {\r\n  props.node.off('change:data', updateNodeData)\r\n})\r\n\r\nconst approverText = computed(() => {\r\n  if (nodeData.value.approverType === 'superior') return '发起人上级'\r\n  if (nodeData.value.approverType === 'deptHead') return '部门负责人'\r\n  if (nodeData.value.approverType === 'role') return nodeData.value.roles?.join('、') || '未配置角色'\r\n  return nodeData.value.approvers?.join('、') || '未配置审批人'\r\n})\r\n</script>\r\n\r\n<style scoped>\r\n.node-approval {\r\n  width: 100%;\r\n  height: 100%;\r\n  background: #e6eeff;\r\n  border: 1px solid #83b3f7;\r\n  border-radius: 8px; overflow: hidden;\r\n  box-shadow: 0 2px 8px rgba(0,0,0,.08);\r\n  display: flex; flex-direction: column;\r\n  user-select: none;\r\n  transition: box-shadow 0.2s, border-color 0.2s;\r\n}\r\n.node-approval:hover {\r\n  border: 2px solid #83b3f7;\r\n  -background: #f1f5f1;\r\n}\r\n.node-approval--selected {\r\n  border: 2px solid #003eca;\r\n  background: #1d78f4;\r\n  box-shadow: 0 0 0 3px rgba(245,34,45,0.15), 0 2px 8px rgba(0,0,0,.08);\r\n}\r\n.node-approval--selected .name{\r\n  color: white;\r\n}\r\n.body { flex: 1; display: flex; align-items: center; padding: 0 12px; gap: 10px; }\r\n.info { overflow: hidden; flex: 1; }\r\n.name { font-size: 13px; color: #5d9df7; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; font-weight: 390}\r\n</style>\r\n"