export default "<template>\n  <div class=\"demo-node-svg\">\n    <!-- 事件日志面板 -->\n    <div class=\"demo-node-svg__log\">\n      <div class=\"demo-node-svg__log-header\">\n        <h4>事件日志</h4>\n        <button class=\"demo-node-svg__clear-btn\" @click=\"clearLogs\" title=\"清除日志\">\n          清除\n        </button>\n      </div>\n      <div class=\"demo-node-svg__log-content\">\n        <div v-for=\"(log, index) in logs\" :key=\"index\" class=\"demo-node-svg__log-item\">\n          {{ log }}\n        </div>\n      </div>\n    </div>\n\n    <!-- 画布容器 -->\n    <div class=\"demo-node-svg__canvas\">\n      <FlowDesignerLayout\n        mode=\"design\"\n        :before-graph-init=\"handleBeforeGraphInit\"\n        @ready=\"handleReady\"\n      >\n        <!-- 自定义节点面板插槽 -->\n        <template #palette=\"{ onStartDrag }\">\n          <div class=\"custom-palette\">\n            <div class=\"custom-palette__header\">\n              <h3 class=\"custom-palette__title\">VUE 节点</h3>\n              <span class=\"custom-palette__desc\">三种状态切换</span>\n            </div>\n\n            <div class=\"custom-palette__section\">\n              <div class=\"custom-palette__section-title\">带图标的节点</div>\n              <div\n                v-for=\"nodeType in nodeTypesConfig\"\n                :key=\"nodeType.type\"\n                class=\"custom-palette__item\"\n                @mousedown=\"(e) => handleStartDrag(e, nodeType, onStartDrag)\"\n                :style=\"{ background: nodeType.rectFill, borderColor: nodeType.rectStroke}\"\n              >\n                <div class=\"custom-palette__item-icon\" >\n                  <img :src=\"nodeType.icon\" />\n                </div>\n                <div class=\"custom-palette__item-info\">\n                  <div class=\"custom-palette__item-label\" :style=\"{ color: nodeType.textFill}\">{{ nodeType.label }}</div>\n                </div>\n              </div>\n\n            </div>\n\n            <div class=\"custom-palette__tips\">\n              <div class=\"tips-title\">💡 交互说明</div>\n              <ul class=\"tips-list\">\n                <li><strong>Default:</strong> 白底 + 彩色图标</li>\n                <li><strong>Hover:</strong> 淡色背景</li>\n                <li><strong>Selected:</strong> 彩底 + 白色图标</li>\n              </ul>\n            </div>\n          </div>\n        </template>\n      </FlowDesignerLayout>\n    </div>\n  </div>\n</template>\n\n<script setup lang=\"ts\">\nimport { ref } from 'vue'\nimport FlowDesignerLayout from '@/components/FlowDesigner/FlowDesignerLayout.vue'\nimport type { FlowDesigner, FlowDesignerOptions } from '@/components/FlowDesigner/core'\nimport { Graph, Node } from '@antv/x6'\nimport StartNode from './components/StartNode.vue'\nimport ApproverNode from './components/ApproverNode.vue'\n\n\nimport startSvg from \"./icons/start.svg\";\nimport startHover from \"./icons/start-hover.svg\";\n\nimport approvalSvg from \"./icons/approval.svg\";\nimport approvalHoverSvg from \"./icons/approval-hover.svg\";\nimport {register} from \"@antv/x6-vue-shape\";\n\n\n\nconst logs = ref<string[]>([])\n\n// 节点类型配置（包含颜色和 iconPath）\ninterface NodeTypeConfig {\n  type: string\n  label: string\n  hint: string\n  color: string\n  hoverColor: string\n  iconPath: string\n  width: number\n  height: number\n}\n\nconst nodeTypesConfig: any[] = [\n  {\n    type: 'vue-start-node',\n    label: '开始节点',\n    classNamePerfix: 'x6',\n    width: 120,\n    height: 38,\n    rectStroke: '#95d375',\n    rectStrokeWidth: 1,\n    rectFill: '#edf8e7',\n    icon: startSvg,\n    iconHover: startHover,\n    textFill: '#81cb5c'\n  },\n  {\n    type: 'vue-approval-node',\n    label: '审批节点',\n    classNamePerfix: 'x6',\n    width: 120,\n    height: 38,\n    rectStroke: '#83b3f7',\n    rectStrokeWidth: 1,\n    rectFill: '#e6eeff',\n    icon: approvalSvg,\n    iconHover: approvalHoverSvg,\n    textFill: '#5d9df7'\n  },\n]\n\nconst Ports = {\n  groups: {\n    top: {\n      position: 'top',\n      attrs: {\n        circle: {\n          r: 4,\n          magnet: true,\n          stroke: '#5F95FF',\n          strokeWidth: 1,\n          fill: '#fff',\n          style: {\n            visibility: 'hidden',\n          },\n        },\n        label: {\n          position: 'top',\n        },\n        text: {\n          text: '',\n          fill: '#ff5800',\n        },\n      },\n    },\n    right: {\n      position: 'right',\n      attrs: {\n        circle: {\n          r: 4,\n          magnet: true,\n          stroke: '#5F95FF',\n          strokeWidth: 1,\n          fill: '#fff',\n          style: {\n            visibility: 'hidden',\n          },\n        },\n        label: {\n          position: 'right',\n        },\n        text: {\n          text: '',\n          fill: '#ff5800',\n        },\n      },\n    },\n    bottom: {\n      position: 'bottom',\n      attrs: {\n        circle: {\n          r: 4,\n          magnet: true,\n          stroke: '#5F95FF',\n          strokeWidth: 1,\n          fill: '#fff',\n          style: {\n            visibility: 'hidden',\n          },\n        },\n        label: {\n          position: 'bottom',\n        },\n        text: {\n          text: '',\n          fill: '#ff5800',\n        },\n      },\n    },\n    left: {\n      position: 'left',\n      attrs: {\n        circle: {\n          r: 4,\n          magnet: true,\n          stroke: '#5F95FF',\n          strokeWidth: 1,\n          fill: '#fff',\n          style: {\n            visibility: 'hidden',\n          },\n        },\n        label: {\n          position: 'left',\n        },\n        text: {\n          text: '',\n          fill: '#ff5800',\n        },\n      },\n    },\n  },\n  items: [\n    {\n      group: 'top',\n      label: {\n        position : 'top'\n      }\n    },\n    {\n      group: 'right',\n      label: {\n        position : 'right'\n      }\n    },\n    {\n      group: 'bottom',\n      label: {\n        position : 'bottom'\n      }\n    },\n    {\n      group: 'left',\n      label: {\n        position : 'left'\n      }\n    },\n  ],\n}\n\n\n// 手动跟踪节点的选中状态（因为 X6 的 selection 可能有默认行为）\nconst selectedNodesMap = new Map<string, boolean>()\n\nfunction addLog(message: string) {\n  const timestamp = new Date().toLocaleTimeString()\n  logs.value.push(`[${timestamp}] ${message}`)\n}\n\nfunction clearLogs() {\n  logs.value = []\n}\n\n\n\n/**\n * Graph 初始化前钩子：注册带 SVG icon 的自定义节点\n */\nfunction handleBeforeGraphInit(options: FlowDesignerOptions) {\n  addLog('🔧 beforeGraphInit: 开始注册 SVG 节点')\n\n  register({\n    shape: 'vue-start-node',\n    width: 120, height: 38,\n    component: StartNode,\n    ports: { ...Ports },\n  })\n\n  register({\n    shape: 'vue-approval-node',\n    width: 120, height: 38,\n    component: ApproverNode,\n    ports: { ...Ports },\n  })\n\n  addLog('🎉 所有 SVG 节点注册完成')\n}\n\nfunction handleReady(designer: FlowDesigner, graph: Graph) {\n  addLog('✅ 画布初始化完成')\n  addLog('💡 提示: 悬停查看 hover 效果，点击切换 selected 状态')\n\n\n  // ─── 添加示例节点 ───────────────────────────────────────────────────\n  setTimeout(() => {\n    graph.addNode({\n      shape: 'vue-start-node',\n      x: 100,\n      y: 100,\n      label: '开始节点',\n    })\n\n    addLog('📦 已添加 3 个示例节点')\n    addLog('🎨 试试悬停和点击节点吧！')\n  }, 100)\n}\n\nfunction handleStartDrag(e: MouseEvent, nodeType: NodeTypeConfig, onStartDrag: any) {\n  addLog(`🎯 开始拖拽: ${nodeType.label}`)\n\n  onStartDrag(e, {\n    shape: nodeType.type,\n    label: nodeType.label,\n    width: nodeType.width,\n    height: nodeType.height,\n    data: {\n      label: nodeType.label,\n      nodeInfo: {\n        hint: nodeType.hint,\n        color: nodeType.color,\n      }\n    }\n  })\n}\n</script>\n\n<style scoped>\n.demo-node-svg {\n  display: flex;\n  height: 100%;\n  min-height: 600px;\n  gap: 16px;\n}\n\n.demo-node-svg__log {\n  width: 280px;\n  border: 1px solid #e8e8e8;\n  border-radius: 8px;\n  padding: 16px;\n  background: #fafafa;\n  overflow: hidden;\n  display: flex;\n  flex-direction: column;\n}\n\n.demo-node-svg__log-header {\n  display: flex;\n  justify-content: space-between;\n  align-items: center;\n  margin-bottom: 12px;\n}\n\n.demo-node-svg__log h4 {\n  margin: 0;\n  font-size: 14px;\n  color: #1a1a2e;\n  font-weight: 600;\n}\n\n.demo-node-svg__clear-btn {\n  padding: 2px 8px;\n  font-size: 12px;\n  color: #666;\n  background: #fff;\n  border: 1px solid #d9d9d9;\n  border-radius: 4px;\n  cursor: pointer;\n  transition: all 0.2s;\n  user-select: none;\n}\n\n.demo-node-svg__clear-btn:hover {\n  color: #1890ff;\n  border-color: #1890ff;\n}\n\n.demo-node-svg__log-content {\n  flex: 1;\n  overflow-y: auto;\n  font-size: 12px;\n  line-height: 1.8;\n}\n\n.demo-node-svg__log-item {\n  padding: 4px 0;\n  color: #555;\n  font-family: 'Monaco', 'Menlo', 'Consolas', monospace;\n  border-bottom: 1px solid #f0f0f0;\n}\n\n.demo-node-svg__log-item:last-child {\n  border-bottom: none;\n}\n\n.demo-node-svg__canvas {\n  flex: 1;\n  border: 1px solid #e8e8e8;\n  border-radius: 8px;\n  overflow: hidden;\n  background: #fff;\n}\n\n/* ==================== 自定义节点面板样式 ==================== */\n.custom-palette {\n  display: flex;\n  flex-direction: column;\n  height: 100%;\n  background: linear-gradient(to bottom, #f9fafb, #ffffff);\n  border-right: 1px solid #e8e8e8;\n  width: 200px;\n}\n\n.custom-palette__header {\n  padding: 16px;\n  border-bottom: 2px solid #e8e8e8;\n  background: #fff;\n}\n\n.custom-palette__title {\n  margin: 0 0 4px 0;\n  font-size: 16px;\n  font-weight: 600;\n  color: #1a1a2e;\n}\n\n.custom-palette__desc {\n  font-size: 12px;\n  color: #999;\n}\n\n.custom-palette__section {\n  padding: 12px;\n}\n\n.custom-palette__section-title {\n  font-size: 11px;\n  font-weight: 600;\n  color: #999;\n  text-transform: uppercase;\n  letter-spacing: 0.06em;\n  margin-bottom: 8px;\n  padding: 0 4px;\n}\n\n.custom-palette__item {\n  display: flex;\n  align-items: center;\n  gap: 12px;\n  padding: 10px;\n  margin-bottom: 8px;\n  background: #fff;\n  border: 1px solid #e8e8e8;\n  border-radius: 12px;\n  cursor: move;\n  transition: all 0.2s;\n  user-select: none;\n  width: 160px;\n  height: 50px;\n}\n\n.custom-palette__item:hover {\n  border-color: #1677ff;\n  box-shadow: 0 2px 8px rgba(22, 119, 255, 0.15);\n  transform: translateY(-1px);\n}\n\n.custom-palette__item:active {\n  transform: translateY(0);\n  box-shadow: 0 1px 4px rgba(22, 119, 255, 0.2);\n}\n\n.custom-palette__item-icon {\n  width: 36px;\n  height: 36px;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  border-radius: 6px;\n  flex-shrink: 0;\n}\n\n.custom-palette__item-info {\n  flex: 1;\n  min-width: 0;\n}\n\n.custom-palette__item-label {\n  font-size: 13px;\n  font-weight: 500;\n  color: #333;\n  margin-bottom: 2px;\n}\n\n.custom-palette__item-hint {\n  font-size: 11px;\n  color: #999;\n  white-space: nowrap;\n  overflow: hidden;\n  text-overflow: ellipsis;\n}\n\n/* ==================== 交互说明 ==================== */\n.custom-palette__tips {\n  margin-top: auto;\n  padding: 12px;\n  background: #fff9e6;\n  border-top: 1px solid #ffe58f;\n}\n\n.tips-title {\n  font-size: 12px;\n  font-weight: 600;\n  color: #d48806;\n  margin-bottom: 8px;\n}\n\n.tips-list {\n  margin: 0;\n  padding-left: 16px;\n  font-size: 11px;\n  line-height: 1.8;\n  color: #8c8c8c;\n}\n\n.tips-list li {\n  margin-bottom: 4px;\n}\n\n.tips-list strong {\n  color: #595959;\n}\n\n</style>\n\n\n<!--如果需要简单控制节点样式，需要将此节点样式暴露到全局,适当增加前缀以防止污染-->\n<style>\n.x6-svg-start-node-body:hover{\n  stroke-width: 2px;\n  fill: #caf1c1;\n}\n.x6-node-selected .x6-svg-start-node-body{\n  stroke: #48c02a;\n  stroke-width: 2px;\n  fill: #8fd16f\n}\n.x6-node-selected .x6-svg-start-node-image {\n  display: none;\n}\n.x6-node-selected .x6-svg-start-node-imageHover {\n  display: block;\n}\n.x6-node-selected .x6-svg-start-node-label {\n  fill: #ffffff\n}\n\n.x6-node-selected .x6-svg-approval-node-body{\n  stroke: #003eca;\n  stroke-width: 2px;\n  fill: #1d78f4\n}\n.x6-node-selected .x6-svg-approval-node-image {\n  display: none;\n}\n\n.x6-node-selected .x6-svg-approval-node-imageHover {\n  display: block;\n}\n.x6-node-selected .x6-svg-approval-node-label {\n  fill: #ffffff\n}\n\n.x6-node-selected .x6-svg-condition-node-body{\n  stroke: #ffa100;\n  stroke-width: 2px;\n  fill: #fdc059\n}\n.x6-node-selected .x6-svg-condition-node-image {\n  display: none;\n}\n\n.x6-node-selected .x6-svg-condition-node-imageHover {\n  display: block;\n}\n.x6-node-selected .x6-svg-condition-node-label {\n  fill: #ffffff\n}\n\n</style>\n"