<template>
  <FlowDesignerLayout @ready="handleReady" />
</template>

<script setup lang="ts">
import { ref } from 'vue'
import FlowDesignerLayout from '../../../../components/FlowDesigner/FlowDesignerLayout.vue'
import type { FlowDesigner } from '../../../../components/FlowDesigner/core'

/**
 * ready 回调：获取 graph 实例并添加原生节点和连线
 */
function handleReady(designer: FlowDesigner) {
  // 获取 X6 Graph 实例
  const graph = designer.getGraph()
  // 添加节点 1：矩形节点
  const node1 = graph.addNode({
    id: 'node1',
    shape: 'rect', // X6 内置的矩形节点
    x: 100,
    y: 100,
    width: 120,
    height: 60,
    label: '节点 1',
    attrs: {
      body: {
        fill: '#5F95FF',
        stroke: '#2563EB',
        strokeWidth: 2,
      },
      label: {
        fill: '#ffffff',
        fontSize: 14,
        fontWeight: 'bold',
      },
    },
  })

  // 添加节点 2：圆形节点
  const node2 = graph.addNode({
    id: 'node2',
    shape: 'circle', // X6 内置的圆形节点
    x: 300,
    y: 100,
    width: 80,
    height: 80,
    label: '节点 2',
    attrs: {
      body: {
        fill: '#10B981',
        stroke: '#059669',
        strokeWidth: 2,
      },
      label: {
        fill: '#ffffff',
        fontSize: 14,
        fontWeight: 'bold',
      },
    },
  })

  // 添加节点 3：椭圆节点
  const node3 = graph.addNode({
    id: 'node3',
    shape: 'ellipse', // X6 内置的椭圆节点
    x: 500,
    y: 100,
    width: 100,
    height: 60,
    label: '节点 3',
    attrs: {
      body: {
        fill: '#F59E0B',
        stroke: '#D97706',
        strokeWidth: 2,
      },
      label: {
        fill: '#ffffff',
        fontSize: 14,
        fontWeight: 'bold',
      },
    },
  })

  // 添加节点 4：菱形节点
  const node4 = graph.addNode({
    id: 'node4',
    shape: 'polygon', // X6 内置的多边形节点（菱形）
    x: 300,
    y: 250,
    width: 100,
    height: 100,
    label: '节点 4',
    attrs: {
      body: {
        fill: '#EF4444',
        stroke: '#DC2626',
        strokeWidth: 2,
        refPoints: '0,10 10,0 20,10 10,20', // 菱形的四个顶点
      },
      label: {
        fill: '#ffffff',
        fontSize: 14,
        fontWeight: 'bold',
      },
    },
  })

  // 添加连线 1：node1 -> node2（使用 flow-edge）
  graph.addEdge({
    id: 'edge1',
    shape: 'flow-edge', // 使用自定义连线类型
    source: node1,
    target: node2,
    labels: ['连线 1'], // 简化的 label 写法
  })

  // 添加连线 2：node2 -> node3（使用 flow-edge）
  graph.addEdge({
    id: 'edge2',
    shape: 'flow-edge', // 使用自定义连线类型
    source: node2,
    target: node3,
    labels: ['连线 2'], // 简化的 label 写法
  })

  // 添加连线 3：node2 -> node4（使用 flow-edge）
  graph.addEdge({
    id: 'edge3',
    shape: 'flow-edge', // 使用自定义连线类型
    source: node2,
    target: node4,
    labels: ['连线 3'], // 简化的 label 写法
  })

  // 添加连线 4：node4 -> node3（使用 flow-edge）
  graph.addEdge({
    id: 'edge4',
    shape: 'flow-edge', // 使用自定义连线类型
    source: node4,
    target: node3,
    labels: ['连线 4'], // 简化的 label 写法
  })

  // 调整视图，使所有节点居中显示
  graph.centerContent()

  console.log('[Demo1] Graph 实例已获取，已添加 4 个节点和 4 条连线')
}
</script>

