<template>
  <div class="demo-slot-palette">
    <!-- 事件日志面板 -->
    <div class="demo-slot-palette__log">
      <div class="demo-slot-palette__log-header">
        <h4>事件日志</h4>
        <button class="demo-slot-palette__clear-btn" @click="clearLogs" title="清除日志">
          清除
        </button>
      </div>
      <div class="demo-slot-palette__log-content">
        <div v-for="(log, index) in logs" :key="index" class="demo-slot-palette__log-item">
          {{ log }}
        </div>
      </div>
    </div>

    <!-- 画布容器 -->
    <div class="demo-slot-palette__canvas">
      <FlowDesignerLayout
        mode="design"
        :before-graph-init="handleBeforeGraphInit"
        @ready="handleReady"
      >
        <!-- 自定义节点面板插槽 -->
        <template #palette="{ onStartDrag }">
          <div class="custom-palette">
            <div class="custom-palette__header">
              <h3 class="custom-palette__title">自定义节点</h3>
              <span class="custom-palette__desc">拖拽到画布</span>
            </div>

            <div class="custom-palette__section">
              <div class="custom-palette__section-title">基础节点</div>
              <div
                v-for="nodeType in customNodeTypes"
                :key="nodeType.type"
                class="custom-palette__item"
                @mousedown="(e) => handleStartDrag(e, nodeType, onStartDrag)"
              >
                <div class="custom-palette__item-icon" :style="{ background: nodeType.color }">
                  {{ nodeType.icon }}
                </div>
                <div class="custom-palette__item-info">
                  <div class="custom-palette__item-label">{{ nodeType.label }}</div>
                  <div class="custom-palette__item-hint">{{ nodeType.hint }}</div>
                </div>
              </div>
            </div>
          </div>
        </template>
      </FlowDesignerLayout>
    </div>
  </div>
</template>

<script setup lang="ts">
import { ref } from 'vue'
import FlowDesignerLayout from '@/components/FlowDesigner/FlowDesignerLayout.vue'
import type { FlowDesigner, FlowDesignerOptions } from '@/components/FlowDesigner/core'
import { Graph } from '@antv/x6'

const logs = ref<string[]>([])
const customNodeTypes = ref([
  {
    type: 'custom-circle',
    label: '圆形节点',
    icon: '⚪',
    hint: '用于流程开始/结束',
    color: '#5F95FF',
    width: 80,
    height: 80,
  },
  {
    type: 'custom-diamond',
    label: '菱形节点',
    icon: '◆',
    hint: '用于条件判断',
    color: '#47C769',
    width: 100,
    height: 80,
  },
])

function addLog(message: string) {
  const timestamp = new Date().toLocaleTimeString()
  logs.value.push(`[${timestamp}] ${message}`)
}

function clearLogs() {
  logs.value = []
}

/**
 * Graph 初始化前钩子：注册自定义 X6 原生节点
 */
function handleBeforeGraphInit(options: FlowDesignerOptions) {
  addLog('🔧 beforeGraphInit: 开始注册自定义节点')

  // 注册第 1 个节点：圆形节点
  Graph.registerNode(
    'custom-circle',
    {
      inherit: 'circle',
      width: 80,
      height: 80,
      attrs: {
        body: {
          fill: '#5F95FF',
          stroke: '#2563EB',
          strokeWidth: 2,
        },
        label: {
          fill: '#fff',
          fontSize: 14,
          fontWeight: 500,
        },
      },
      ports: {
        groups: {
          top: {
            position: 'top',
            attrs: {
              circle: {
                r: 4,
                magnet: true,
                stroke: '#2563EB',
                strokeWidth: 1,
                fill: '#fff',
              },
            },
          },
          bottom: {
            position: 'bottom',
            attrs: {
              circle: {
                r: 4,
                magnet: true,
                stroke: '#2563EB',
                strokeWidth: 1,
                fill: '#fff',
              },
            },
          },
        },
        items: [
          { group: 'top', id: 'port-top' },
          { group: 'bottom', id: 'port-bottom' },
        ],
      },
    },
    true // 覆盖已存在的同名节点
  )

  addLog('✅ 已注册节点: custom-circle (圆形)')

  // 注册第 2 个节点：菱形节点
  Graph.registerNode(
    'custom-diamond',
    {
      inherit: 'polygon',
      width: 100,
      height: 80,
      attrs: {
        body: {
          fill: '#47C769',
          stroke: '#27AE60',
          strokeWidth: 2,
          refPoints: '0,10 10,0 20,10 10,20',
        },
        label: {
          fill: '#fff',
          fontSize: 13,
          fontWeight: 500,
          textWrap: {
            width: -20,
            height: -20,
            ellipsis: true,
          },
        },
      },
      ports: {
        groups: {
          top: {
            position: { name: 'top' },
            attrs: {
              circle: {
                r: 4,
                magnet: true,
                stroke: '#27AE60',
                strokeWidth: 1,
                fill: '#fff',
              },
            },
          },
          right: {
            position: { name: 'right' },
            attrs: {
              circle: {
                r: 4,
                magnet: true,
                stroke: '#27AE60',
                strokeWidth: 1,
                fill: '#fff',
              },
            },
          },
          bottom: {
            position: { name: 'bottom' },
            attrs: {
              circle: {
                r: 4,
                magnet: true,
                stroke: '#27AE60',
                strokeWidth: 1,
                fill: '#fff',
              },
            },
          },
          left: {
            position: { name: 'left' },
            attrs: {
              circle: {
                r: 4,
                magnet: true,
                stroke: '#27AE60',
                strokeWidth: 1,
                fill: '#fff',
              },
            },
          },
        },
        items: [
          { group: 'top', id: 'port-top' },
          { group: 'right', id: 'port-right' },
          { group: 'bottom', id: 'port-bottom' },
          { group: 'left', id: 'port-left' },
        ],
      },
    },
    true
  )

  addLog('✅ 已注册节点: custom-diamond (菱形)')
  addLog('🎉 所有自定义节点注册完成')
}

function handleReady(designer: FlowDesigner, graph: Graph) {
  addLog('✅ 画布初始化完成')
  addLog('🎨 自定义节点面板已渲染')
  addLog('💡 提示: 点击左侧节点拖拽到画布')
}

function handleStartDrag(e: MouseEvent, nodeType: any, onStartDrag: any) {
  addLog(`🎯 开始拖拽: ${nodeType.label}`)

  // 使用 palette 插槽提供的 onStartDrag 函数
  // 参数：(event, nodeConfig)
  // nodeConfig 是完整的 X6 Node.Metadata 对象
  onStartDrag(e, {
    shape: nodeType.type,
    label: nodeType.label,
    width: nodeType.width,
    height: nodeType.height,
    data: {
      label: nodeType.label,
      // 其他业务数据
      nodeInfo: {
        icon: nodeType.icon,
        hint: nodeType.hint,
        color: nodeType.color,
      }
    }
  })
}
</script>

<style scoped>
.demo-slot-palette {
  display: flex;
  height: 100%;
  min-height: 500px;
  gap: 16px;
}

.demo-slot-palette__log {
  width: 280px;
  border: 1px solid #e8e8e8;
  border-radius: 8px;
  padding: 16px;
  background: #fafafa;
  overflow: hidden;
  display: flex;
  flex-direction: column;
}

.demo-slot-palette__log-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 12px;
}

.demo-slot-palette__log h4 {
  margin: 0;
  font-size: 14px;
  color: #1a1a2e;
  font-weight: 600;
}

.demo-slot-palette__clear-btn {
  padding: 2px 8px;
  font-size: 12px;
  color: #666;
  background: #fff;
  border: 1px solid #d9d9d9;
  border-radius: 4px;
  cursor: pointer;
  transition: all 0.2s;
  user-select: none;
}

.demo-slot-palette__clear-btn:hover {
  color: #1890ff;
  border-color: #1890ff;
}

.demo-slot-palette__log-content {
  flex: 1;
  overflow-y: auto;
  font-size: 12px;
  line-height: 1.8;
}

.demo-slot-palette__log-item {
  padding: 4px 0;
  color: #555;
  font-family: 'Monaco', 'Menlo', 'Consolas', monospace;
  border-bottom: 1px solid #f0f0f0;
}

.demo-slot-palette__log-item:last-child {
  border-bottom: none;
}

.demo-slot-palette__canvas {
  flex: 1;
  border: 1px solid #e8e8e8;
  border-radius: 8px;
  overflow: hidden;
  background: #fff;
}

/* ==================== 自定义节点面板样式 ==================== */
.custom-palette {
  display: flex;
  flex-direction: column;
  height: 100%;
  background: linear-gradient(to bottom, #f9fafb, #ffffff);
  border-right: 1px solid #e8e8e8;
  width: 180px;
}

.custom-palette__header {
  padding: 16px;
  border-bottom: 2px solid #e8e8e8;
  background: #fff;
}

.custom-palette__title {
  margin: 0 0 4px 0;
  font-size: 16px;
  font-weight: 600;
  color: #1a1a2e;
}

.custom-palette__desc {
  font-size: 12px;
  color: #999;
}

.custom-palette__section {
  padding: 12px;
}

.custom-palette__section-title {
  font-size: 11px;
  font-weight: 600;
  color: #999;
  text-transform: uppercase;
  letter-spacing: 0.06em;
  margin-bottom: 8px;
  padding: 0 4px;
}

.custom-palette__item {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 10px;
  margin-bottom: 8px;
  background: #fff;
  border: 1px solid #e8e8e8;
  border-radius: 6px;
  cursor: move;
  transition: all 0.2s;
  user-select: none;
}

.custom-palette__item:hover {
  border-color: #1677ff;
  box-shadow: 0 2px 8px rgba(22, 119, 255, 0.15);
  transform: translateY(-1px);
}

.custom-palette__item:active {
  transform: translateY(0);
  box-shadow: 0 1px 4px rgba(22, 119, 255, 0.2);
}

.custom-palette__item-icon {
  width: 36px;
  height: 36px;
  display: flex;
  align-items: center;
  justify-content: center;
  border-radius: 6px;
  font-size: 18px;
  flex-shrink: 0;
}

.custom-palette__item-info {
  flex: 1;
  min-width: 0;
}

.custom-palette__item-label {
  font-size: 13px;
  font-weight: 500;
  color: #333;
  margin-bottom: 2px;
}

.custom-palette__item-hint {
  font-size: 11px;
  color: #999;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}
</style>
