export default "<template>\r\n  <FlowDesignerLayout @ready=\"handleReady\" />\r\n</template>\r\n\r\n<script setup lang=\"ts\">\r\nimport { ref } from 'vue'\r\nimport FlowDesignerLayout from '../../../../components/FlowDesigner/FlowDesignerLayout.vue'\r\nimport type { FlowDesigner } from '../../../../components/FlowDesigner/core'\r\n\r\n/**\r\n * ready 回调：获取 graph 实例并添加原生节点和连线\r\n */\r\nfunction handleReady(designer: FlowDesigner) {\r\n  // 获取 X6 Graph 实例\r\n  const graph = designer.getGraph()\r\n  // 添加节点 1：矩形节点\r\n  const node1 = graph.addNode({\r\n    id: 'node1',\r\n    shape: 'rect', // X6 内置的矩形节点\r\n    x: 100,\r\n    y: 100,\r\n    width: 120,\r\n    height: 60,\r\n    label: '节点 1',\r\n    attrs: {\r\n      body: {\r\n        fill: '#5F95FF',\r\n        stroke: '#2563EB',\r\n        strokeWidth: 2,\r\n      },\r\n      label: {\r\n        fill: '#ffffff',\r\n        fontSize: 14,\r\n        fontWeight: 'bold',\r\n      },\r\n    },\r\n  })\r\n\r\n  // 添加节点 2：圆形节点\r\n  const node2 = graph.addNode({\r\n    id: 'node2',\r\n    shape: 'circle', // X6 内置的圆形节点\r\n    x: 300,\r\n    y: 100,\r\n    width: 80,\r\n    height: 80,\r\n    label: '节点 2',\r\n    attrs: {\r\n      body: {\r\n        fill: '#10B981',\r\n        stroke: '#059669',\r\n        strokeWidth: 2,\r\n      },\r\n      label: {\r\n        fill: '#ffffff',\r\n        fontSize: 14,\r\n        fontWeight: 'bold',\r\n      },\r\n    },\r\n  })\r\n\r\n  // 添加节点 3：椭圆节点\r\n  const node3 = graph.addNode({\r\n    id: 'node3',\r\n    shape: 'ellipse', // X6 内置的椭圆节点\r\n    x: 500,\r\n    y: 100,\r\n    width: 100,\r\n    height: 60,\r\n    label: '节点 3',\r\n    attrs: {\r\n      body: {\r\n        fill: '#F59E0B',\r\n        stroke: '#D97706',\r\n        strokeWidth: 2,\r\n      },\r\n      label: {\r\n        fill: '#ffffff',\r\n        fontSize: 14,\r\n        fontWeight: 'bold',\r\n      },\r\n    },\r\n  })\r\n\r\n  // 添加节点 4：菱形节点\r\n  const node4 = graph.addNode({\r\n    id: 'node4',\r\n    shape: 'polygon', // X6 内置的多边形节点（菱形）\r\n    x: 300,\r\n    y: 250,\r\n    width: 100,\r\n    height: 100,\r\n    label: '节点 4',\r\n    attrs: {\r\n      body: {\r\n        fill: '#EF4444',\r\n        stroke: '#DC2626',\r\n        strokeWidth: 2,\r\n        refPoints: '0,10 10,0 20,10 10,20', // 菱形的四个顶点\r\n      },\r\n      label: {\r\n        fill: '#ffffff',\r\n        fontSize: 14,\r\n        fontWeight: 'bold',\r\n      },\r\n    },\r\n  })\r\n\r\n  // 添加连线 1：node1 -> node2（使用 flow-edge）\r\n  graph.addEdge({\r\n    id: 'edge1',\r\n    shape: 'flow-edge', // 使用自定义连线类型\r\n    source: node1,\r\n    target: node2,\r\n    labels: ['连线 1'], // 简化的 label 写法\r\n  })\r\n\r\n  // 添加连线 2：node2 -> node3（使用 flow-edge）\r\n  graph.addEdge({\r\n    id: 'edge2',\r\n    shape: 'flow-edge', // 使用自定义连线类型\r\n    source: node2,\r\n    target: node3,\r\n    labels: ['连线 2'], // 简化的 label 写法\r\n  })\r\n\r\n  // 添加连线 3：node2 -> node4（使用 flow-edge）\r\n  graph.addEdge({\r\n    id: 'edge3',\r\n    shape: 'flow-edge', // 使用自定义连线类型\r\n    source: node2,\r\n    target: node4,\r\n    labels: ['连线 3'], // 简化的 label 写法\r\n  })\r\n\r\n  // 添加连线 4：node4 -> node3（使用 flow-edge）\r\n  graph.addEdge({\r\n    id: 'edge4',\r\n    shape: 'flow-edge', // 使用自定义连线类型\r\n    source: node4,\r\n    target: node3,\r\n    labels: ['连线 4'], // 简化的 label 写法\r\n  })\r\n\r\n  // 调整视图，使所有节点居中显示\r\n  graph.centerContent()\r\n\r\n  console.log('[Demo1] Graph 实例已获取，已添加 4 个节点和 4 条连线')\r\n}\r\n</script>\r\n\r\n<style scoped>\r\n\r\n</style>\r\n"