<template>
  <div class="demo-node-svg">
    <!-- 事件日志面板 -->
    <div class="demo-node-svg__log">
      <div class="demo-node-svg__log-header">
        <h4>事件日志</h4>
        <button class="demo-node-svg__clear-btn" @click="clearLogs" title="清除日志">
          清除
        </button>
      </div>
      <div class="demo-node-svg__log-content">
        <div v-for="(log, index) in logs" :key="index" class="demo-node-svg__log-item">
          {{ log }}
        </div>
      </div>
    </div>

    <!-- 画布容器 -->
    <div class="demo-node-svg__canvas">
      <FlowDesignerLayout
        mode="design"
        :before-graph-init="handleBeforeGraphInit"
        @ready="handleReady"
      >
        <!-- 自定义节点面板插槽 -->
        <template #palette="{ onStartDrag }">
          <div class="custom-palette">
            <div class="custom-palette__header">
              <h3 class="custom-palette__title">SVG 节点</h3>
              <span class="custom-palette__desc">三种状态切换</span>
            </div>

            <div class="custom-palette__section">
              <div class="custom-palette__section-title">带图标的节点</div>
              <div
                v-for="nodeType in nodeTypesConfig"
                :key="nodeType.type"
                class="custom-palette__item"
                @mousedown="(e) => handleStartDrag(e, nodeType, onStartDrag)"
                :style="{ background: nodeType.rectFill, borderColor: nodeType.rectStroke}"
              >
                <div class="custom-palette__item-icon" >
                  <img :src="nodeType.icon" />
                </div>
                <div class="custom-palette__item-info">
                  <div class="custom-palette__item-label" :style="{ color: nodeType.textFill}">{{ nodeType.label }}</div>
                </div>
              </div>

              <div
                  key="svg-condition-node"
                  class="custom-palette__item"
                  @mousedown="(e) => handleStartDrag(e, {
                    type:'svg-condition-node',
                    label:'条件分支',
                    width: 132,
                    height: 72,
                    }, onStartDrag)"
                  :style="{ background: '#ffeed1', borderColor: '#fdc059'}"
              >
                <div class="custom-palette__item-icon" >
                  <img :src="conditionSvg" />
                </div>
                <div class="custom-palette__item-info">
                  <div class="custom-palette__item-label" :style="{ color: '#ffb02a'}">条件分支</div>
                </div>
              </div>

            </div>

            <div class="custom-palette__tips">
              <div class="tips-title">💡 交互说明</div>
              <ul class="tips-list">
                <li><strong>Default:</strong> 白底 + 彩色图标</li>
                <li><strong>Hover:</strong> 淡色背景</li>
                <li><strong>Selected:</strong> 彩底 + 白色图标</li>
              </ul>
            </div>
          </div>
        </template>
      </FlowDesignerLayout>
    </div>
  </div>
</template>

<script setup lang="ts">
import { ref } from 'vue'
import FlowDesignerLayout from '@/components/FlowDesigner/FlowDesignerLayout.vue'
import type { FlowDesigner, FlowDesignerOptions } from '@/components/FlowDesigner/core'
import { Graph, Node } from '@antv/x6'


import startSvg from "./icons/start.svg";
import startHover from "./icons/start-hover.svg";

import approvalSvg from "./icons/approval.svg";
import approvalHoverSvg from "./icons/approval-hover.svg";

import conditionSvg from "./icons/condition.svg";
import conditionHoverSvg from "./icons/condition-hover.svg";

const logs = ref<string[]>([])

// 节点类型配置（包含颜色和 iconPath）
interface NodeTypeConfig {
  type: string
  label: string
  hint: string
  color: string
  hoverColor: string
  iconPath: string
  width: number
  height: number
}

const nodeTypesConfig: any[] = [
  {
    type: 'svg-start-node',
    label: '开始节点',
    classNamePerfix: 'x6',
    width: 120,
    height: 38,
    rectStroke: '#95d375',
    rectStrokeWidth: 1,
    rectFill: '#edf8e7',
    icon: startSvg,
    iconHover: startHover,
    textFill: '#81cb5c'
  },
  {
    type: 'svg-approval-node',
    label: '审批节点',
    classNamePerfix: 'x6',
    width: 120,
    height: 38,
    rectStroke: '#83b3f7',
    rectStrokeWidth: 1,
    rectFill: '#e6eeff',
    icon: approvalSvg,
    iconHover: approvalHoverSvg,
    textFill: '#5d9df7'
  },
]

const Ports = {
  groups: {
    top: {
      position: 'top',
      attrs: {
        circle: {
          r: 4,
          magnet: true,
          stroke: '#5F95FF',
          strokeWidth: 1,
          fill: '#fff',
          style: {
            visibility: 'hidden',
          },
        },
        label: {
          position: 'top',
        },
        text: {
          text: '',
          fill: '#ff5800',
        },
      },
    },
    right: {
      position: 'right',
      attrs: {
        circle: {
          r: 4,
          magnet: true,
          stroke: '#5F95FF',
          strokeWidth: 1,
          fill: '#fff',
          style: {
            visibility: 'hidden',
          },
        },
        label: {
          position: 'right',
        },
        text: {
          text: '',
          fill: '#ff5800',
        },
      },
    },
    bottom: {
      position: 'bottom',
      attrs: {
        circle: {
          r: 4,
          magnet: true,
          stroke: '#5F95FF',
          strokeWidth: 1,
          fill: '#fff',
          style: {
            visibility: 'hidden',
          },
        },
        label: {
          position: 'bottom',
        },
        text: {
          text: '',
          fill: '#ff5800',
        },
      },
    },
    left: {
      position: 'left',
      attrs: {
        circle: {
          r: 4,
          magnet: true,
          stroke: '#5F95FF',
          strokeWidth: 1,
          fill: '#fff',
          style: {
            visibility: 'hidden',
          },
        },
        label: {
          position: 'left',
        },
        text: {
          text: '',
          fill: '#ff5800',
        },
      },
    },
  },
  items: [
    {
      id: 'port-top',
      group: 'top',
      label: {
        position : 'top'
      }
    },
    {
      id: 'port-right',
      group: 'right',
      label: {
        position : 'right'
      }
    },
    {
      id: 'port-bottom',
      group: 'bottom',
      label: {
        position : 'bottom'
      }
    },
    {
      id: 'port-left',
      group: 'left',
      label: {
        position : 'left'
      }
    },
  ],
}


// 手动跟踪节点的选中状态（因为 X6 的 selection 可能有默认行为）
const selectedNodesMap = new Map<string, boolean>()

function addLog(message: string) {
  const timestamp = new Date().toLocaleTimeString()
  logs.value.push(`[${timestamp}] ${message}`)
}

function clearLogs() {
  logs.value = []
}



/**
 * Graph 初始化前钩子：注册带 SVG icon 的自定义节点
 */
function handleBeforeGraphInit(options: FlowDesignerOptions) {
  addLog('🔧 beforeGraphInit: 开始注册 SVG 节点')

  // 遍历配置，注册所有节点
  nodeTypesConfig.forEach((config) => {
    Graph.registerNode(
        config.type,
        {
          inherit: 'rect',
          width: config.width,
          height: config.height,
          markup: [
            {
              tagName: 'rect', // 标签名称
              selector: 'body', // 选择器
              className: config.classNamePerfix + '-' + config.type + '-' + 'body'
            },
            {
              tagName: 'image',
              selector: 'icon',
              className: config.classNamePerfix + '-' + config.type + '-' + 'image'
            },
            {
              tagName: 'image',
              selector: 'iconHover',
              className: config.classNamePerfix + '-' + config.type + '-' + 'imageHover'
            },
            {
              tagName: 'text',
              selector: 'label',
              className: config.classNamePerfix + '-' + config.type + '-' + 'label'
            },
          ],
          attrs: {
            body: {
              stroke: config.rectStroke,
              strokeWidth: config.rectStrokeWidth,
              fill: config.rectFill,
              rx: 10,
              ry: 10,
            },
            icon: {
              'xlink:href': config.icon,
              width: 20,
              height: 20,
              x: 12,
              y: 8,
            },
            iconHover: {
              'xlink:href': config.iconHover,
              width: 20,
              height: 20,
              x: 12,
              y: 8,
              display: 'none'
            },
            text: {
              fontSize: 12,
              fill: config.textFill,
            },
          },
          ports: { ...Ports },
        },
        true,
    );

    addLog(`✅ 已注册节点: ${config.type} (${config.label})`)
  })  // ✅ 修复：forEach 的回调函数结束

  Graph.registerNode(
      //'custom-polygon',
      'svg-condition-node',
      {
        inherit: 'polygon',
        width: 132,
        height: 72,
        markup: [
          {
            tagName: 'polygon', // 标签名称
            selector: 'body', // 选择器
            className: 'x6-svg-condition-node-body'
          },
          {
            tagName: 'text',
            selector: 'label',
            className: 'x6-svg-condition-node-label'
          },
          {
            tagName: 'image',
            selector: 'icon',
            className: 'x6-svg-condition-node-image'
          },
          {
            tagName: 'image',
            selector: 'iconHover',
            className: 'x6-svg-condition-node-imageHover'
          },
        ],
        attrs: {
          body: {
            strokeWidth: 1,
            stroke: '#fdc059',
            fill: '#ffeed1',
            refPoints: '0,20 20,0 40,20 20,40',
          },
          text: {
            fontSize: 12,
            fill: '#ffb02a',
            y:8
          },
          icon: {
            'xlink:href': conditionSvg,
            width: 20,
            height: 20,
            x: 56,
            y: 8,
          },
          iconHover: {
            'xlink:href': conditionHoverSvg,
            width: 20,
            height: 20,
            x: 56,
            y: 8,
            display: 'none'
          },
        },
        ports: {
          ...Ports,
          items: [
            {
              group: 'top',
            },
            {
              group: 'bottom',
            },
          ],
        },
      },
      true,
  );

  addLog('🎉 所有 SVG 节点注册完成')
  
  // ─── 注册自定义边：渐变流动边 ────────────────────────────────────────────
  addLog('🔧 开始注册自定义边')
  
  Graph.registerEdge(
    'gradient-flow-edge',
    {
      inherit: 'edge',
      attrs: {
        line: {
          stroke: '#1890ff',
          strokeWidth: 3,
          targetMarker: {
            name: 'block',
            width: 12,
            height: 8,
          },
          strokeDasharray: 5,
          style: {
            animation: 'ant-line 30s infinite linear',
          },
        },
      },
    },
    true
  )
  
  // 注册渐变色边
  Graph.registerEdge(
    'rainbow-edge',
    {
      inherit: 'edge',
      attrs: {
        line: {
          stroke: {
            type: 'linearGradient',
            stops: [
              { offset: '0%', color: '#667eea' },
              { offset: '50%', color: '#764ba2' },
              { offset: '100%', color: '#f093fb' },
            ],
          },
          strokeWidth: 4,
          targetMarker: {
            name: 'classic',
            fill: '#f093fb',
            stroke: '#f093fb',
          },
        },
      },
    },
    true
  )
  
  // 注册发光边
  Graph.registerEdge(
    'glow-edge',
    {
      inherit: 'edge',
      attrs: {
        line: {
          stroke: '#52c41a',
          strokeWidth: 3,
          targetMarker: {
            name: 'block',
            fill: '#52c41a',
            stroke: '#52c41a',
            width: 10,
            height: 8,
          },
          filter: {
            name: 'dropShadow',
            args: {
              dx: 0,
              dy: 0,
              blur: 8,
              color: '#52c41a',
            },
          },
        },
      },
    },
    true
  )
  
  // 注册粗箭头边
  Graph.registerEdge(
    'thick-arrow-edge',
    {
      inherit: 'edge',
      attrs: {
        line: {
          stroke: '#ff4d4f',
          strokeWidth: 5,
          targetMarker: {
            name: 'block',
            fill: '#ff4d4f',
            stroke: '#ff4d4f',
            width: 16,
            height: 12,
          },
        },
      },
    },
    true
  )
  
  addLog('✨ 自定义边注册完成')
}

function handleReady(designer: FlowDesigner, graph: Graph) {
  addLog('✅ 画布初始化完成')
  addLog('💡 提示: 悬停查看 hover 效果，点击切换 selected 状态')


  // ─── 添加示例节点和边 ───────────────────────────────────────────────────
  setTimeout(() => {
    // 第一行：流动边
    const node1 = graph.addNode({
      shape: 'svg-start-node',
      x: 100,
      y: 80,
      label: '开始',
      id: 'node-1',
    })
    
    const node2 = graph.addNode({
      shape: 'svg-approval-node',
      x: 300,
      y: 80,
      label: '审批',
      id: 'node-2',
    })
    
    // 第二行：渐变色边
    const node3 = graph.addNode({
      shape: 'svg-start-node',
      x: 100,
      y: 200,
      label: '节点A',
      id: 'node-3',
    })
    
    const node4 = graph.addNode({
      shape: 'svg-approval-node',
      x: 300,
      y: 200,
      label: '节点B',
      id: 'node-4',
    })
    
    // 第三行：发光边
    const node5 = graph.addNode({
      shape: 'svg-start-node',
      x: 100,
      y: 320,
      label: '任务1',
      id: 'node-5',
    })
    
    const node6 = graph.addNode({
      shape: 'svg-approval-node',
      x: 300,
      y: 320,
      label: '任务2',
      id: 'node-6',
    })
    
    // 第四行：粗箭头边
    const node7 = graph.addNode({
      shape: 'svg-start-node',
      x: 100,
      y: 440,
      label: '步骤X',
      id: 'node-7',
    })
    
    const node8 = graph.addNode({
      shape: 'svg-approval-node',
      x: 300,
      y: 440,
      label: '步骤Y',
      id: 'node-8',
    })
    
    // 添加自定义边
    setTimeout(() => {
      // 1. 流动边（蚂蚁线）- 从右侧端口到左侧端口
      graph.addEdge({
        shape: 'gradient-flow-edge',
        source: {
          cell: 'node-1',
          port: 'port-right',  // 从 node-1 的右侧端口出发
        },
        target: {
          cell: 'node-2',
          port: 'port-left',   // 连接到 node-2 的左侧端口
        },
        label: '流动边',
        attrs: {
          line: {
            stroke: '#1890ff',
          },
        },
      })
      addLog('➡️ 添加流动边（蚂蚁线动画）')
      
      // 2. 渐变色边 - 从右侧端口到左侧端口
      graph.addEdge({
        shape: 'rainbow-edge',
        source: {
          cell: 'node-3',
          port: 'port-right',
        },
        target: {
          cell: 'node-4',
          port: 'port-left',
        },
        label: '渐变边',
      })
      addLog('🌈 添加渐变色边')
      
      // 3. 发光边 - 从右侧端口到左侧端口
      graph.addEdge({
        shape: 'glow-edge',
        source: {
          cell: 'node-5',
          port: 'port-right',
        },
        target: {
          cell: 'node-6',
          port: 'port-left',
        },
        label: '发光边',
      })
      addLog('✨ 添加发光边')
      
      // 4. 粗箭头边 - 从右侧端口到左侧端口
      graph.addEdge({
        shape: 'thick-arrow-edge',
        source: {
          cell: 'node-7',
          port: 'port-right',
        },
        target: {
          cell: 'node-8',
          port: 'port-left',
        },
        label: '粗箭头',
      })
      addLog('🎯 添加粗箭头边')
      
      addLog('📦 已添加 8 个节点和 4 种自定义边')
      addLog('🎨 试试悬停和点击边吧！')
    }, 300)
  }, 100)
}

function handleStartDrag(e: MouseEvent, nodeType: NodeTypeConfig, onStartDrag: any) {
  addLog(`🎯 开始拖拽: ${nodeType.label}`)

  onStartDrag(e, {
    shape: nodeType.type,
    label: nodeType.label,
    width: nodeType.width,
    height: nodeType.height,
    data: {
      label: nodeType.label,
      nodeInfo: {
        hint: nodeType.hint,
        color: nodeType.color,
      }
    }
  })
}
</script>

