export default "<template>\r\n  <div class=\"demo-node-svg\">\r\n    <!-- 事件日志面板 -->\r\n    <div class=\"demo-node-svg__log\">\r\n      <div class=\"demo-node-svg__log-header\">\r\n        <h4>事件日志</h4>\r\n        <button class=\"demo-node-svg__clear-btn\" @click=\"clearLogs\" title=\"清除日志\">\r\n          清除\r\n        </button>\r\n      </div>\r\n      <div class=\"demo-node-svg__log-content\">\r\n        <div v-for=\"(log, index) in logs\" :key=\"index\" class=\"demo-node-svg__log-item\">\r\n          {{ log }}\r\n        </div>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- 画布容器 -->\r\n    <div class=\"demo-node-svg__canvas\">\r\n      <FlowDesignerLayout\r\n        mode=\"design\"\r\n        :before-graph-init=\"handleBeforeGraphInit\"\r\n        @ready=\"handleReady\"\r\n      >\r\n        <!-- 自定义节点面板插槽 -->\r\n        <template #palette=\"{ onStartDrag }\">\r\n          <div class=\"custom-palette\">\r\n            <div class=\"custom-palette__header\">\r\n              <h3 class=\"custom-palette__title\">SVG 节点</h3>\r\n              <span class=\"custom-palette__desc\">三种状态切换</span>\r\n            </div>\r\n\r\n            <div class=\"custom-palette__section\">\r\n              <div class=\"custom-palette__section-title\">带图标的节点</div>\r\n              <div\r\n                v-for=\"nodeType in nodeTypesConfig\"\r\n                :key=\"nodeType.type\"\r\n                class=\"custom-palette__item\"\r\n                @mousedown=\"(e) => handleStartDrag(e, nodeType, onStartDrag)\"\r\n                :style=\"{ background: nodeType.rectFill, borderColor: nodeType.rectStroke}\"\r\n              >\r\n                <div class=\"custom-palette__item-icon\" >\r\n                  <img :src=\"nodeType.icon\" />\r\n                </div>\r\n                <div class=\"custom-palette__item-info\">\r\n                  <div class=\"custom-palette__item-label\" :style=\"{ color: nodeType.textFill}\">{{ nodeType.label }}</div>\r\n                </div>\r\n              </div>\r\n\r\n              <div\r\n                  key=\"svg-condition-node\"\r\n                  class=\"custom-palette__item\"\r\n                  @mousedown=\"(e) => handleStartDrag(e, {\r\n                    type:'svg-condition-node',\r\n                    label:'条件分支',\r\n                    width: 132,\r\n                    height: 72,\r\n                    }, onStartDrag)\"\r\n                  :style=\"{ background: '#ffeed1', borderColor: '#fdc059'}\"\r\n              >\r\n                <div class=\"custom-palette__item-icon\" >\r\n                  <img :src=\"conditionSvg\" />\r\n                </div>\r\n                <div class=\"custom-palette__item-info\">\r\n                  <div class=\"custom-palette__item-label\" :style=\"{ color: '#ffb02a'}\">条件分支</div>\r\n                </div>\r\n              </div>\r\n\r\n            </div>\r\n\r\n            <div class=\"custom-palette__tips\">\r\n              <div class=\"tips-title\">💡 交互说明</div>\r\n              <ul class=\"tips-list\">\r\n                <li><strong>Default:</strong> 白底 + 彩色图标</li>\r\n                <li><strong>Hover:</strong> 淡色背景</li>\r\n                <li><strong>Selected:</strong> 彩底 + 白色图标</li>\r\n              </ul>\r\n            </div>\r\n          </div>\r\n        </template>\r\n      </FlowDesignerLayout>\r\n    </div>\r\n  </div>\r\n</template>\r\n\r\n<script setup lang=\"ts\">\r\nimport { ref } from 'vue'\r\nimport FlowDesignerLayout from '@/components/FlowDesigner/FlowDesignerLayout.vue'\r\nimport type { FlowDesigner, FlowDesignerOptions } from '@/components/FlowDesigner/core'\r\nimport { Graph, Node } from '@antv/x6'\r\n\r\n\r\nimport startSvg from \"./icons/start.svg\";\r\nimport startHover from \"./icons/start-hover.svg\";\r\n\r\nimport approvalSvg from \"./icons/approval.svg\";\r\nimport approvalHoverSvg from \"./icons/approval-hover.svg\";\r\n\r\nimport conditionSvg from \"./icons/condition.svg\";\r\nimport conditionHoverSvg from \"./icons/condition-hover.svg\";\r\n\r\nconst logs = ref<string[]>([])\r\n\r\n// 节点类型配置（包含颜色和 iconPath）\r\ninterface NodeTypeConfig {\r\n  type: string\r\n  label: string\r\n  hint: string\r\n  color: string\r\n  hoverColor: string\r\n  iconPath: string\r\n  width: number\r\n  height: number\r\n}\r\n\r\nconst nodeTypesConfig: any[] = [\r\n  {\r\n    type: 'svg-start-node',\r\n    label: '开始节点',\r\n    classNamePerfix: 'x6',\r\n    width: 120,\r\n    height: 38,\r\n    rectStroke: '#95d375',\r\n    rectStrokeWidth: 1,\r\n    rectFill: '#edf8e7',\r\n    icon: startSvg,\r\n    iconHover: startHover,\r\n    textFill: '#81cb5c'\r\n  },\r\n  {\r\n    type: 'svg-approval-node',\r\n    label: '审批节点',\r\n    classNamePerfix: 'x6',\r\n    width: 120,\r\n    height: 38,\r\n    rectStroke: '#83b3f7',\r\n    rectStrokeWidth: 1,\r\n    rectFill: '#e6eeff',\r\n    icon: approvalSvg,\r\n    iconHover: approvalHoverSvg,\r\n    textFill: '#5d9df7'\r\n  },\r\n]\r\n\r\nconst Ports = {\r\n  groups: {\r\n    top: {\r\n      position: 'top',\r\n      attrs: {\r\n        circle: {\r\n          r: 4,\r\n          magnet: true,\r\n          stroke: '#5F95FF',\r\n          strokeWidth: 1,\r\n          fill: '#fff',\r\n          style: {\r\n            visibility: 'hidden',\r\n          },\r\n        },\r\n        label: {\r\n          position: 'top',\r\n        },\r\n        text: {\r\n          text: '',\r\n          fill: '#ff5800',\r\n        },\r\n      },\r\n    },\r\n    right: {\r\n      position: 'right',\r\n      attrs: {\r\n        circle: {\r\n          r: 4,\r\n          magnet: true,\r\n          stroke: '#5F95FF',\r\n          strokeWidth: 1,\r\n          fill: '#fff',\r\n          style: {\r\n            visibility: 'hidden',\r\n          },\r\n        },\r\n        label: {\r\n          position: 'right',\r\n        },\r\n        text: {\r\n          text: '',\r\n          fill: '#ff5800',\r\n        },\r\n      },\r\n    },\r\n    bottom: {\r\n      position: 'bottom',\r\n      attrs: {\r\n        circle: {\r\n          r: 4,\r\n          magnet: true,\r\n          stroke: '#5F95FF',\r\n          strokeWidth: 1,\r\n          fill: '#fff',\r\n          style: {\r\n            visibility: 'hidden',\r\n          },\r\n        },\r\n        label: {\r\n          position: 'bottom',\r\n        },\r\n        text: {\r\n          text: '',\r\n          fill: '#ff5800',\r\n        },\r\n      },\r\n    },\r\n    left: {\r\n      position: 'left',\r\n      attrs: {\r\n        circle: {\r\n          r: 4,\r\n          magnet: true,\r\n          stroke: '#5F95FF',\r\n          strokeWidth: 1,\r\n          fill: '#fff',\r\n          style: {\r\n            visibility: 'hidden',\r\n          },\r\n        },\r\n        label: {\r\n          position: 'left',\r\n        },\r\n        text: {\r\n          text: '',\r\n          fill: '#ff5800',\r\n        },\r\n      },\r\n    },\r\n  },\r\n  items: [\r\n    {\r\n      group: 'top',\r\n      label: {\r\n        position : 'top'\r\n      }\r\n    },\r\n    {\r\n      group: 'right',\r\n      label: {\r\n        position : 'right'\r\n      }\r\n    },\r\n    {\r\n      group: 'bottom',\r\n      label: {\r\n        position : 'bottom'\r\n      }\r\n    },\r\n    {\r\n      group: 'left',\r\n      label: {\r\n        position : 'left'\r\n      }\r\n    },\r\n  ],\r\n}\r\n\r\n\r\n// 手动跟踪节点的选中状态（因为 X6 的 selection 可能有默认行为）\r\nconst selectedNodesMap = new Map<string, boolean>()\r\n\r\nfunction addLog(message: string) {\r\n  const timestamp = new Date().toLocaleTimeString()\r\n  logs.value.push(`[${timestamp}] ${message}`)\r\n}\r\n\r\nfunction clearLogs() {\r\n  logs.value = []\r\n}\r\n\r\n\r\n\r\n/**\r\n * Graph 初始化前钩子：注册带 SVG icon 的自定义节点\r\n */\r\nfunction handleBeforeGraphInit(options: FlowDesignerOptions) {\r\n  addLog('🔧 beforeGraphInit: 开始注册 SVG 节点')\r\n\r\n  // 遍历配置，注册所有节点\r\n  nodeTypesConfig.forEach((config) => {\r\n    Graph.registerNode(\r\n        config.type,\r\n        {\r\n          inherit: 'rect',\r\n          width: config.width,\r\n          height: config.height,\r\n          markup: [\r\n            {\r\n              tagName: 'rect', // 标签名称\r\n              selector: 'body', // 选择器\r\n              className: config.classNamePerfix + '-' + config.type + '-' + 'body'\r\n            },\r\n            {\r\n              tagName: 'image',\r\n              selector: 'icon',\r\n              className: config.classNamePerfix + '-' + config.type + '-' + 'image'\r\n            },\r\n            {\r\n              tagName: 'image',\r\n              selector: 'iconHover',\r\n              className: config.classNamePerfix + '-' + config.type + '-' + 'imageHover'\r\n            },\r\n            {\r\n              tagName: 'text',\r\n              selector: 'label',\r\n              className: config.classNamePerfix + '-' + config.type + '-' + 'label'\r\n            },\r\n          ],\r\n          attrs: {\r\n            body: {\r\n              stroke: config.rectStroke,\r\n              strokeWidth: config.rectStrokeWidth,\r\n              fill: config.rectFill,\r\n              rx: 10,\r\n              ry: 10,\r\n            },\r\n            icon: {\r\n              'xlink:href': config.icon,\r\n              width: 20,\r\n              height: 20,\r\n              x: 12,\r\n              y: 8,\r\n            },\r\n            iconHover: {\r\n              'xlink:href': config.iconHover,\r\n              width: 20,\r\n              height: 20,\r\n              x: 12,\r\n              y: 8,\r\n              display: 'none'\r\n            },\r\n            text: {\r\n              fontSize: 12,\r\n              fill: config.textFill,\r\n            },\r\n          },\r\n          ports: { ...Ports },\r\n        },\r\n        true,\r\n    );\r\n\r\n    addLog(`✅ 已注册节点: ${config.type} (${config.label})`)\r\n  })  // ✅ 修复：forEach 的回调函数结束\r\n\r\n  Graph.registerNode(\r\n      //'custom-polygon',\r\n      'svg-condition-node',\r\n      {\r\n        inherit: 'polygon',\r\n        width: 132,\r\n        height: 72,\r\n        markup: [\r\n          {\r\n            tagName: 'polygon', // 标签名称\r\n            selector: 'body', // 选择器\r\n            className: 'x6-svg-condition-node-body'\r\n          },\r\n          {\r\n            tagName: 'text',\r\n            selector: 'label',\r\n            className: 'x6-svg-condition-node-label'\r\n          },\r\n          {\r\n            tagName: 'image',\r\n            selector: 'icon',\r\n            className: 'x6-svg-condition-node-image'\r\n          },\r\n          {\r\n            tagName: 'image',\r\n            selector: 'iconHover',\r\n            className: 'x6-svg-condition-node-imageHover'\r\n          },\r\n        ],\r\n        attrs: {\r\n          body: {\r\n            strokeWidth: 1,\r\n            stroke: '#fdc059',\r\n            fill: '#ffeed1',\r\n            refPoints: '0,20 20,0 40,20 20,40',\r\n          },\r\n          text: {\r\n            fontSize: 12,\r\n            fill: '#ffb02a',\r\n            y:8\r\n          },\r\n          icon: {\r\n            'xlink:href': conditionSvg,\r\n            width: 20,\r\n            height: 20,\r\n            x: 56,\r\n            y: 8,\r\n          },\r\n          iconHover: {\r\n            'xlink:href': conditionHoverSvg,\r\n            width: 20,\r\n            height: 20,\r\n            x: 56,\r\n            y: 8,\r\n            display: 'none'\r\n          },\r\n        },\r\n        ports: {\r\n          ...Ports,\r\n          items: [\r\n            {\r\n              group: 'top',\r\n            },\r\n            {\r\n              group: 'bottom',\r\n            },\r\n          ],\r\n        },\r\n      },\r\n      true,\r\n  );\r\n\r\n  addLog('🎉 所有 SVG 节点注册完成')\r\n}\r\n\r\nfunction handleReady(designer: FlowDesigner, graph: Graph) {\r\n  addLog('✅ 画布初始化完成')\r\n  addLog('💡 提示: 悬停查看 hover 效果，点击切换 selected 状态')\r\n\r\n\r\n  // ─── 添加示例节点 ───────────────────────────────────────────────────\r\n  setTimeout(() => {\r\n    graph.addNode({\r\n      shape: 'svg-start-node',\r\n      x: 100,\r\n      y: 100,\r\n      label: '开始节点',\r\n    })\r\n\r\n    addLog('📦 已添加 3 个示例节点')\r\n    addLog('🎨 试试悬停和点击节点吧！')\r\n  }, 100)\r\n}\r\n\r\nfunction handleStartDrag(e: MouseEvent, nodeType: NodeTypeConfig, onStartDrag: any) {\r\n  addLog(`🎯 开始拖拽: ${nodeType.label}`)\r\n\r\n  onStartDrag(e, {\r\n    shape: nodeType.type,\r\n    label: nodeType.label,\r\n    width: nodeType.width,\r\n    height: nodeType.height,\r\n    data: {\r\n      label: nodeType.label,\r\n      nodeInfo: {\r\n        hint: nodeType.hint,\r\n        color: nodeType.color,\r\n      }\r\n    }\r\n  })\r\n}\r\n</script>\r\n\r\n<style scoped>\r\n.demo-node-svg {\r\n  display: flex;\r\n  height: 100%;\r\n  min-height: 600px;\r\n  gap: 16px;\r\n}\r\n\r\n.demo-node-svg__log {\r\n  width: 280px;\r\n  border: 1px solid #e8e8e8;\r\n  border-radius: 8px;\r\n  padding: 16px;\r\n  background: #fafafa;\r\n  overflow: hidden;\r\n  display: flex;\r\n  flex-direction: column;\r\n}\r\n\r\n.demo-node-svg__log-header {\r\n  display: flex;\r\n  justify-content: space-between;\r\n  align-items: center;\r\n  margin-bottom: 12px;\r\n}\r\n\r\n.demo-node-svg__log h4 {\r\n  margin: 0;\r\n  font-size: 14px;\r\n  color: #1a1a2e;\r\n  font-weight: 600;\r\n}\r\n\r\n.demo-node-svg__clear-btn {\r\n  padding: 2px 8px;\r\n  font-size: 12px;\r\n  color: #666;\r\n  background: #fff;\r\n  border: 1px solid #d9d9d9;\r\n  border-radius: 4px;\r\n  cursor: pointer;\r\n  transition: all 0.2s;\r\n  user-select: none;\r\n}\r\n\r\n.demo-node-svg__clear-btn:hover {\r\n  color: #1890ff;\r\n  border-color: #1890ff;\r\n}\r\n\r\n.demo-node-svg__log-content {\r\n  flex: 1;\r\n  overflow-y: auto;\r\n  font-size: 12px;\r\n  line-height: 1.8;\r\n}\r\n\r\n.demo-node-svg__log-item {\r\n  padding: 4px 0;\r\n  color: #555;\r\n  font-family: 'Monaco', 'Menlo', 'Consolas', monospace;\r\n  border-bottom: 1px solid #f0f0f0;\r\n}\r\n\r\n.demo-node-svg__log-item:last-child {\r\n  border-bottom: none;\r\n}\r\n\r\n.demo-node-svg__canvas {\r\n  flex: 1;\r\n  border: 1px solid #e8e8e8;\r\n  border-radius: 8px;\r\n  overflow: hidden;\r\n  background: #fff;\r\n}\r\n\r\n/* ==================== 自定义节点面板样式 ==================== */\r\n.custom-palette {\r\n  display: flex;\r\n  flex-direction: column;\r\n  height: 100%;\r\n  background: linear-gradient(to bottom, #f9fafb, #ffffff);\r\n  border-right: 1px solid #e8e8e8;\r\n  width: 200px;\r\n}\r\n\r\n.custom-palette__header {\r\n  padding: 16px;\r\n  border-bottom: 2px solid #e8e8e8;\r\n  background: #fff;\r\n}\r\n\r\n.custom-palette__title {\r\n  margin: 0 0 4px 0;\r\n  font-size: 16px;\r\n  font-weight: 600;\r\n  color: #1a1a2e;\r\n}\r\n\r\n.custom-palette__desc {\r\n  font-size: 12px;\r\n  color: #999;\r\n}\r\n\r\n.custom-palette__section {\r\n  padding: 12px;\r\n}\r\n\r\n.custom-palette__section-title {\r\n  font-size: 11px;\r\n  font-weight: 600;\r\n  color: #999;\r\n  text-transform: uppercase;\r\n  letter-spacing: 0.06em;\r\n  margin-bottom: 8px;\r\n  padding: 0 4px;\r\n}\r\n\r\n.custom-palette__item {\r\n  display: flex;\r\n  align-items: center;\r\n  gap: 12px;\r\n  padding: 10px;\r\n  margin-bottom: 8px;\r\n  background: #fff;\r\n  border: 1px solid #e8e8e8;\r\n  border-radius: 12px;\r\n  cursor: move;\r\n  transition: all 0.2s;\r\n  user-select: none;\r\n  width: 160px;\r\n  height: 50px;\r\n}\r\n\r\n.custom-palette__item:hover {\r\n  border-color: #1677ff;\r\n  box-shadow: 0 2px 8px rgba(22, 119, 255, 0.15);\r\n  transform: translateY(-1px);\r\n}\r\n\r\n.custom-palette__item:active {\r\n  transform: translateY(0);\r\n  box-shadow: 0 1px 4px rgba(22, 119, 255, 0.2);\r\n}\r\n\r\n.custom-palette__item-icon {\r\n  width: 36px;\r\n  height: 36px;\r\n  display: flex;\r\n  align-items: center;\r\n  justify-content: center;\r\n  border-radius: 6px;\r\n  flex-shrink: 0;\r\n}\r\n\r\n.custom-palette__item-info {\r\n  flex: 1;\r\n  min-width: 0;\r\n}\r\n\r\n.custom-palette__item-label {\r\n  font-size: 13px;\r\n  font-weight: 500;\r\n  color: #333;\r\n  margin-bottom: 2px;\r\n}\r\n\r\n.custom-palette__item-hint {\r\n  font-size: 11px;\r\n  color: #999;\r\n  white-space: nowrap;\r\n  overflow: hidden;\r\n  text-overflow: ellipsis;\r\n}\r\n\r\n/* ==================== 交互说明 ==================== */\r\n.custom-palette__tips {\r\n  margin-top: auto;\r\n  padding: 12px;\r\n  background: #fff9e6;\r\n  border-top: 1px solid #ffe58f;\r\n}\r\n\r\n.tips-title {\r\n  font-size: 12px;\r\n  font-weight: 600;\r\n  color: #d48806;\r\n  margin-bottom: 8px;\r\n}\r\n\r\n.tips-list {\r\n  margin: 0;\r\n  padding-left: 16px;\r\n  font-size: 11px;\r\n  line-height: 1.8;\r\n  color: #8c8c8c;\r\n}\r\n\r\n.tips-list li {\r\n  margin-bottom: 4px;\r\n}\r\n\r\n.tips-list strong {\r\n  color: #595959;\r\n}\r\n\r\n</style>\r\n\r\n\r\n<!--如果需要简单控制节点样式，需要将此节点样式暴露到全局,适当增加前缀以防止污染-->\r\n<style>\r\n.x6-svg-start-node-body:hover{\r\n  stroke-width: 2px;\r\n  fill: #caf1c1;\r\n}\r\n.x6-node-selected .x6-svg-start-node-body{\r\n  stroke: #48c02a;\r\n  stroke-width: 2px;\r\n  fill: #8fd16f\r\n}\r\n.x6-node-selected .x6-svg-start-node-image {\r\n  display: none;\r\n}\r\n.x6-node-selected .x6-svg-start-node-imageHover {\r\n  display: block;\r\n}\r\n.x6-node-selected .x6-svg-start-node-label {\r\n  fill: #ffffff\r\n}\r\n\r\n.x6-node-selected .x6-svg-approval-node-body{\r\n  stroke: #003eca;\r\n  stroke-width: 2px;\r\n  fill: #1d78f4\r\n}\r\n.x6-node-selected .x6-svg-approval-node-image {\r\n  display: none;\r\n}\r\n\r\n.x6-node-selected .x6-svg-approval-node-imageHover {\r\n  display: block;\r\n}\r\n.x6-node-selected .x6-svg-approval-node-label {\r\n  fill: #ffffff\r\n}\r\n\r\n.x6-node-selected .x6-svg-condition-node-body{\r\n  stroke: #ffa100;\r\n  stroke-width: 2px;\r\n  fill: #fdc059\r\n}\r\n.x6-node-selected .x6-svg-condition-node-image {\r\n  display: none;\r\n}\r\n\r\n.x6-node-selected .x6-svg-condition-node-imageHover {\r\n  display: block;\r\n}\r\n.x6-node-selected .x6-svg-condition-node-label {\r\n  fill: #ffffff\r\n}\r\n\r\n</style>\r\n"