<template>
  <div class="demo-slot-node-menu">
    <!-- 事件日志面板 -->
    <div class="demo-slot-node-menu__log">
      <div class="demo-slot-node-menu__log-header">
        <h4>事件日志</h4>
        <button class="demo-slot-node-menu__clear-btn" @click="clearLogs" title="清除日志">
          清除
        </button>
      </div>
      <div class="demo-slot-node-menu__log-content">
        <div v-for="(log, index) in logs" :key="index" class="demo-slot-node-menu__log-item">
          {{ log }}
        </div>
      </div>
    </div>

    <!-- 画布容器 -->
    <div class="demo-slot-node-menu__canvas">
      <FlowDesignerLayout
        mode="design"
        :before-graph-init="handleBeforeGraphInit"
        @ready="handleReady"
      >
        <!-- 自定义节点右键菜单插槽 -->
        <template #node-menu="{ node, isGroup, isMultiSelect, capabilities, designer, graph, onSelect }">
          <div class="node-context-menu" @click.stop>
            <div class="node-context-menu__header">
              <span class="node-context-menu__title">
                {{ getNodeTitle(node, isGroup, isMultiSelect) }}
              </span>
            </div>

            <!-- 节点信息显示 -->
            <div class="node-context-menu__info">
              <div class="node-context-menu__info-item">
                <span class="node-context-menu__info-label">节点名称:</span>
                <span class="node-context-menu__info-value">{{ getNodeLabel(node) }}</span>
              </div>
              <div class="node-context-menu__info-item">
                <span class="node-context-menu__info-label">节点类型:</span>
                <span class="node-context-menu__info-value">{{ node.shape }}</span>
              </div>
              <div v-if="isMultiSelect" class="node-context-menu__info-item">
                <span class="node-context-menu__info-label">选中数量:</span>
                <span class="node-context-menu__info-value">{{ graph?.getSelectedCells().length || 0 }} 个</span>
              </div>
            </div>

            <div class="node-context-menu__divider" />

            <!-- 成组/解组 -->
            <div
              v-if="isMultiSelect && capabilities.canGroup"
              class="node-context-menu__item"
              @click="handleMenuClick('group', node, onSelect)"
            >
              <span class="node-context-menu__icon">📦</span>
              <span class="node-context-menu__text">成组</span>
              <span class="node-context-menu__shortcut">Ctrl+G</span>
            </div>
            <div
              v-if="isGroup && capabilities.canGroup"
              class="node-context-menu__item"
              @click="handleMenuClick('ungroup', node, onSelect)"
            >
              <span class="node-context-menu__icon">📂</span>
              <span class="node-context-menu__text">解组</span>
              <span class="node-context-menu__shortcut">Ctrl+Shift+G</span>
            </div>

            <!-- 分隔线 -->
            <div
              v-if="((isMultiSelect || isGroup) && capabilities.canGroup) && (capabilities.canCopy || capabilities.canPaste)"
              class="node-context-menu__divider"
            />

            <!-- 复制粘贴 -->
            <div
              v-if="capabilities.canCopy"
              class="node-context-menu__item"
              @click="handleMenuClick('copy', node, onSelect)"
            >
              <span class="node-context-menu__icon">📄</span>
              <span class="node-context-menu__text">复制节点</span>
              <span class="node-context-menu__shortcut">Ctrl+C</span>
            </div>
            <div
              v-if="capabilities.canPaste"
              class="node-context-menu__item"
              @click="handleMenuClick('paste', node, onSelect)"
            >
              <span class="node-context-menu__icon">📋</span>
              <span class="node-context-menu__text">粘贴节点</span>
              <span class="node-context-menu__shortcut">Ctrl+V</span>
            </div>

            <!-- 分隔线 -->
            <div
              v-if="(capabilities.canCopy || capabilities.canPaste) && (capabilities.canToFront || capabilities.canToBack)"
              class="node-context-menu__divider"
            />

            <!-- 层级操作 -->
            <div
              v-if="capabilities.canToFront"
              class="node-context-menu__item"
              @click="handleMenuClick('toFront', node, onSelect)"
            >
              <span class="node-context-menu__icon">⬆️</span>
              <span class="node-context-menu__text">层级前置</span>
            </div>
            <div
              v-if="capabilities.canToBack"
              class="node-context-menu__item"
              @click="handleMenuClick('toBack', node, onSelect)"
            >
              <span class="node-context-menu__icon">⬇️</span>
              <span class="node-context-menu__text">层级后置</span>
            </div>

            <!-- 分隔线 -->
            <div
              v-if="(capabilities.canToFront || capabilities.canToBack) && graph"
              class="node-context-menu__divider"
            />

            <!-- 自定义操作（使用 designer 和 graph） -->
            <div
              v-if="graph && designer"
              class="node-context-menu__item"
              @click="handleCenterNode(node, graph)"
            >
              <span class="node-context-menu__icon">🎯</span>
              <span class="node-context-menu__text">居中显示</span>
            </div>
            <div
              v-if="graph"
              class="node-context-menu__item"
              @click="handleHighlightConnections(node, graph)"
            >
              <span class="node-context-menu__icon">🔗</span>
              <span class="node-context-menu__text">高亮连线</span>
            </div>

            <!-- 分隔线 -->
            <div
              v-if="capabilities.canDelete"
              class="node-context-menu__divider"
            />

            <!-- 删除 -->
            <div
              v-if="capabilities.canDelete"
              class="node-context-menu__item node-context-menu__item--danger"
              @click="handleMenuClick('delete', node, onSelect)"
            >
              <span class="node-context-menu__icon">🗑</span>
              <span class="node-context-menu__text">删除节点</span>
              <span class="node-context-menu__shortcut">Delete</span>
            </div>
          </div>
        </template>
      </FlowDesignerLayout>
    </div>
  </div>
</template>

<script setup lang="ts">
import { ref } from 'vue'
import FlowDesignerLayout from '@/components/FlowDesigner/FlowDesignerLayout.vue'
import type { FlowDesigner, FlowDesignerOptions } from '@/components/FlowDesigner/core'
import { Graph, Node } from '@antv/x6'

const logs = ref<string[]>([])
let designerInstance: FlowDesigner | null = null
let graphInstance: Graph | null = null

function addLog(message: string) {
  const timestamp = new Date().toLocaleTimeString()
  logs.value.push(`[${timestamp}] ${message}`)
  // 自动滚动到底部
  setTimeout(() => {
    const logContent = document.querySelector('.demo-slot-node-menu__log-content')
    if (logContent) {
      logContent.scrollTop = logContent.scrollHeight
    }
  }, 0)
}

function clearLogs() {
  logs.value = []
}

/**
 * Graph 初始化前注册自定义节点
 */
function handleBeforeGraphInit(options: FlowDesignerOptions) {
  addLog('🔧 初始化自定义节点样式...')

  // 注册自定义圆形节点
  Graph.registerNode('custom-circle', {
    inherit: 'circle',
    width: 100,
    height: 100,
    attrs: {
      body: {
        fill: '#5F95FF',
        stroke: '#2563EB',
        strokeWidth: 2,
      },
      label: {
        fill: '#fff',
        fontSize: 14,
        fontWeight: 500,
      },
    },
  }, true)

  // 注册自定义矩形节点
  Graph.registerNode('custom-rect', {
    inherit: 'rect',
    width: 140,
    height: 70,
    attrs: {
      body: {
        fill: '#47C769',
        stroke: '#27AE60',
        strokeWidth: 2,
        rx: 8,
        ry: 8,
      },
      label: {
        fill: '#fff',
        fontSize: 14,
        fontWeight: 500,
      },
    },
  }, true)

  // 注册自定义警告节点
  Graph.registerNode('custom-warning', {
    inherit: 'rect',
    width: 140,
    height: 70,
    attrs: {
      body: {
        fill: '#FFA940',
        stroke: '#FA8C16',
        strokeWidth: 2,
        rx: 8,
        ry: 8,
      },
      label: {
        fill: '#fff',
        fontSize: 14,
        fontWeight: 600,
      },
    },
  }, true)

  addLog('✅ 节点样式注册完成')
}

/**
 * 获取节点标签
 */
function getNodeLabel(node: Node): string {
  const propLabel = node.getProp('label')
  if (propLabel) return String(propLabel)

  const data = node.getData()
  if (data?.label) return data.label

  return node.id.substring(0, 8) + '...'
}

/**
 * 获取节点菜单标题
 */
function getNodeTitle(node: Node, isGroup: boolean, isMultiSelect: boolean): string {
  if (isMultiSelect) return '多选节点菜单'
  if (isGroup) return '组节点菜单'
  return '节点菜单'
}

/**
 * 处理菜单项点击
 */
function handleMenuClick(action: string, node: Node, onSelect: (action: string) => void) {
  addLog(`🖱️ 节点菜单: ${getActionName(action)} - ${getNodeLabel(node)}`)
  onSelect(action)
}

/**
 * 居中显示节点（自定义操作，使用 graph）
 */
function handleCenterNode(node: Node, graph: Graph) {
  graph.centerCell(node, {
    padding: 100,
    animation: {
      duration: 300,
      easing: 'ease-in-out'
    }
  })
  addLog(`🎯 居中显示节点: ${getNodeLabel(node)}`)
}

/**
 * 高亮节点的所有连线（自定义操作，使用 graph）
 */
function handleHighlightConnections(node: Node, graph: Graph) {
  // 获取所有相关连线
  const edges = graph.getConnectedEdges(node)

  // 高亮连线
  edges.forEach(edge => {
    edge.attr('line/stroke', '#FF4D4F')
    edge.attr('line/strokeWidth', 3)

    // 3秒后恢复
    setTimeout(() => {
      edge.attr('line/stroke', '#8c9bb5')
      edge.attr('line/strokeWidth', 1.5)
    }, 3000)
  })

  addLog(`🔗 高亮连线: ${edges.length} 条相关连线（3秒后恢复）`)
}

/**
 * 获取操作名称（用于日志显示）
 */
function getActionName(action: string): string {
  const actionMap: Record<string, string> = {
    'group': '成组',
    'ungroup': '解组',
    'copy': '复制节点',
    'paste': '粘贴节点',
    'toFront': '层级前置',
    'toBack': '层级后置',
    'delete': '删除节点',
  }
  return actionMap[action] || action
}

function handleReady(designer: FlowDesigner, graph: Graph) {
  designerInstance = designer
  graphInstance = graph
  addLog('✅ 画布初始化完成')

  // 初始化测试数据
  initTestData(graph)
  addLog('✅ 节点初始化完成，请右键节点菜单测试')
}
function initTestData(graph) {

  // 添加初始节点
  const node1 = graph.addNode({
    shape: 'custom-circle',
    x: 100,
    y: 100,
    label: '开始',
    data: {
      description: '流程开始节点',
      owner: '张三',
      priority: 'high',
    },
  })

  const node2 = graph.addNode({
    shape: 'custom-rect',
    x: 300,
    y: 100,
    label: '处理',
    data: {
      description: '执行业务处理',
      owner: '李四',
      priority: 'medium',
    },
  })

  const node3 = graph.addNode({
    shape: 'custom-circle',
    x: 500,
    y: 100,
    label: '结束',
    data: {
      description: '流程结束',
      owner: '王五',
      priority: 'low',
    },
  })

  // 添加连线
  graph.addEdge({
    source: node1,
    target: node2,
    shape: 'flow-edge',
    labels: [{ attrs: { text: { text: '通过' } } }],
    data: {
      lineType: 'normal',
      condition: 'status === "approved"',
      description: '审批通过后的流转',
      isDefault: false,
    },
  })

  graph.addEdge({
    source: node2,
    target: node3,
    shape: 'flow-edge',
    labels: [{ attrs: { text: { text: '完成' } } }],
    data: {
      lineType: 'normal',
      condition: '',
      description: '处理完成后结束',
      isDefault: true,
    },
  })
}
</script>

<style scoped>
.demo-slot-node-menu {
  display: flex;
  height: 100%;
  min-height: 500px;
  gap: 16px;
}

.demo-slot-node-menu__log {
  width: 320px;
  border: 1px solid #e8e8e8;
  border-radius: 8px;
  padding: 16px;
  background: #fafafa;
  overflow: hidden;
  display: flex;
  flex-direction: column;
}

.demo-slot-node-menu__log-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 12px;
}

.demo-slot-node-menu__log h4 {
  margin: 0;
  font-size: 14px;
  color: #1a1a2e;
  font-weight: 600;
}

.demo-slot-node-menu__clear-btn {
  padding: 2px 8px;
  font-size: 12px;
  color: #666;
  background: #fff;
  border: 1px solid #d9d9d9;
  border-radius: 4px;
  cursor: pointer;
  transition: all 0.2s;
  user-select: none;
}

.demo-slot-node-menu__clear-btn:hover {
  color: #1890ff;
  border-color: #1890ff;
}

.demo-slot-node-menu__log-content {
  flex: 1;
  overflow-y: auto;
  font-size: 12px;
  line-height: 1.8;
}

.demo-slot-node-menu__log-item {
  padding: 4px 0;
  color: #555;
  font-family: 'Monaco', 'Menlo', 'Consolas', monospace;
  border-bottom: 1px solid #f0f0f0;
}

.demo-slot-node-menu__log-item:last-child {
  border-bottom: none;
}

.demo-slot-node-menu__canvas {
  flex: 1;
  border: 1px solid #e8e8e8;
  border-radius: 8px;
  overflow: hidden;
  background: #fff;
  position: relative;
}

/* ==================== 节点右键菜单样式 ==================== */
.node-context-menu {
  background: #ffffff;
  border-radius: 8px;
  box-shadow: 0 4px 16px rgba(0, 0, 0, 0.15);
  min-width: 240px;
  overflow: hidden;
  user-select: none;
}

.node-context-menu__header {
  padding: 10px 16px;
  background: linear-gradient(135deg, #FF6B6B 0%, #FF8E53 100%);
  border-bottom: 1px solid #f0f0f0;
}

.node-context-menu__title {
  font-size: 13px;
  font-weight: 600;
  color: #ffffff;
  display: flex;
  align-items: center;
  gap: 6px;
}

.node-context-menu__info {
  padding: 8px 16px;
  background: #f9fafb;
}

.node-context-menu__info-item {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 4px 0;
  font-size: 12px;
}

.node-context-menu__info-label {
  color: #8c8c8c;
  flex-shrink: 0;
  margin-right: 12px;
}

.node-context-menu__info-value {
  color: #262626;
  font-weight: 500;
  text-align: right;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.node-context-menu__item {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 10px 16px;
  cursor: pointer;
  transition: all 0.2s;
  position: relative;
}

.node-context-menu__item:hover {
  background: #f5f7fa;
}

.node-context-menu__item:active {
  background: #e8ecf1;
}

.node-context-menu__item--danger {
  color: #ff4d4f;
}

.node-context-menu__item--danger:hover {
  background: #fff1f0;
}

.node-context-menu__icon {
  font-size: 16px;
  width: 20px;
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
}

.node-context-menu__text {
  flex: 1;
  font-size: 13px;
  color: inherit;
}

.node-context-menu__shortcut {
  font-size: 11px;
  color: #8c8c8c;
  background: #f5f5f5;
  padding: 2px 6px;
  border-radius: 3px;
  font-family: 'Monaco', 'Menlo', 'Consolas', monospace;
  flex-shrink: 0;
}

.node-context-menu__divider {
  height: 1px;
  background: #f0f0f0;
  margin: 4px 0;
}

/* 自定义滚动条 */
.demo-slot-node-menu__log-content::-webkit-scrollbar {
  width: 6px;
}

.demo-slot-node-menu__log-content::-webkit-scrollbar-track {
  background: #f0f0f0;
  border-radius: 3px;
}

.demo-slot-node-menu__log-content::-webkit-scrollbar-thumb {
  background: #bfbfbf;
  border-radius: 3px;
}

.demo-slot-node-menu__log-content::-webkit-scrollbar-thumb:hover {
  background: #999;
}
</style>
