export default "<template>\r\n  <div class=\"demo-slot-palette\">\r\n    <!-- 事件日志面板 -->\r\n    <div class=\"demo-slot-palette__log\">\r\n      <div class=\"demo-slot-palette__log-header\">\r\n        <h4>事件日志</h4>\r\n        <button class=\"demo-slot-palette__clear-btn\" @click=\"clearLogs\" title=\"清除日志\">\r\n          清除\r\n        </button>\r\n      </div>\r\n      <div class=\"demo-slot-palette__log-content\">\r\n        <div v-for=\"(log, index) in logs\" :key=\"index\" class=\"demo-slot-palette__log-item\">\r\n          {{ log }}\r\n        </div>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- 画布容器 -->\r\n    <div class=\"demo-slot-palette__canvas\">\r\n      <FlowDesignerLayout\r\n        mode=\"design\"\r\n        :before-graph-init=\"handleBeforeGraphInit\"\r\n        @ready=\"handleReady\"\r\n      >\r\n        <!-- 自定义节点面板插槽 -->\r\n        <template #palette=\"{ onStartDrag }\">\r\n          <div class=\"custom-palette\">\r\n            <div class=\"custom-palette__header\">\r\n              <h3 class=\"custom-palette__title\">自定义节点</h3>\r\n              <span class=\"custom-palette__desc\">拖拽到画布</span>\r\n            </div>\r\n\r\n            <div class=\"custom-palette__section\">\r\n              <div class=\"custom-palette__section-title\">基础节点</div>\r\n              <div\r\n                v-for=\"nodeType in customNodeTypes\"\r\n                :key=\"nodeType.type\"\r\n                class=\"custom-palette__item\"\r\n                @mousedown=\"(e) => handleStartDrag(e, nodeType, onStartDrag)\"\r\n              >\r\n                <div class=\"custom-palette__item-icon\" :style=\"{ background: nodeType.color }\">\r\n                  {{ nodeType.icon }}\r\n                </div>\r\n                <div class=\"custom-palette__item-info\">\r\n                  <div class=\"custom-palette__item-label\">{{ nodeType.label }}</div>\r\n                  <div class=\"custom-palette__item-hint\">{{ nodeType.hint }}</div>\r\n                </div>\r\n              </div>\r\n            </div>\r\n          </div>\r\n        </template>\r\n      </FlowDesignerLayout>\r\n    </div>\r\n  </div>\r\n</template>\r\n\r\n<script setup lang=\"ts\">\r\nimport { ref } from 'vue'\r\nimport FlowDesignerLayout from '@/components/FlowDesigner/FlowDesignerLayout.vue'\r\nimport type { FlowDesigner, FlowDesignerOptions } from '@/components/FlowDesigner/core'\r\nimport { Graph } from '@antv/x6'\r\n\r\nconst logs = ref<string[]>([])\r\nconst customNodeTypes = ref([\r\n  {\r\n    type: 'custom-circle',\r\n    label: '圆形节点',\r\n    icon: '⚪',\r\n    hint: '用于流程开始/结束',\r\n    color: '#5F95FF',\r\n    width: 80,\r\n    height: 80,\r\n  },\r\n  {\r\n    type: 'custom-diamond',\r\n    label: '菱形节点',\r\n    icon: '◆',\r\n    hint: '用于条件判断',\r\n    color: '#47C769',\r\n    width: 100,\r\n    height: 80,\r\n  },\r\n])\r\n\r\nfunction addLog(message: string) {\r\n  const timestamp = new Date().toLocaleTimeString()\r\n  logs.value.push(`[${timestamp}] ${message}`)\r\n}\r\n\r\nfunction clearLogs() {\r\n  logs.value = []\r\n}\r\n\r\n/**\r\n * Graph 初始化前钩子：注册自定义 X6 原生节点\r\n */\r\nfunction handleBeforeGraphInit(options: FlowDesignerOptions) {\r\n  addLog('🔧 beforeGraphInit: 开始注册自定义节点')\r\n\r\n  // 注册第 1 个节点：圆形节点\r\n  Graph.registerNode(\r\n    'custom-circle',\r\n    {\r\n      inherit: 'circle',\r\n      width: 80,\r\n      height: 80,\r\n      attrs: {\r\n        body: {\r\n          fill: '#5F95FF',\r\n          stroke: '#2563EB',\r\n          strokeWidth: 2,\r\n        },\r\n        label: {\r\n          fill: '#fff',\r\n          fontSize: 14,\r\n          fontWeight: 500,\r\n        },\r\n      },\r\n      ports: {\r\n        groups: {\r\n          top: {\r\n            position: 'top',\r\n            attrs: {\r\n              circle: {\r\n                r: 4,\r\n                magnet: true,\r\n                stroke: '#2563EB',\r\n                strokeWidth: 1,\r\n                fill: '#fff',\r\n              },\r\n            },\r\n          },\r\n          bottom: {\r\n            position: 'bottom',\r\n            attrs: {\r\n              circle: {\r\n                r: 4,\r\n                magnet: true,\r\n                stroke: '#2563EB',\r\n                strokeWidth: 1,\r\n                fill: '#fff',\r\n              },\r\n            },\r\n          },\r\n        },\r\n        items: [\r\n          { group: 'top', id: 'port-top' },\r\n          { group: 'bottom', id: 'port-bottom' },\r\n        ],\r\n      },\r\n    },\r\n    true // 覆盖已存在的同名节点\r\n  )\r\n\r\n  addLog('✅ 已注册节点: custom-circle (圆形)')\r\n\r\n  // 注册第 2 个节点：菱形节点\r\n  Graph.registerNode(\r\n    'custom-diamond',\r\n    {\r\n      inherit: 'polygon',\r\n      width: 100,\r\n      height: 80,\r\n      attrs: {\r\n        body: {\r\n          fill: '#47C769',\r\n          stroke: '#27AE60',\r\n          strokeWidth: 2,\r\n          refPoints: '0,10 10,0 20,10 10,20',\r\n        },\r\n        label: {\r\n          fill: '#fff',\r\n          fontSize: 13,\r\n          fontWeight: 500,\r\n          textWrap: {\r\n            width: -20,\r\n            height: -20,\r\n            ellipsis: true,\r\n          },\r\n        },\r\n      },\r\n      ports: {\r\n        groups: {\r\n          top: {\r\n            position: { name: 'top' },\r\n            attrs: {\r\n              circle: {\r\n                r: 4,\r\n                magnet: true,\r\n                stroke: '#27AE60',\r\n                strokeWidth: 1,\r\n                fill: '#fff',\r\n              },\r\n            },\r\n          },\r\n          right: {\r\n            position: { name: 'right' },\r\n            attrs: {\r\n              circle: {\r\n                r: 4,\r\n                magnet: true,\r\n                stroke: '#27AE60',\r\n                strokeWidth: 1,\r\n                fill: '#fff',\r\n              },\r\n            },\r\n          },\r\n          bottom: {\r\n            position: { name: 'bottom' },\r\n            attrs: {\r\n              circle: {\r\n                r: 4,\r\n                magnet: true,\r\n                stroke: '#27AE60',\r\n                strokeWidth: 1,\r\n                fill: '#fff',\r\n              },\r\n            },\r\n          },\r\n          left: {\r\n            position: { name: 'left' },\r\n            attrs: {\r\n              circle: {\r\n                r: 4,\r\n                magnet: true,\r\n                stroke: '#27AE60',\r\n                strokeWidth: 1,\r\n                fill: '#fff',\r\n              },\r\n            },\r\n          },\r\n        },\r\n        items: [\r\n          { group: 'top', id: 'port-top' },\r\n          { group: 'right', id: 'port-right' },\r\n          { group: 'bottom', id: 'port-bottom' },\r\n          { group: 'left', id: 'port-left' },\r\n        ],\r\n      },\r\n    },\r\n    true\r\n  )\r\n\r\n  addLog('✅ 已注册节点: custom-diamond (菱形)')\r\n  addLog('🎉 所有自定义节点注册完成')\r\n}\r\n\r\nfunction handleReady(designer: FlowDesigner, graph: Graph) {\r\n  addLog('✅ 画布初始化完成')\r\n  addLog('🎨 自定义节点面板已渲染')\r\n  addLog('💡 提示: 点击左侧节点拖拽到画布')\r\n}\r\n\r\nfunction handleStartDrag(e: MouseEvent, nodeType: any, onStartDrag: any) {\r\n  addLog(`🎯 开始拖拽: ${nodeType.label}`)\r\n\r\n  // 使用 palette 插槽提供的 onStartDrag 函数\r\n  // 参数：(event, nodeConfig)\r\n  // nodeConfig 是完整的 X6 Node.Metadata 对象\r\n  onStartDrag(e, {\r\n    shape: nodeType.type,\r\n    label: nodeType.label,\r\n    width: nodeType.width,\r\n    height: nodeType.height,\r\n    data: {\r\n      label: nodeType.label,\r\n      // 其他业务数据\r\n      nodeInfo: {\r\n        icon: nodeType.icon,\r\n        hint: nodeType.hint,\r\n        color: nodeType.color,\r\n      }\r\n    }\r\n  })\r\n}\r\n</script>\r\n\r\n<style scoped>\r\n.demo-slot-palette {\r\n  display: flex;\r\n  height: 100%;\r\n  min-height: 500px;\r\n  gap: 16px;\r\n}\r\n\r\n.demo-slot-palette__log {\r\n  width: 280px;\r\n  border: 1px solid #e8e8e8;\r\n  border-radius: 8px;\r\n  padding: 16px;\r\n  background: #fafafa;\r\n  overflow: hidden;\r\n  display: flex;\r\n  flex-direction: column;\r\n}\r\n\r\n.demo-slot-palette__log-header {\r\n  display: flex;\r\n  justify-content: space-between;\r\n  align-items: center;\r\n  margin-bottom: 12px;\r\n}\r\n\r\n.demo-slot-palette__log h4 {\r\n  margin: 0;\r\n  font-size: 14px;\r\n  color: #1a1a2e;\r\n  font-weight: 600;\r\n}\r\n\r\n.demo-slot-palette__clear-btn {\r\n  padding: 2px 8px;\r\n  font-size: 12px;\r\n  color: #666;\r\n  background: #fff;\r\n  border: 1px solid #d9d9d9;\r\n  border-radius: 4px;\r\n  cursor: pointer;\r\n  transition: all 0.2s;\r\n  user-select: none;\r\n}\r\n\r\n.demo-slot-palette__clear-btn:hover {\r\n  color: #1890ff;\r\n  border-color: #1890ff;\r\n}\r\n\r\n.demo-slot-palette__log-content {\r\n  flex: 1;\r\n  overflow-y: auto;\r\n  font-size: 12px;\r\n  line-height: 1.8;\r\n}\r\n\r\n.demo-slot-palette__log-item {\r\n  padding: 4px 0;\r\n  color: #555;\r\n  font-family: 'Monaco', 'Menlo', 'Consolas', monospace;\r\n  border-bottom: 1px solid #f0f0f0;\r\n}\r\n\r\n.demo-slot-palette__log-item:last-child {\r\n  border-bottom: none;\r\n}\r\n\r\n.demo-slot-palette__canvas {\r\n  flex: 1;\r\n  border: 1px solid #e8e8e8;\r\n  border-radius: 8px;\r\n  overflow: hidden;\r\n  background: #fff;\r\n}\r\n\r\n/* ==================== 自定义节点面板样式 ==================== */\r\n.custom-palette {\r\n  display: flex;\r\n  flex-direction: column;\r\n  height: 100%;\r\n  background: linear-gradient(to bottom, #f9fafb, #ffffff);\r\n  border-right: 1px solid #e8e8e8;\r\n  width: 180px;\r\n}\r\n\r\n.custom-palette__header {\r\n  padding: 16px;\r\n  border-bottom: 2px solid #e8e8e8;\r\n  background: #fff;\r\n}\r\n\r\n.custom-palette__title {\r\n  margin: 0 0 4px 0;\r\n  font-size: 16px;\r\n  font-weight: 600;\r\n  color: #1a1a2e;\r\n}\r\n\r\n.custom-palette__desc {\r\n  font-size: 12px;\r\n  color: #999;\r\n}\r\n\r\n.custom-palette__section {\r\n  padding: 12px;\r\n}\r\n\r\n.custom-palette__section-title {\r\n  font-size: 11px;\r\n  font-weight: 600;\r\n  color: #999;\r\n  text-transform: uppercase;\r\n  letter-spacing: 0.06em;\r\n  margin-bottom: 8px;\r\n  padding: 0 4px;\r\n}\r\n\r\n.custom-palette__item {\r\n  display: flex;\r\n  align-items: center;\r\n  gap: 12px;\r\n  padding: 10px;\r\n  margin-bottom: 8px;\r\n  background: #fff;\r\n  border: 1px solid #e8e8e8;\r\n  border-radius: 6px;\r\n  cursor: move;\r\n  transition: all 0.2s;\r\n  user-select: none;\r\n}\r\n\r\n.custom-palette__item:hover {\r\n  border-color: #1677ff;\r\n  box-shadow: 0 2px 8px rgba(22, 119, 255, 0.15);\r\n  transform: translateY(-1px);\r\n}\r\n\r\n.custom-palette__item:active {\r\n  transform: translateY(0);\r\n  box-shadow: 0 1px 4px rgba(22, 119, 255, 0.2);\r\n}\r\n\r\n.custom-palette__item-icon {\r\n  width: 36px;\r\n  height: 36px;\r\n  display: flex;\r\n  align-items: center;\r\n  justify-content: center;\r\n  border-radius: 6px;\r\n  font-size: 18px;\r\n  flex-shrink: 0;\r\n}\r\n\r\n.custom-palette__item-info {\r\n  flex: 1;\r\n  min-width: 0;\r\n}\r\n\r\n.custom-palette__item-label {\r\n  font-size: 13px;\r\n  font-weight: 500;\r\n  color: #333;\r\n  margin-bottom: 2px;\r\n}\r\n\r\n.custom-palette__item-hint {\r\n  font-size: 11px;\r\n  color: #999;\r\n  white-space: nowrap;\r\n  overflow: hidden;\r\n  text-overflow: ellipsis;\r\n}\r\n</style>\r\n"