  {
    type: 'vue-start-node',
    label: '开始节点',
    classNamePerfix: 'x6',
    width: 120,
    height: 38,
    rectStroke: '#95d375',
    rectStrokeWidth: 1,
    rectFill: '#edf8e7',
    icon: startSvg,
    iconHover: startHover,
    textFill: '#81cb5c'
  },
  {
    type: 'vue-approval-node',
    label: '审批节点',
    classNamePerfix: 'x6',
    width: 120,
    height: 38,
    rectStroke: '#83b3f7',
    rectStrokeWidth: 1,
    rectFill: '#e6eeff',
    icon: approvalSvg,
    iconHover: approvalHoverSvg,
    textFill: '#5d9df7'
  },
]

const Ports = {
