        },
      },
    },
    right: {
      position: 'right',
      attrs: {
        circle: {
          r: 4,
          magnet: true,
          stroke: '#5F95FF',
          strokeWidth: 1,
          fill: '#fff',
          style: {
            visibility: 'hidden',
          },
        },
        label: {
          position: 'right',
        },
        text: {
          text: '',
          fill: '#ff5800',
        },
      },
    },
    bottom: {
      position: 'bottom',
      attrs: {
        circle: {
          r: 4,
          magnet: true,
          stroke: '#5F95FF',
          strokeWidth: 1,
          fill: '#fff',
          style: {
            visibility: 'hidden',
          },
        },
        label: {
          position: 'bottom',
        },
        text: {
          text: '',
          fill: '#ff5800',
        },
      },
    },
    left: {
      position: 'left',
      attrs: {
        circle: {
          r: 4,
          magnet: true,
          stroke: '#5F95FF',
          strokeWidth: 1,
          fill: '#fff',
          style: {
            visibility: 'hidden',
          },
        },
        label: {
          position: 'left',
        },
        text: {
          text: '',
          fill: '#ff5800',
        },
      },
    },
  },
  items: [
    {
      group: 'top',
      label: {
        position : 'top'
      }
    },
    {
      group: 'right',
      label: {
        position : 'right'
      }
    },
    {
      group: 'bottom',
      label: {
        position : 'bottom'
      }
    },
    {
      group: 'left',
      label: {
        position : 'left'
      }
    },
  ],
}


// 手动跟踪节点的选中状态（因为 X6 的 selection 可能有默认行为）
const selectedNodesMap = new Map<string, boolean>()

function addLog(message: string) {
  const timestamp = new Date().toLocaleTimeString()
  logs.value.push(`[${timestamp}] ${message}`)
}

function clearLogs() {
  logs.value = []
}



/**
 * Graph 初始化前钩子：注册带 SVG icon 的自定义节点
 */
function handleBeforeGraphInit(options: FlowDesignerOptions) {
  addLog('🔧 beforeGraphInit: 开始注册 SVG 节点')

  register({
    shape: 'vue-start-node',
    width: 120, height: 38,
    component: StartNode,
    ports: { ...Ports },
  })

  register({
    shape: 'vue-approval-node',
    width: 120, height: 38,
    component: ApproverNode,
    ports: { ...Ports },
  })

  addLog('🎉 所有 SVG 节点注册完成')
}

function handleReady(designer: FlowDesigner, graph: Graph) {
  addLog('✅ 画布初始化完成')
  addLog('💡 提示: 悬停查看 hover 效果，点击切换 selected 状态')


  // ─── 添加示例节点 ───────────────────────────────────────────────────
  setTimeout(() => {
    graph.addNode({
      shape: 'vue-start-node',
      x: 100,
      y: 100,
      label: '开始节点',
    })

    addLog('📦 已添加 3 个示例节点')
    addLog('🎨 试试悬停和点击节点吧！')
  }, 100)
}

function handleStartDrag(e: MouseEvent, nodeType: NodeTypeConfig, onStartDrag: any) {
  addLog(`🎯 开始拖拽: ${nodeType.label}`)

  onStartDrag(e, {
    shape: nodeType.type,
    label: nodeType.label,
    width: nodeType.width,
    height: nodeType.height,
    data: {
      label: nodeType.label,
      nodeInfo: {
        hint: nodeType.hint,
        color: nodeType.color,
      }
    }
  })
}
</script>

