  border: 1px solid #e8e8e8;
  border-radius: 8px;
  padding: 16px;
  background: #fafafa;
  overflow: hidden;
  display: flex;
  flex-direction: column;
}

.demo-slot-edge-menu__log-header {
  display: flex;
  justify-content: space-between;
