  flex: 1;
  overflow-y: auto;
  font-size: 12px;
  line-height: 1.8;
}

.demo-slot-edge-menu__log-item {
  padding: 4px 0;
  color: #555;
  font-family: 'Monaco', 'Menlo', 'Consolas', monospace;
  border-bottom: 1px solid #f0f0f0;
}

.demo-slot-edge-menu__log-item:last-child {
  border-bottom: none;
}

.demo-slot-edge-menu__canvas {
  flex: 1;
  border: 1px solid #e8e8e8;
  border-radius: 8px;
  overflow: hidden;
  background: #fff;
  position: relative;
}

