export default "<template>\r\n  <div class=\"demo-slot-edge-menu\">\r\n    <!-- 事件日志面板 -->\r\n    <div class=\"demo-slot-edge-menu__log\">\r\n      <div class=\"demo-slot-edge-menu__log-header\">\r\n        <h4>事件日志</h4>\r\n        <button class=\"demo-slot-edge-menu__clear-btn\" @click=\"clearLogs\" title=\"清除日志\">\r\n          清除\r\n        </button>\r\n      </div>\r\n      <div class=\"demo-slot-edge-menu__log-content\">\r\n        <div v-for=\"(log, index) in logs\" :key=\"index\" class=\"demo-slot-edge-menu__log-item\">\r\n          {{ log }}\r\n        </div>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- 画布容器 -->\r\n    <div class=\"demo-slot-edge-menu__canvas\">\r\n      <FlowDesignerLayout\r\n        mode=\"design\"\r\n        :before-graph-init=\"handleBeforeGraphInit\"\r\n        @ready=\"handleReady\"\r\n      >\r\n        <!-- 自定义连线右键菜单插槽 -->\r\n        <template #edge-menu=\"{ edge, capabilities, designer, graph, onSelect }\">\r\n          <div class=\"edge-context-menu\" @click.stop>\r\n            <div class=\"edge-context-menu__header\">\r\n              <span class=\"edge-context-menu__title\">连线菜单</span>\r\n            </div>\r\n\r\n            <!-- 连线信息显示 -->\r\n            <div class=\"edge-context-menu__info\">\r\n              <div class=\"edge-context-menu__info-item\">\r\n                <span class=\"edge-context-menu__info-label\">连线标签:</span>\r\n                <span class=\"edge-context-menu__info-value\">{{ getEdgeLabel(edge) }}</span>\r\n              </div>\r\n              <div class=\"edge-context-menu__info-item\">\r\n                <span class=\"edge-context-menu__info-label\">源节点:</span>\r\n                <span class=\"edge-context-menu__info-value\">{{ getEdgeSourceLabel(edge) }}</span>\r\n              </div>\r\n              <div class=\"edge-context-menu__info-item\">\r\n                <span class=\"edge-context-menu__info-label\">目标节点:</span>\r\n                <span class=\"edge-context-menu__info-value\">{{ getEdgeTargetLabel(edge) }}</span>\r\n              </div>\r\n              <div class=\"edge-context-menu__info-item\">\r\n                <span class=\"edge-context-menu__info-label\">连线类型:</span>\r\n                <span class=\"edge-context-menu__info-value\">{{ edge.shape }}</span>\r\n              </div>\r\n            </div>\r\n\r\n            <div class=\"edge-context-menu__divider\" />\r\n\r\n            <!-- 编辑标签 -->\r\n            <div\r\n              class=\"edge-context-menu__item\"\r\n              @click=\"handleEditLabel(edge, designer)\"\r\n            >\r\n              <span class=\"edge-context-menu__icon\">✏️</span>\r\n              <span class=\"edge-context-menu__text\">编辑标签</span>\r\n            </div>\r\n\r\n            <!-- 分隔线 -->\r\n            <div class=\"edge-context-menu__divider\" />\r\n\r\n            <!-- 样式操作（使用 edge 直接修改） -->\r\n            <div\r\n              class=\"edge-context-menu__item\"\r\n              @click=\"handleChangeStyle(edge, 'normal')\"\r\n            >\r\n              <span class=\"edge-context-menu__icon\">━</span>\r\n              <span class=\"edge-context-menu__text\">直线样式</span>\r\n            </div>\r\n            <div\r\n              class=\"edge-context-menu__item\"\r\n              @click=\"handleChangeStyle(edge, 'smooth')\"\r\n            >\r\n              <span class=\"edge-context-menu__icon\">〰️</span>\r\n              <span class=\"edge-context-menu__text\">平滑曲线</span>\r\n            </div>\r\n            <div\r\n              class=\"edge-context-menu__item\"\r\n              @click=\"handleChangeStyle(edge, 'rounded')\"\r\n            >\r\n              <span class=\"edge-context-menu__icon\">⌝</span>\r\n              <span class=\"edge-context-menu__text\">圆角折线</span>\r\n            </div>\r\n\r\n            <!-- 分隔线 -->\r\n            <div class=\"edge-context-menu__divider\" />\r\n\r\n            <!-- 颜色操作 -->\r\n            <div\r\n              class=\"edge-context-menu__item\"\r\n              @click=\"handleChangeColor(edge, '#1890ff', '蓝色')\"\r\n            >\r\n              <span class=\"edge-context-menu__icon\" style=\"color: #1890ff;\">●</span>\r\n              <span class=\"edge-context-menu__text\">蓝色连线</span>\r\n            </div>\r\n            <div\r\n              class=\"edge-context-menu__item\"\r\n              @click=\"handleChangeColor(edge, '#52c41a', '绿色')\"\r\n            >\r\n              <span class=\"edge-context-menu__icon\" style=\"color: #52c41a;\">●</span>\r\n              <span class=\"edge-context-menu__text\">绿色连线</span>\r\n            </div>\r\n            <div\r\n              class=\"edge-context-menu__item\"\r\n              @click=\"handleChangeColor(edge, '#ff4d4f', '红色')\"\r\n            >\r\n              <span class=\"edge-context-menu__icon\" style=\"color: #ff4d4f;\">●</span>\r\n              <span class=\"edge-context-menu__text\">红色连线</span>\r\n            </div>\r\n\r\n            <!-- 分隔线 -->\r\n            <div v-if=\"graph\" class=\"edge-context-menu__divider\" />\r\n\r\n            <!-- 自定义操作（使用 graph） -->\r\n            <div\r\n              v-if=\"graph\"\r\n              class=\"edge-context-menu__item\"\r\n              @click=\"handleCenterEdge(edge, graph)\"\r\n            >\r\n              <span class=\"edge-context-menu__icon\">🎯</span>\r\n              <span class=\"edge-context-menu__text\">居中显示</span>\r\n            </div>\r\n            <div\r\n              v-if=\"graph\"\r\n              class=\"edge-context-menu__item\"\r\n              @click=\"handleHighlightPath(edge, graph)\"\r\n            >\r\n              <span class=\"edge-context-menu__icon\">✨</span>\r\n              <span class=\"edge-context-menu__text\">高亮路径</span>\r\n            </div>\r\n            <div\r\n              v-if=\"graph\"\r\n              class=\"edge-context-menu__item\"\r\n              @click=\"handleReverseEdge(edge, graph)\"\r\n            >\r\n              <span class=\"edge-context-menu__icon\">🔄</span>\r\n              <span class=\"edge-context-menu__text\">反转连线</span>\r\n            </div>\r\n\r\n            <!-- 分隔线 -->\r\n            <div\r\n              v-if=\"capabilities.canDelete\"\r\n              class=\"edge-context-menu__divider\"\r\n            />\r\n\r\n            <!-- 删除 -->\r\n            <div\r\n              v-if=\"capabilities.canDelete\"\r\n              class=\"edge-context-menu__item edge-context-menu__item--danger\"\r\n              @click=\"handleMenuClick('delete', edge, onSelect)\"\r\n            >\r\n              <span class=\"edge-context-menu__icon\">🗑</span>\r\n              <span class=\"edge-context-menu__text\">删除连线</span>\r\n              <span class=\"edge-context-menu__shortcut\">Delete</span>\r\n            </div>\r\n          </div>\r\n        </template>\r\n      </FlowDesignerLayout>\r\n    </div>\r\n  </div>\r\n</template>\r\n\r\n<script setup lang=\"ts\">\r\nimport { ref } from 'vue'\r\nimport FlowDesignerLayout from '@/components/FlowDesigner/FlowDesignerLayout.vue'\r\nimport type { FlowDesigner, FlowDesignerOptions } from '@/components/FlowDesigner/core'\r\nimport { Graph, Edge } from '@antv/x6'\r\n\r\nconst logs = ref<string[]>([])\r\nlet designerInstance: FlowDesigner | null = null\r\nlet graphInstance: Graph | null = null\r\n\r\nfunction addLog(message: string) {\r\n  const timestamp = new Date().toLocaleTimeString()\r\n  logs.value.push(`[${timestamp}] ${message}`)\r\n  // 自动滚动到底部\r\n  setTimeout(() => {\r\n    const logContent = document.querySelector('.demo-slot-edge-menu__log-content')\r\n    if (logContent) {\r\n      logContent.scrollTop = logContent.scrollHeight\r\n    }\r\n  }, 0)\r\n}\r\n\r\nfunction clearLogs() {\r\n  logs.value = []\r\n}\r\n\r\n/**\r\n * Graph 初始化前注册自定义节点\r\n */\r\nfunction handleBeforeGraphInit(options: FlowDesignerOptions) {\r\n  addLog('🔧 初始化自定义节点样式...')\r\n\r\n  // 注册自定义节点：蓝色圆形\r\n  Graph.registerNode('custom-circle', {\r\n    inherit: 'circle',\r\n    width: 100,\r\n    height: 100,\r\n    attrs: {\r\n      body: {\r\n        fill: '#5F95FF',\r\n        stroke: '#2563EB',\r\n        strokeWidth: 2,\r\n      },\r\n      label: {\r\n        fill: '#fff',\r\n        fontSize: 14,\r\n        fontWeight: 500,\r\n      },\r\n    },\r\n  }, true)\r\n\r\n  Graph.registerNode('custom-rect', {\r\n    inherit: 'rect',\r\n    width: 140,\r\n    height: 70,\r\n    attrs: {\r\n      body: {\r\n        fill: '#47C769',\r\n        stroke: '#27AE60',\r\n        strokeWidth: 2,\r\n        rx: 8,\r\n        ry: 8,\r\n      },\r\n      label: {\r\n        fill: '#fff',\r\n        fontSize: 14,\r\n        fontWeight: 500,\r\n      },\r\n    },\r\n  }, true)\r\n}\r\n\r\n/**\r\n * 获取连线标签\r\n */\r\nfunction getEdgeLabel(edge: Edge): string {\r\n  const labels = edge.getLabels()\r\n  if (labels && labels.length > 0) {\r\n    return labels[0].attrs?.text?.text || '无标签'\r\n  }\r\n  return '无标签'\r\n}\r\n\r\n/**\r\n * 获取源节点标签\r\n */\r\nfunction getEdgeSourceLabel(edge: Edge): string {\r\n  const sourceNode = edge.getSourceNode()\r\n  if (sourceNode) {\r\n    const label = sourceNode.getProp('label')\r\n    return label ? String(label) : sourceNode.id.substring(0, 8) + '...'\r\n  }\r\n  return '未知'\r\n}\r\n\r\n/**\r\n * 获取目标节点标签\r\n */\r\nfunction getEdgeTargetLabel(edge: Edge): string {\r\n  const targetNode = edge.getTargetNode()\r\n  if (targetNode) {\r\n    const label = targetNode.getProp('label')\r\n    return label ? String(label) : targetNode.id.substring(0, 8) + '...'\r\n  }\r\n  return '未知'\r\n}\r\n\r\n/**\r\n * 处理菜单项点击\r\n */\r\nfunction handleMenuClick(action: string, edge: Edge, onSelect: (action: string) => void) {\r\n  addLog(`🖱️ 连线菜单: 删除连线 - ${getEdgeLabel(edge)}`)\r\n  onSelect(action)\r\n}\r\n\r\n/**\r\n * 编辑标签（使用 designer）\r\n */\r\nfunction handleEditLabel(edge: Edge, designer: FlowDesigner | null) {\r\n  const currentLabel = getEdgeLabel(edge)\r\n  const newLabel = prompt('请输入新的标签:', currentLabel === '无标签' ? '' : currentLabel)\r\n\r\n  if (newLabel !== null && designer) {\r\n    designer.updateEdgeLabelText(edge, newLabel)\r\n    addLog(`✏️ 编辑标签: ${currentLabel} → ${newLabel}`)\r\n  }\r\n}\r\n\r\n/**\r\n * 修改连线样式\r\n */\r\nfunction handleChangeStyle(edge: Edge, connectorType: 'normal' | 'smooth' | 'rounded') {\r\n  const connectorMap = {\r\n    'normal': { name: 'normal' },\r\n    'smooth': { name: 'smooth' },\r\n    'rounded': { name: 'rounded', args: { radius: 10 } }\r\n  }\r\n\r\n  edge.setConnector(connectorMap[connectorType])\r\n\r\n  const styleNameMap = {\r\n    'normal': '直线',\r\n    'smooth': '平滑曲线',\r\n    'rounded': '圆角折线'\r\n  }\r\n\r\n  addLog(`━ 样式修改: ${styleNameMap[connectorType]} - ${getEdgeLabel(edge)}`)\r\n}\r\n\r\n/**\r\n * 修改连线颜色\r\n */\r\nfunction handleChangeColor(edge: Edge, color: string, colorName: string) {\r\n  edge.attr('line/stroke', color)\r\n  edge.attr('line/strokeWidth', 2)\r\n\r\n  addLog(`● 颜色修改: ${colorName} - ${getEdgeLabel(edge)}`)\r\n}\r\n\r\n/**\r\n * 居中显示连线（使用 graph）\r\n */\r\nfunction handleCenterEdge(edge: Edge, graph: Graph) {\r\n  graph.centerCell(edge, {\r\n    padding: 100,\r\n    animation: {\r\n      duration: 300,\r\n      easing: 'ease-in-out'\r\n    }\r\n  })\r\n\r\n  addLog(`🎯 居中显示连线: ${getEdgeLabel(edge)}`)\r\n}\r\n\r\n/**\r\n * 高亮路径：源节点 → 连线 → 目标节点（使用 graph）\r\n */\r\nfunction handleHighlightPath(edge: Edge, graph: Graph) {\r\n  const sourceNode = edge.getSourceNode()\r\n  const targetNode = edge.getTargetNode()\r\n\r\n  // 保存原始样式\r\n  const edgeOriginalStroke = edge.attr('line/stroke') || '#8c9bb5'\r\n  const edgeOriginalWidth = edge.attr('line/strokeWidth') || 1.5\r\n\r\n  // 高亮连线\r\n  edge.attr('line/stroke', '#FF4D4F')\r\n  edge.attr('line/strokeWidth', 3)\r\n\r\n  // 高亮源节点和目标节点\r\n  if (sourceNode) {\r\n    sourceNode.attr('body/stroke', '#FF4D4F')\r\n    sourceNode.attr('body/strokeWidth', 3)\r\n  }\r\n  if (targetNode) {\r\n    targetNode.attr('body/stroke', '#FF4D4F')\r\n    targetNode.attr('body/strokeWidth', 3)\r\n  }\r\n\r\n  addLog(`✨ 高亮路径: ${getEdgeSourceLabel(edge)} → ${getEdgeTargetLabel(edge)}`)\r\n\r\n  // 3秒后恢复\r\n  setTimeout(() => {\r\n    edge.attr('line/stroke', edgeOriginalStroke)\r\n    edge.attr('line/strokeWidth', edgeOriginalWidth)\r\n\r\n    if (sourceNode) {\r\n      sourceNode.attr('body/stroke', '#27AE60')\r\n      sourceNode.attr('body/strokeWidth', 2)\r\n    }\r\n    if (targetNode) {\r\n      targetNode.attr('body/stroke', '#27AE60')\r\n      targetNode.attr('body/strokeWidth', 2)\r\n    }\r\n\r\n    addLog(`⏰ 高亮已恢复`)\r\n  }, 3000)\r\n}\r\n\r\n/**\r\n * 反转连线方向（使用 graph）\r\n */\r\nfunction handleReverseEdge(edge: Edge, graph: Graph) {\r\n  const source = edge.getSource()\r\n  const target = edge.getTarget()\r\n  const labels = edge.getLabels()\r\n\r\n  // 交换源和目标\r\n  edge.setSource(target)\r\n  edge.setTarget(source)\r\n\r\n  addLog(`🔄 反转连线: ${getEdgeSourceLabel(edge)} ⇄ ${getEdgeTargetLabel(edge)}`)\r\n}\r\n\r\nfunction handleReady(designer: FlowDesigner, graph: Graph) {\r\n\r\n  graph = designer.getGraph()\r\n\r\n  addLog('FlowDesigner 初始化完成')\r\n  addLog('✨ 将鼠标悬停在节点上查看自定义 Tooltip')\r\n\r\n  // 初始化测试数据\r\n  initTestData(graph)\r\n}\r\n\r\nfunction initTestData(graph) {\r\n\r\n  // 添加初始节点\r\n  const node1 = graph.addNode({\r\n    shape: 'custom-circle',\r\n    x: 100,\r\n    y: 100,\r\n    label: '开始',\r\n    data: {\r\n      description: '流程开始节点',\r\n      owner: '张三',\r\n      priority: 'high',\r\n    },\r\n  })\r\n\r\n  const node2 = graph.addNode({\r\n    shape: 'custom-rect',\r\n    x: 300,\r\n    y: 100,\r\n    label: '处理',\r\n    data: {\r\n      description: '执行业务处理',\r\n      owner: '李四',\r\n      priority: 'medium',\r\n    },\r\n  })\r\n\r\n  const node3 = graph.addNode({\r\n    shape: 'custom-circle',\r\n    x: 500,\r\n    y: 100,\r\n    label: '结束',\r\n    data: {\r\n      description: '流程结束',\r\n      owner: '王五',\r\n      priority: 'low',\r\n    },\r\n  })\r\n\r\n  // 添加连线\r\n  graph.addEdge({\r\n    source: node1,\r\n    target: node2,\r\n    shape: 'flow-edge',\r\n    labels: [{ attrs: { text: { text: '通过' } } }],\r\n    data: {\r\n      lineType: 'normal',\r\n      condition: 'status === \"approved\"',\r\n      description: '审批通过后的流转',\r\n      isDefault: false,\r\n    },\r\n  })\r\n\r\n  graph.addEdge({\r\n    source: node2,\r\n    target: node3,\r\n    shape: 'flow-edge',\r\n    labels: [{ attrs: { text: { text: '完成' } } }],\r\n    data: {\r\n      lineType: 'normal',\r\n      condition: '',\r\n      description: '处理完成后结束',\r\n      isDefault: true,\r\n    },\r\n  })\r\n}\r\n</script>\r\n\r\n<style scoped>\r\n.demo-slot-edge-menu {\r\n  display: flex;\r\n  height: 100%;\r\n  min-height: 500px;\r\n  gap: 16px;\r\n}\r\n\r\n.demo-slot-edge-menu__log {\r\n  width: 320px;\r\n  border: 1px solid #e8e8e8;\r\n  border-radius: 8px;\r\n  padding: 16px;\r\n  background: #fafafa;\r\n  overflow: hidden;\r\n  display: flex;\r\n  flex-direction: column;\r\n}\r\n\r\n.demo-slot-edge-menu__log-header {\r\n  display: flex;\r\n  justify-content: space-between;\r\n  align-items: center;\r\n  margin-bottom: 12px;\r\n}\r\n\r\n.demo-slot-edge-menu__log h4 {\r\n  margin: 0;\r\n  font-size: 14px;\r\n  color: #1a1a2e;\r\n  font-weight: 600;\r\n}\r\n\r\n.demo-slot-edge-menu__clear-btn {\r\n  padding: 2px 8px;\r\n  font-size: 12px;\r\n  color: #666;\r\n  background: #fff;\r\n  border: 1px solid #d9d9d9;\r\n  border-radius: 4px;\r\n  cursor: pointer;\r\n  transition: all 0.2s;\r\n  user-select: none;\r\n}\r\n\r\n.demo-slot-edge-menu__clear-btn:hover {\r\n  color: #1890ff;\r\n  border-color: #1890ff;\r\n}\r\n\r\n.demo-slot-edge-menu__log-content {\r\n  flex: 1;\r\n  overflow-y: auto;\r\n  font-size: 12px;\r\n  line-height: 1.8;\r\n}\r\n\r\n.demo-slot-edge-menu__log-item {\r\n  padding: 4px 0;\r\n  color: #555;\r\n  font-family: 'Monaco', 'Menlo', 'Consolas', monospace;\r\n  border-bottom: 1px solid #f0f0f0;\r\n}\r\n\r\n.demo-slot-edge-menu__log-item:last-child {\r\n  border-bottom: none;\r\n}\r\n\r\n.demo-slot-edge-menu__canvas {\r\n  flex: 1;\r\n  border: 1px solid #e8e8e8;\r\n  border-radius: 8px;\r\n  overflow: hidden;\r\n  background: #fff;\r\n  position: relative;\r\n}\r\n\r\n/* ==================== 连线右键菜单样式 ==================== */\r\n.edge-context-menu {\r\n  background: #ffffff;\r\n  border-radius: 8px;\r\n  box-shadow: 0 4px 16px rgba(0, 0, 0, 0.15);\r\n  min-width: 220px;\r\n  overflow: hidden;\r\n  user-select: none;\r\n}\r\n\r\n.edge-context-menu__header {\r\n  padding: 10px 16px;\r\n  background: linear-gradient(135deg, #36D1DC 0%, #5B86E5 100%);\r\n  border-bottom: 1px solid #f0f0f0;\r\n}\r\n\r\n.edge-context-menu__title {\r\n  font-size: 13px;\r\n  font-weight: 600;\r\n  color: #ffffff;\r\n  display: flex;\r\n  align-items: center;\r\n  gap: 6px;\r\n}\r\n\r\n.edge-context-menu__info {\r\n  padding: 8px 16px;\r\n  background: #f9fafb;\r\n}\r\n\r\n.edge-context-menu__info-item {\r\n  display: flex;\r\n  justify-content: space-between;\r\n  align-items: center;\r\n  padding: 4px 0;\r\n  font-size: 12px;\r\n}\r\n\r\n.edge-context-menu__info-label {\r\n  color: #8c8c8c;\r\n  flex-shrink: 0;\r\n  margin-right: 12px;\r\n}\r\n\r\n.edge-context-menu__info-value {\r\n  color: #262626;\r\n  font-weight: 500;\r\n  text-align: right;\r\n  overflow: hidden;\r\n  text-overflow: ellipsis;\r\n  white-space: nowrap;\r\n}\r\n\r\n.edge-context-menu__item {\r\n  display: flex;\r\n  align-items: center;\r\n  gap: 10px;\r\n  padding: 10px 16px;\r\n  cursor: pointer;\r\n  transition: all 0.2s;\r\n  position: relative;\r\n}\r\n\r\n.edge-context-menu__item:hover {\r\n  background: #f5f7fa;\r\n}\r\n\r\n.edge-context-menu__item:active {\r\n  background: #e8ecf1;\r\n}\r\n\r\n.edge-context-menu__item--danger {\r\n  color: #ff4d4f;\r\n}\r\n\r\n.edge-context-menu__item--danger:hover {\r\n  background: #fff1f0;\r\n}\r\n\r\n.edge-context-menu__icon {\r\n  font-size: 16px;\r\n  width: 20px;\r\n  display: flex;\r\n  align-items: center;\r\n  justify-content: center;\r\n  flex-shrink: 0;\r\n}\r\n\r\n.edge-context-menu__text {\r\n  flex: 1;\r\n  font-size: 13px;\r\n  color: inherit;\r\n}\r\n\r\n.edge-context-menu__shortcut {\r\n  font-size: 11px;\r\n  color: #8c8c8c;\r\n  background: #f5f5f5;\r\n  padding: 2px 6px;\r\n  border-radius: 3px;\r\n  font-family: 'Monaco', 'Menlo', 'Consolas', monospace;\r\n  flex-shrink: 0;\r\n}\r\n\r\n.edge-context-menu__divider {\r\n  height: 1px;\r\n  background: #f0f0f0;\r\n  margin: 4px 0;\r\n}\r\n\r\n/* 自定义滚动条 */\r\n.demo-slot-edge-menu__log-content::-webkit-scrollbar {\r\n  width: 6px;\r\n}\r\n\r\n.demo-slot-edge-menu__log-content::-webkit-scrollbar-track {\r\n  background: #f0f0f0;\r\n  border-radius: 3px;\r\n}\r\n\r\n.demo-slot-edge-menu__log-content::-webkit-scrollbar-thumb {\r\n  background: #bfbfbf;\r\n  border-radius: 3px;\r\n}\r\n\r\n.demo-slot-edge-menu__log-content::-webkit-scrollbar-thumb:hover {\r\n  background: #999;\r\n}\r\n</style>\r\n"