<template>
  <FlowDesignerLayout
    @ready="handleReady"
  />
</template>

<script setup lang="ts">
import { message } from 'ant-design-vue'
import FlowDesignerLayout from '../../../../components/FlowDesigner/FlowDesignerLayout.vue'
import type { FlowDesigner } from '../../../../components/FlowDesigner/core'
import type { Node } from '@antv/x6'

/**
 * ready 回调：覆盖内置节点状态并初始化画布
 */
function handleReady(designer: FlowDesigner) {
  const graph = designer.getGraph()

  // ========== 覆盖 3 种内置节点状态 ==========

  // 1. 覆盖 default 状态：淡蓝色边框
  designer.registerNodeStateHandler('default', {
    apply(node) {
      node.setAttrs({
        body: {
          stroke: '#3b82f6',
          strokeWidth: 2,
          fill: '#dbeafe',
        },
        label: {
          fill: '#1e40af',
          fontWeight: 'normal',
        }
      })
    }
  })

  // 2. 覆盖 hover 状态：紫色加粗 + 阴影
  designer.registerNodeStateHandler('hover', {
    apply(node) {
      node.setAttrs({
        body: {
          stroke: '#8b5cf6',
          strokeWidth: 3,
          fill: '#ede9fe',
          filter: {
            name: 'dropShadow',
            args: { dx: 0, dy: 2, blur: 6, color: 'rgba(139, 92, 246, 0.4)' }
          }
        },
        label: {
          fill: '#5b21b6',
          fontWeight: 'bold',
        }
      })
    },
    cleanup(node) {
      node.setAttrs({
        body: {
          filter: null
        }
      })
    }
  })

  // 3. 覆盖 selected 状态：青色粗边框 + 光晕
  designer.registerNodeStateHandler('selected', {
    apply(node) {
      node.setAttrs({
        body: {
          stroke: '#06b6d4',
          strokeWidth: 4,
          fill: '#cffafe',
          filter: {
            name: 'dropShadow',
            args: { dx: 0, dy: 0, blur: 8, color: 'rgba(6, 182, 212, 0.6)' }
          }
        },
        label: {
          fill: '#164e63',
          fontWeight: 'bold',
          fontSize: 14,
        }
      })
    },
    cleanup(node) {
      node.setAttrs({
        body: {
          filter: null
        }
      })
    }
  })

  // ========== 新增自定义状态 ==========

  // 4. error 状态：红色粗边框 + 错误图标
  designer.registerNodeStateHandler('error', {
    apply(node) {
      node.setAttrs({
        body: {
          stroke: '#ef4444',
          strokeWidth: 4,
          fill: '#fee2e2',
          filter: {
            name: 'dropShadow',
            args: { dx: 0, dy: 2, blur: 8, color: 'rgba(239, 68, 68, 0.5)' }
          }
        },
        label: {
          fill: '#991b1b',
          fontWeight: 'bold',
        }
      })

      // 设置错误标记（可在插槽中使用）
      const currentData = node.getData() || {}
      node.setData({
        ...currentData,
        hasError: true,
        errorMessage: '节点验证失败'
      })
    },
    cleanup(node) {
      // 恢复默认样式
      node.setAttrs({
        body: {
          filter: null
        }
      })

      // 清除错误标记
      const currentData = node.getData() || {}
      node.setData({
        ...currentData,
        hasError: false,
        errorMessage: undefined
      })
    }
  })

  // ========== 创建演示节点 ==========

  const node1 = graph.addNode({
    id: 'node1',
    shape: 'rect',
    x: 80,
    y: 80,
    width: 140,
    height: 70,
    label: '默认状态',
    attrs: {
      label: {
        fontSize: 14,
      },
    },
  })
  // 设置初始状态为 default
  designer.setNodeState(node1, 'default')

  const node2 = graph.addNode({
    id: 'node2',
    shape: 'rect',
    x: 280,
    y: 80,
    width: 140,
    height: 70,
    label: '默认状态',
    attrs: {
      label: {
        fontSize: 14,
      },
    },
  })
  designer.setNodeState(node2, 'default')

  const node3 = graph.addNode({
    id: 'node3',
    shape: 'rect',
    x: 480,
    y: 80,
    width: 140,
    height: 70,
    label: '默认状态',
    attrs: {
      label: {
        fontSize: 14,
      },
    },
  })
  designer.setNodeState(node3, 'default')

  const node4 = graph.addNode({
    id: 'node4',
    shape: 'rect',
    x: 80,
    y: 200,
    width: 140,
    height: 70,
    label: '默认状态',
    attrs: {
      label: {
        fontSize: 14,
      },
    },
  })
  designer.setNodeState(node4, 'default')

  const node5 = graph.addNode({
    id: 'node5',
    shape: 'rect',
    x: 280,
    y: 200,
    width: 140,
    height: 70,
    label: '默认状态',
    attrs: {
      label: {
        fontSize: 14,
      },
    },
  })
  designer.setNodeState(node5, 'default')

  const node6 = graph.addNode({
    id: 'node6',
    shape: 'rect',
    x: 480,
    y: 200,
    width: 140,
    height: 70,
    label: '默认状态',
    attrs: {
      label: {
        fontSize: 14,
      },
    },
  })
  designer.setNodeState(node6, 'default')

  // ========== 添加连线 ==========

  graph.addEdge({
    id: 'edge1',
    shape: 'flow-edge',
    source: node1,
    target: node2,
    labels: ['流程1'],
  })

  graph.addEdge({
    id: 'edge2',
    shape: 'flow-edge',
    source: node2,
    target: node3,
    labels: ['流程2'],
  })

  graph.addEdge({
    id: 'edge3',
    shape: 'flow-edge',
    source: node1,
    target: node4,
    labels: ['流程3'],
  })

  graph.addEdge({
    id: 'edge4',
    shape: 'flow-edge',
    source: node4,
    target: node5,
    labels: ['流程4'],
  })

  graph.addEdge({
    id: 'edge5',
    shape: 'flow-edge',
    source: node5,
    target: node6,
    labels: ['流程5'],
  })

  // 居中显示
  graph.centerContent()

  // ========== 添加交互：单击切换内置状态，双击切换到 error 状态 ==========

  const builtinStates = ['default', 'hover', 'selected']
  const stateMap = new Map<string, number>() // 记录每个节点的当前状态索引

  // 双击事件：切换到 error 状态或恢复到 default 状态
  graph.on('node:dblclick', ({ node }) => {
    const currentState = node.getProp('_state') || 'default'

    if (currentState === 'error') {
      // 如果已经是 error，恢复到 default
      designer.setNodeState(node, 'default')
      stateMap.set(node.id, 0) // 重置索引
      message.success('节点已恢复到默认状态')
    } else {
      // 切换到 error 状态
      designer.setNodeState(node, 'error')
      message.error('节点已设置为错误状态（双击可恢复）')
    }
  })

  console.log('[Demo] 节点状态管理示例已加载（覆盖内置状态）')
  message.success('已覆盖 3 种内置节点状态，单击切换状态，双击切换 error 状态')
}
</script>
