export default "<template>\r\n  <div class=\"demo-permission-layout\">\r\n    <!-- 左侧权限配置面板 -->\r\n    <div class=\"permission-panel\">\r\n      <div class=\"permission-panel__header\">\r\n        <h3 class=\"permission-panel__title\">权限配置</h3>\r\n        <span class=\"permission-panel__mode\">Design 模式</span>\r\n        <span class=\"permission-panel__mode\" style=\"color: red\">此处即使配置了design权限也会完全失效，因为使用了getPermissions 函数完全接管权限计算</span>\r\n      </div>\r\n\r\n      <div class=\"permission-panel__content\">\r\n        <!-- UI 显示权限 -->\r\n        <div class=\"permission-group\">\r\n          <h4 class=\"permission-group__title\">🎨 界面显示</h4>\r\n          <div class=\"permission-list\">\r\n            <label class=\"permission-item\">\r\n              <a-checkbox v-model:checked=\"permissionConfig.design.showToolbar\" />\r\n              <span class=\"permission-item__label\">显示工具栏</span>\r\n            </label>\r\n            <label class=\"permission-item\">\r\n              <a-checkbox v-model:checked=\"permissionConfig.design.showNodePalette\" />\r\n              <span class=\"permission-item__label\">显示节点面板</span>\r\n            </label>\r\n            <label class=\"permission-item\">\r\n              <a-checkbox v-model:checked=\"permissionConfig.design.showPropertiesPanel\" />\r\n              <span class=\"permission-item__label\">显示属性面板</span>\r\n            </label>\r\n            <label class=\"permission-item\">\r\n              <a-checkbox v-model:checked=\"permissionConfig.design.showContextMenu\" />\r\n              <span class=\"permission-item__label\">显示右键菜单</span>\r\n            </label>\r\n            <label class=\"permission-item\">\r\n              <a-checkbox v-model:checked=\"permissionConfig.design.showMinimap\" />\r\n              <span class=\"permission-item__label\">显示小地图</span>\r\n            </label>\r\n          </div>\r\n        </div>\r\n\r\n        <!-- 编辑操作权限 -->\r\n        <div class=\"permission-group\">\r\n          <h4 class=\"permission-group__title\">✏️ 编辑操作</h4>\r\n          <div class=\"permission-list\">\r\n            <label class=\"permission-item\">\r\n              <a-checkbox v-model:checked=\"permissionConfig.design.canAddNode\" />\r\n              <span class=\"permission-item__label\">添加节点</span>\r\n            </label>\r\n            <label class=\"permission-item\">\r\n              <a-checkbox v-model:checked=\"permissionConfig.design.canDrag\" />\r\n              <span class=\"permission-item__label\">拖动节点</span>\r\n            </label>\r\n            <label class=\"permission-item\">\r\n              <a-checkbox v-model:checked=\"permissionConfig.design.canConnect\" />\r\n              <span class=\"permission-item__label\">创建连线</span>\r\n            </label>\r\n            <label class=\"permission-item\">\r\n              <a-checkbox v-model:checked=\"permissionConfig.design.canDelete\" />\r\n              <span class=\"permission-item__label\">删除元素</span>\r\n            </label>\r\n            <label class=\"permission-item\">\r\n              <a-checkbox v-model:checked=\"permissionConfig.design.canCopy\" />\r\n              <span class=\"permission-item__label\">复制</span>\r\n            </label>\r\n            <label class=\"permission-item\">\r\n              <a-checkbox v-model:checked=\"permissionConfig.design.canPaste\" />\r\n              <span class=\"permission-item__label\">粘贴</span>\r\n            </label>\r\n            <label class=\"permission-item\">\r\n              <a-checkbox v-model:checked=\"permissionConfig.design.canGroup\" />\r\n              <span class=\"permission-item__label\">节点成组</span>\r\n            </label>\r\n            <label class=\"permission-item\">\r\n              <a-checkbox v-model:checked=\"permissionConfig.design.canToFront\" />\r\n              <span class=\"permission-item__label\">层级前置</span>\r\n            </label>\r\n            <label class=\"permission-item\">\r\n              <a-checkbox v-model:checked=\"permissionConfig.design.canToBack\" />\r\n              <span class=\"permission-item__label\">层级后置</span>\r\n            </label>\r\n          </div>\r\n        </div>\r\n\r\n        <!-- 对齐操作权限 -->\r\n        <div class=\"permission-group\">\r\n          <h4 class=\"permission-group__title\">📐 对齐操作</h4>\r\n          <div class=\"permission-list\">\r\n            <label class=\"permission-item\">\r\n              <a-checkbox v-model:checked=\"permissionConfig.design.canAlign\" />\r\n              <span class=\"permission-item__label\">对齐总开关</span>\r\n            </label>\r\n            <label class=\"permission-item\">\r\n              <a-checkbox v-model:checked=\"permissionConfig.design.canAlignLeft\" />\r\n              <span class=\"permission-item__label\">左对齐</span>\r\n            </label>\r\n            <label class=\"permission-item\">\r\n              <a-checkbox v-model:checked=\"permissionConfig.design.canAlignRight\" />\r\n              <span class=\"permission-item__label\">右对齐</span>\r\n            </label>\r\n            <label class=\"permission-item\">\r\n              <a-checkbox v-model:checked=\"permissionConfig.design.canAlignTop\" />\r\n              <span class=\"permission-item__label\">上对齐</span>\r\n            </label>\r\n            <label class=\"permission-item\">\r\n              <a-checkbox v-model:checked=\"permissionConfig.design.canAlignBottom\" />\r\n              <span class=\"permission-item__label\">下对齐</span>\r\n            </label>\r\n          </div>\r\n        </div>\r\n\r\n        <!-- 选择操作权限 -->\r\n        <div class=\"permission-group\">\r\n          <h4 class=\"permission-group__title\">🎯 选择操作</h4>\r\n          <div class=\"permission-list\">\r\n            <label class=\"permission-item\">\r\n              <a-checkbox v-model:checked=\"permissionConfig.design.canSelectNode\" />\r\n              <span class=\"permission-item__label\">选中节点</span>\r\n            </label>\r\n            <label class=\"permission-item\">\r\n              <a-checkbox v-model:checked=\"permissionConfig.design.canSelectEdge\" />\r\n              <span class=\"permission-item__label\">选中连线</span>\r\n            </label>\r\n            <label class=\"permission-item\">\r\n              <a-checkbox v-model:checked=\"permissionConfig.design.canMultipleSelect\" />\r\n              <span class=\"permission-item__label\">多选/框选</span>\r\n            </label>\r\n            <label class=\"permission-item\">\r\n              <a-checkbox v-model:checked=\"permissionConfig.design.canSelectAll\" />\r\n              <span class=\"permission-item__label\">全选</span>\r\n            </label>\r\n          </div>\r\n        </div>\r\n\r\n        <!-- 导入导出权限 -->\r\n        <div class=\"permission-group\">\r\n          <h4 class=\"permission-group__title\">📦 导入导出</h4>\r\n          <div class=\"permission-list\">\r\n            <label class=\"permission-item\">\r\n              <a-checkbox v-model:checked=\"permissionConfig.design.canImport\" />\r\n              <span class=\"permission-item__label\">导入数据</span>\r\n            </label>\r\n            <label class=\"permission-item\">\r\n              <a-checkbox v-model:checked=\"permissionConfig.design.canExport\" />\r\n              <span class=\"permission-item__label\">导出数据</span>\r\n            </label>\r\n          </div>\r\n        </div>\r\n\r\n        <!-- 历史操作权限 -->\r\n        <div class=\"permission-group\">\r\n          <h4 class=\"permission-group__title\">⏱️ 历史操作</h4>\r\n          <div class=\"permission-list\">\r\n            <label class=\"permission-item\">\r\n              <a-checkbox v-model:checked=\"permissionConfig.design.canUndo\" />\r\n              <span class=\"permission-item__label\">撤销</span>\r\n            </label>\r\n            <label class=\"permission-item\">\r\n              <a-checkbox v-model:checked=\"permissionConfig.design.canRedo\" />\r\n              <span class=\"permission-item__label\">重做</span>\r\n            </label>\r\n          </div>\r\n        </div>\r\n\r\n        <!-- 视图操作权限 -->\r\n        <div class=\"permission-group\">\r\n          <h4 class=\"permission-group__title\">👁️ 视图操作</h4>\r\n          <div class=\"permission-list\">\r\n            <label class=\"permission-item\">\r\n              <a-checkbox v-model:checked=\"permissionConfig.design.canZoom\" />\r\n              <span class=\"permission-item__label\">缩放画布</span>\r\n            </label>\r\n            <label class=\"permission-item\">\r\n              <a-checkbox v-model:checked=\"permissionConfig.design.canPan\" />\r\n              <span class=\"permission-item__label\">拖拽画布</span>\r\n            </label>\r\n            <label class=\"permission-item\">\r\n              <a-checkbox v-model:checked=\"permissionConfig.design.canFitView\" />\r\n              <span class=\"permission-item__label\">适应窗口</span>\r\n            </label>\r\n            <label class=\"permission-item\">\r\n              <a-checkbox v-model:checked=\"permissionConfig.design.canResetView\" />\r\n              <span class=\"permission-item__label\">重置视图</span>\r\n            </label>\r\n          </div>\r\n        </div>\r\n\r\n        <!-- 交互反馈权限 -->\r\n        <div class=\"permission-group\">\r\n          <h4 class=\"permission-group__title\">💬 交互反馈</h4>\r\n          <div class=\"permission-list\">\r\n            <label class=\"permission-item\">\r\n              <a-checkbox v-model:checked=\"permissionConfig.design.canHoverNode\" />\r\n              <span class=\"permission-item__label\">节点 Hover 高亮</span>\r\n            </label>\r\n            <label class=\"permission-item\">\r\n              <a-checkbox v-model:checked=\"permissionConfig.design.canHoverEdge\" />\r\n              <span class=\"permission-item__label\">连线 Hover 高亮</span>\r\n            </label>\r\n            <label class=\"permission-item\">\r\n              <a-checkbox v-model:checked=\"permissionConfig.design.canNodeTooltip\" />\r\n              <span class=\"permission-item__label\">节点 Tooltip</span>\r\n            </label>\r\n            <label class=\"permission-item\">\r\n              <a-checkbox v-model:checked=\"permissionConfig.design.canEdgeTooltip\" />\r\n              <span class=\"permission-item__label\">连线 Tooltip</span>\r\n            </label>\r\n          </div>\r\n        </div>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- 右侧流程设计器 -->\r\n    <div class=\"designer-container\">\r\n      <FlowDesignerLayout\r\n        class=\"flow-designer-test\"\r\n        ref=\"layoutRef\"\r\n        :mode=\"currentMode\"\r\n        :permission-config=\"permissionConfig\"\r\n        :getPermissions=\"getPermissionsByRole\"\r\n        @ready=\"handleReady\"\r\n        @mode-change=\"handleModeChange\"\r\n      >\r\n        <!-- 顶部工具栏 -->\r\n        <template #toolbar=\"scope\">\r\n          <Toolbar\r\n            :zoom-percent=\"scope.zoomPercent\"\r\n            :has-selection=\"scope.hasSelection\"\r\n            :can-paste=\"scope.canPaste\"\r\n            :can-group=\"scope.canGroup\"\r\n            :can-ungroup=\"scope.canUngroup\"\r\n            :can-undo=\"scope.canUndo\"\r\n            :can-redo=\"scope.canRedo\"\r\n            :designer-mode=\"scope.currentMode\"\r\n            @undo=\"scope.onUndo\"\r\n            @redo=\"scope.onRedo\"\r\n            @zoom-in=\"scope.onZoomIn\"\r\n            @zoom-out=\"scope.onZoomOut\"\r\n            @zoom-to=\"scope.onZoomTo\"\r\n            @fit-view=\"scope.onFitView\"\r\n            @reset-view=\"scope.onResetView\"\r\n            @copy=\"scope.onCopy\"\r\n            @paste=\"scope.onPaste\"\r\n            @to-front=\"scope.onToFront\"\r\n            @to-back=\"scope.onToBack\"\r\n            @align-left=\"scope.onAlignLeft\"\r\n            @align-right=\"scope.onAlignRight\"\r\n            @align-top=\"scope.onAlignTop\"\r\n            @align-bottom=\"scope.onAlignBottom\"\r\n            @group=\"scope.onGroup\"\r\n            @ungroup=\"scope.onUngroup\"\r\n            @export=\"scope.onExport\"\r\n            @import=\"scope.onImport\"\r\n            @open-settings=\"scope.onOpenSettings\"\r\n            @mode-change=\"scope.onModeChange\"\r\n          />\r\n        </template>\r\n\r\n        <!-- 左侧节点面板 -->\r\n        <template #palette=\"scope\">\r\n          <NodePalette @start-drag=\"scope.onStartDrag\" />\r\n        </template>\r\n\r\n        <!-- 右侧属性面板 -->\r\n        <template #properties>\r\n          <PropertiesPanel />\r\n        </template>\r\n\r\n      </FlowDesignerLayout>\r\n\r\n      <!-- 模式选择器（固定在右上角） -->\r\n<!--      <ModeSelection-->\r\n<!--        :designer=\"designer\"-->\r\n<!--        @mode-change=\"handleModeChangeFromSelector\"-->\r\n<!--      />-->\r\n    </div>\r\n  </div>\r\n</template>\r\n\r\n<script setup lang=\"ts\">\r\nimport { ref, reactive, computed } from 'vue'\r\nimport { message } from 'ant-design-vue'\r\nimport { FlowDesigner } from '@/components/FlowDesigner/core'\r\nimport FlowDesignerLayout from '@/components/FlowDesigner/FlowDesignerLayout.vue'\r\nimport Toolbar from '@/views/Toolbar.vue'\r\nimport NodePalette from '@/views/NodePalette.vue'\r\nimport PropertiesPanel from '@/views/PropertiesPanel.vue'\r\nimport ModeSelection from '@/views/ModeSelection.vue'\r\n\r\nimport node30 from '/testfile/node-30.json'\r\n\r\n\r\nconst layoutRef = ref<InstanceType<typeof FlowDesignerLayout> | null>(null)\r\n// 测试用：搜索框插槽内的 input 引用（用于自动聚焦）\r\nconst searchInputRef = ref<HTMLInputElement | null>(null);\r\n\r\n// ─── Designer 实例（从 layoutRef 中提取，传递给 ModeSelection）──────────────\r\nconst designer = computed(() => layoutRef.value?.designer || null)\r\n\r\n// ─── 当前模式状态 ─────────────────────────────────────────────────────────────\r\nconst currentMode = ref('design')\r\n\r\n// ─── 权限配置（简化版：只配置需要覆盖默认值的权限）────────────────────────────\r\n/**\r\n * 用户权限配置\r\n *\r\n * 说明：\r\n * 1. 只需配置需要覆盖默认值的权限项\r\n * 2. 未配置的权限项会自动使用 defaultPermissionConfig.ts 中的默认值\r\n * 3. 扩展模式会自动继承 design 模式的配置\r\n * 4. Designer 类内部会自动合并默认配置\r\n *\r\n * 默认值规则：\r\n * - design 模式：所有权限默认开启（true）\r\n * - readonly 模式：禁用编辑权限，保留查看权限\r\n * - preview 模式：最小化界面，只保留基本查看\r\n */\r\nconst permissionConfig = reactive({\r\n  // ─── 设计模式 ───\r\n  design: {\r\n    // UI 显示\r\n    showToolbar: true,\r\n    showNodePalette: true,\r\n    showPropertiesPanel: true,\r\n    showContextMenu: true,\r\n    showMinimap: true,\r\n\r\n    // 编辑能力\r\n    canDrag: true,\r\n    canConnect: true,\r\n    canDelete: true,\r\n    canCopy: true,\r\n    canPaste: true,\r\n    canGroup: true,\r\n    canToFront: true,\r\n    canToBack: true,\r\n    canAddNode: true,\r\n\r\n    // 选择能力\r\n    canMultipleSelect: true,\r\n    canSelectAll: true,\r\n\r\n    // 对齐能力\r\n    canAlign: true,\r\n    canAlignLeft: true,\r\n    canAlignRight: true,\r\n    canAlignTop: true,\r\n    canAlignBottom: true,\r\n\r\n    // 操作能力\r\n    canImport: true,\r\n    canExport: true,\r\n    canUndo: true,\r\n    canRedo: true,\r\n\r\n    // 视图能力\r\n    canZoom: true,\r\n    canPan: true,\r\n    canFitView: true,\r\n    canResetView: true,\r\n\r\n    // 交互反馈能力\r\n    canHoverNode: true,\r\n    canHoverEdge: true,\r\n    canSelectNode: true,\r\n    canSelectEdge: true,\r\n    canNodeTooltip: true,\r\n    canEdgeTooltip: true,\r\n  }\r\n})\r\nconst userRole = ref('admin')\r\n//注意：通过getPermissions函数完全接管权限，permissionConfig参数配置的权限将会失效，所有权限默认都为false, 需要对应的权限必须显式地置为true\r\nconst getPermissionsByRole = (mode) => {\r\n  const base = {\r\n    canSelectNode: true,\r\n    canZoom: true,\r\n    canPan: true\r\n  }\r\n\r\n  if (userRole.value === 'admin') {\r\n    return { ...base, canAddNode: false, canDrag: true, canDelete: true }\r\n  }\r\n\r\n  if (userRole.value === 'editor') {\r\n    return { ...base, canAddNode: true, canDrag: true, canDelete: false }\r\n  }\r\n\r\n  return { ...base, canAddNode: false, canDrag: false }\r\n}\r\n\r\n\r\n// ─── ready 回调：拿到 designer 实例后加载本地数据 ─────────────────────────────\r\nfunction handleReady(designer: FlowDesigner) {\r\n  // ─── 加载测试数据 ──────────────────────────────────────────────────────\r\n  if (node30) {\r\n    try {\r\n      designer.load(node30)\r\n      //message.success('加载成功！')\r\n    } catch {\r\n      message.error('加载失败')\r\n    }\r\n  }\r\n}\r\n\r\n\r\n// ─── mode-change 事件 ─────────────────────────────────────────────────────────\r\nfunction handleModeChange(mode) {\r\n  message.success(`已切换至${{ design: '设计', readonly: '只读', preview: '预览' }[mode]}模式`)\r\n  currentMode.value = mode\r\n}\r\n\r\n// ─── 从 ModeSelection 组件触发的模式切换 ─────────────────────────────────────\r\nfunction handleModeChangeFromSelector(mode) {\r\n  // 🎯 调用 designer.setMode() 更新 designer 内部状态\r\n  if (designer.value) {\r\n    console.log('[FlowDesignerTest] 调用 designer.setMode()', mode)\r\n    designer.value.setMode(mode)\r\n  } else {\r\n    console.warn('[FlowDesignerTest] designer 实例不存在，无法切换模式')\r\n  }\r\n\r\n  // 更新本地状态（保持同步）\r\n  currentMode.value = mode\r\n\r\n  //message.success(`已切换至${{ design: '设计', readonly: '只读', preview: '预览' }[mode]}模式`)\r\n}\r\n\r\ndefineExpose({ layoutRef })\r\n</script>\r\n\r\n<style scoped>\r\n/* ==================== 布局容器 ==================== */\r\n.demo-permission-layout {\r\n  display: flex;\r\n  width: 100%;\r\n  height: 100%;\r\n  gap: 0;\r\n  background: #f5f5f5;\r\n}\r\n\r\n/* ==================== 左侧权限配置面板 ==================== */\r\n.permission-panel {\r\n  width: 180px;\r\n  background: #fff;\r\n  border-right: 1px solid #e8e8e8;\r\n  display: flex;\r\n  flex-direction: column;\r\n  overflow: hidden;\r\n}\r\n\r\n.permission-panel__header {\r\n  padding: 16px;\r\n  border-bottom: 1px solid #e8e8e8;\r\n  background: #fafafa;\r\n}\r\n\r\n.permission-panel__title {\r\n  font-size: 16px;\r\n  font-weight: 600;\r\n  color: #1a1a2e;\r\n  margin: 0 0 4px 0;\r\n}\r\n\r\n.permission-panel__mode {\r\n  display: inline-block;\r\n  padding: 2px 8px;\r\n  background: #e6f7ff;\r\n  color: #1677ff;\r\n  border-radius: 4px;\r\n  font-size: 12px;\r\n  font-weight: 500;\r\n}\r\n\r\n.permission-panel__content {\r\n  flex: 1;\r\n  overflow-y: auto;\r\n  padding: 16px;\r\n}\r\n\r\n/* ==================== 权限分组 ==================== */\r\n.permission-group {\r\n  margin-bottom: 20px;\r\n}\r\n\r\n.permission-group:last-child {\r\n  margin-bottom: 0;\r\n}\r\n\r\n.permission-group__title {\r\n  font-size: 14px;\r\n  font-weight: 600;\r\n  color: #333;\r\n  margin: 0 0 12px 0;\r\n  padding-bottom: 8px;\r\n  border-bottom: 2px solid #e8e8e8;\r\n}\r\n\r\n/* ==================== 权限列表 ==================== */\r\n.permission-list {\r\n  display: flex;\r\n  flex-direction: column;\r\n  gap: 8px;\r\n}\r\n\r\n.permission-item {\r\n  display: flex;\r\n  align-items: center;\r\n  gap: 8px;\r\n  padding: 6px 8px;\r\n  border-radius: 4px;\r\n  cursor: pointer;\r\n  transition: background 0.2s;\r\n  user-select: none;\r\n}\r\n\r\n.permission-item:hover {\r\n  background: #f5f5f5;\r\n}\r\n\r\n.permission-item__label {\r\n  font-size: 13px;\r\n  color: #555;\r\n  flex: 1;\r\n}\r\n\r\n/* ==================== 右侧设计器容器 ==================== */\r\n.designer-container {\r\n  flex: 1;\r\n  position: relative;\r\n  overflow: hidden;\r\n}\r\n\r\n.flow-designer-test {\r\n  width: 100%;\r\n  height: 100%;\r\n}\r\n\r\n/* ==================== 滚动条样式 ==================== */\r\n.permission-panel__content::-webkit-scrollbar {\r\n  width: 6px;\r\n}\r\n\r\n.permission-panel__content::-webkit-scrollbar-track {\r\n  background: #f1f1f1;\r\n}\r\n\r\n.permission-panel__content::-webkit-scrollbar-thumb {\r\n  background: #c1c1c1;\r\n  border-radius: 3px;\r\n}\r\n\r\n.permission-panel__content::-webkit-scrollbar-thumb:hover {\r\n  background: #a8a8a8;\r\n}\r\n\r\n/* ── 测试用自定义右键菜单样式 ────────────────────────────────────────────── */\r\n.custom-ctx-menu {\r\n  background: #fff;\r\n  border: 1px solid #e8e8e8;\r\n  border-radius: 6px;\r\n  box-shadow: 0 4px 16px rgba(0, 0, 0, 0.12);\r\n  padding: 4px 0;\r\n  min-width: 180px;\r\n  user-select: none;\r\n}\r\n\r\n.custom-ctx-menu__item {\r\n  padding: 7px 16px;\r\n  font-size: 13px;\r\n  color: #26