export default "<template>\r\n  <div class=\"demo-node-lifecycle\">\r\n    <!-- 事件日志面板 -->\r\n    <div class=\"demo-node-lifecycle__log\">\r\n      <div class=\"demo-node-lifecycle__log-header\">\r\n        <h4>事件日志</h4>\r\n        <button class=\"demo-node-lifecycle__clear-btn\" @click=\"clearLogs\" title=\"清除日志\">\r\n          清除\r\n        </button>\r\n      </div>\r\n      <div class=\"demo-node-lifecycle__log-content\">\r\n        <div v-for=\"(log, index) in logs\" :key=\"index\" class=\"demo-node-lifecycle__log-item\">\r\n          {{ log }}\r\n        </div>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- 画布容器 -->\r\n    <div class=\"demo-node-lifecycle__canvas\">\r\n      <div class=\"demo-node-lifecycle__controls\">\r\n        <button class=\"demo-node-lifecycle__btn\" @click=\"addNode\">\r\n          ➕ 添加节点\r\n        </button>\r\n        <button class=\"demo-node-lifecycle__btn\" @click=\"removeSelectedNode\">\r\n          ➖ 删除选中节点\r\n        </button>\r\n        <label class=\"demo-node-lifecycle__checkbox\">\r\n          <input type=\"checkbox\" v-model=\"allowAdd\" />\r\n          允许添加\r\n        </label>\r\n        <label class=\"demo-node-lifecycle__checkbox\">\r\n          <input type=\"checkbox\" v-model=\"allowRemove\" />\r\n          允许删除\r\n        </label>\r\n      </div>\r\n      <FlowDesignerLayout\r\n        @ready=\"handleReady\"\r\n        :before-node-add=\"handleBeforeNodeAdd\"\r\n        :after-node-add=\"handleAfterNodeAdd\"\r\n        :before-node-remove=\"handleBeforeNodeRemove\"\r\n        :after-node-remove=\"handleAfterNodeRemove\"\r\n      />\r\n    </div>\r\n  </div>\r\n</template>\r\n\r\n<script setup lang=\"ts\">\r\nimport { ref } from 'vue'\r\nimport FlowDesignerLayout from '@/components/FlowDesigner/FlowDesignerLayout.vue'\r\nimport type { FlowDesigner } from '@/components/FlowDesigner/core'\r\nimport type { Graph } from '@antv/x6'\r\nimport type { \r\n  BeforeNodeAddEvent,\r\n  AfterNodeAddEvent,\r\n  BeforeNodeRemoveEvent,\r\n  AfterNodeRemoveEvent\r\n} from '@/components/FlowDesigner/types/events'\r\n\r\nconst logs = ref<string[]>([])\r\nconst graphRef = ref<Graph>()\r\nconst Designer = ref<FlowDesigner>()\r\nconst allowAdd = ref(true)\r\nconst allowRemove = ref(true)\r\nlet nodeCounter = 0\r\n\r\nfunction addLog(message: string) {\r\n  const timestamp = new Date().toLocaleTimeString()\r\n  logs.value.push(`[${timestamp}] ${message}`)\r\n}\r\n\r\nfunction clearLogs() {\r\n  logs.value = []\r\n}\r\n\r\nfunction handleReady(designer, graph) {\r\n  console.log('designerdesignerdesignerdesignerdesigner::', graph,designer);\r\n  graphRef.value = graph\r\n  Designer.value = designer\r\n  addLog('✅ 画布初始化完成')\r\n  addLog('💡 点击\"添加节点\"或\"删除选中节点\"观察事件')\r\n}\r\n\r\n/**\r\n * :before-node-add 钩子函数\r\n * 返回 false 可阻止节点添加\r\n */\r\nfunction handleBeforeNodeAdd(event: BeforeNodeAddEvent): boolean {\r\n  addLog(`🔵 beforeNodeAdd 触发`)\r\n  addLog(`  节点ID: ${event.node.id}`)\r\n  addLog(`  来源: ${event.source}`)\r\n  addLog(`  允许添加: ${allowAdd.value}`)\r\n\r\n  if (!allowAdd.value) {\r\n    addLog(`❌ 节点添加被阻止`)\r\n    return false // 返回 false 阻止操作\r\n  }\r\n\r\n  addLog(`✅ 允许添加节点`)\r\n  return true // 返回 true 允许操作\r\n}\r\n\r\n/**\r\n * :after-node-add 钩子函数\r\n */\r\nfunction handleAfterNodeAdd(event: AfterNodeAddEvent): void {\r\n  addLog(`🟢 afterNodeAdd 触发`)\r\n  addLog(`  节点ID: ${event.nodeId}`)\r\n  addLog(`  节点已成功添加到画布`)\r\n}\r\n\r\n/**\r\n * :before-node-remove 钩子函数\r\n * 返回 false 可阻止节点删除\r\n */\r\nfunction handleBeforeNodeRemove(event: BeforeNodeRemoveEvent): boolean {\r\n  addLog(`🟡 beforeNodeRemove 触发`)\r\n  addLog(`  节点ID: ${event.nodeId}`)\r\n  addLog(`  来源: ${event.source}`)\r\n  addLog(`  允许删除: ${allowRemove.value}`)\r\n\r\n  if (!allowRemove.value) {\r\n    addLog(`❌ 节点删除被阻止`)\r\n    return false // 返回 false 阻止操作\r\n  }\r\n\r\n  addLog(`✅ 允许删除节点`)\r\n  return true // 返回 true 允许操作\r\n}\r\n\r\n/**\r\n * :after-node-remove 钩子函数\r\n */\r\nfunction handleAfterNodeRemove(event: AfterNodeRemoveEvent): void {\r\n  addLog(`🔴 afterNodeRemove 触发`)\r\n  addLog(`  节点ID: ${event.nodeId}`)\r\n  addLog(`  节点已从画布中移除`)\r\n}\r\n\r\nfunction addNode() {\r\n  if (!graphRef.value || !Designer.value) return\r\n\r\n  nodeCounter++\r\n  const colors = [\r\n    { fill: '#5F95FF', stroke: '#2563EB' },\r\n    { fill: '#10B981', stroke: '#059669' },\r\n    { fill: '#F59E0B', stroke: '#D97706' },\r\n    { fill: '#EF4444', stroke: '#DC2626' },\r\n  ]\r\n\r\n  const color = colors[nodeCounter % colors.length]\r\n  const x = 100 + (nodeCounter % 3) * 120\r\n  const y = 100 + Math.floor(nodeCounter / 3) * 100\r\n\r\n  addLog(`👆 用户点击\"添加节点\"`)\r\n  \r\n  // 使用 designer.addCell 方法\r\n  const node = graphRef.value.createNode({\r\n    shape: 'rect',\r\n    x,\r\n    y,\r\n    width: 100,\r\n    height: 60,\r\n    label: `节点${nodeCounter}`,\r\n    attrs: {\r\n      body: { fill: color.fill, stroke: color.stroke },\r\n      label: { fill: '#fff' },\r\n    },\r\n  })\r\n  \r\n  Designer.value.addCell(node)\r\n}\r\n\r\nfunction removeSelectedNode() {\r\n  if (!Designer.value) return\r\n\r\n  const selectedCells = graphRef.value.getSelectedCells()\r\n  const selectedNodes = selectedCells.filter(cell => cell.isNode())\r\n\r\n  if (selectedNodes.length === 0) {\r\n    addLog('⚠️ 未选中任何节点')\r\n    return\r\n  }\r\n\r\n  addLog(`👆 用户点击\"删除选中节点\"`)\r\n  selectedNodes.forEach(node => {\r\n    Designer.value.removeCell(node)\r\n  })\r\n}\r\n</script>\r\n\r\n<style scoped>\r\n.demo-node-lifecycle {\r\n  display: flex;\r\n  height: 100%; /* 修改：从固定高度改为 100%，支持全屏 */\r\n  min-height: 450px; /* 添加：最小高度，非全屏时保持合理尺寸 */\r\n  gap: 16px;\r\n}\r\n\r\n.demo-node-lifecycle__log {\r\n  width: 320px;\r\n  border: 1px solid #e8e8e8;\r\n  border-radius: 8px;\r\n  padding: 16px;\r\n  background: #fafafa;\r\n  overflow: hidden;\r\n  display: flex;\r\n  flex-direction: column;\r\n}\r\n\r\n.demo-node-lifecycle__log-header {\r\n  display: flex;\r\n  justify-content: space-between;\r\n  align-items: center;\r\n  margin-bottom: 12px;\r\n}\r\n\r\n.demo-node-lifecycle__log h4 {\r\n  margin: 0;\r\n  font-size: 14px;\r\n  color: #1a1a2e;\r\n  font-weight: 600;\r\n}\r\n\r\n.demo-node-lifecycle__clear-btn {\r\n  padding: 2px 8px;\r\n  font-size: 12px;\r\n  color: #666;\r\n  background: #fff;\r\n  border: 1px solid #d9d9d9;\r\n  border-radius: 4px;\r\n  cursor: pointer;\r\n  transition: all 0.2s;\r\n  user-select: none;\r\n}\r\n\r\n.demo-node-lifecycle__clear-btn:hover {\r\n  color: #1890ff;\r\n  border-color: #1890ff;\r\n}\r\n\r\n.demo-node-lifecycle__log-content {\r\n  flex: 1;\r\n  overflow-y: auto;\r\n  font-size: 12px;\r\n  line-height: 1.8;\r\n}\r\n\r\n.demo-node-lifecycle__log-item {\r\n  padding: 4px 0;\r\n  color: #555;\r\n  font-family: 'Monaco', 'Menlo', 'Consolas', monospace;\r\n  border-bottom: 1px solid #f0f0f0;\r\n}\r\n\r\n.demo-node-lifecycle__log-item:last-child {\r\n  border-bottom: none;\r\n}\r\n\r\n.demo-node-lifecycle__canvas {\r\n  flex: 1;\r\n  border: 1px solid #e8e8e8;\r\n  border-radius: 8px;\r\n  overflow: hidden;\r\n  background: #fff;\r\n  display: flex;\r\n  flex-direction: column;\r\n}\r\n\r\n.demo-node-lifecycle__controls {\r\n  display: flex;\r\n  gap: 12px;\r\n  align-items: center;\r\n  padding: 12px;\r\n  background: #fff;\r\n  border-bottom: 1px solid #e8e8e8;\r\n}\r\n\r\n.demo-node-lifecycle__btn {\r\n  padding: 6px 16px;\r\n  font-size: 13px;\r\n  color: #fff;\r\n  background: #1677ff;\r\n  border: none;\r\n  border-radius: 4px;\r\n  cursor: pointer;\r\n  transition: all 0.2s;\r\n}\r\n\r\n.demo-node-lifecycle__btn:hover {\r\n  background: #0958d9;\r\n}\r\n\r\n.demo-node-lifecycle__checkbox {\r\n  display: flex;\r\n  align-items: center;\r\n  gap: 6px;\r\n  font-size: 13px;\r\n  color: #666;\r\n  cursor: pointer;\r\n}\r\n\r\n.demo-node-lifecycle__checkbox input {\r\n  cursor: pointer;\r\n}\r\n</style>\r\n"