export default "<template>\r\n  <div class=\"demo-slot-canvas-menu\">\r\n    <!-- 事件日志面板 -->\r\n    <div class=\"demo-slot-canvas-menu__log\">\r\n      <div class=\"demo-slot-canvas-menu__log-header\">\r\n        <h4>事件日志</h4>\r\n        <button class=\"demo-slot-canvas-menu__clear-btn\" @click=\"clearLogs\" title=\"清除日志\">\r\n          清除\r\n        </button>\r\n      </div>\r\n      <div class=\"demo-slot-canvas-menu__log-content\">\r\n        <div v-for=\"(log, index) in logs\" :key=\"index\" class=\"demo-slot-canvas-menu__log-item\">\r\n          {{ log }}\r\n        </div>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- 画布容器 -->\r\n    <div class=\"demo-slot-canvas-menu__canvas\">\r\n      <FlowDesignerLayout\r\n        mode=\"design\"\r\n        :before-graph-init=\"handleBeforeGraphInit\"\r\n        @ready=\"handleReady\"\r\n      >\r\n        <!-- 自定义画布右键菜单插槽 -->\r\n        <template #canvas-menu=\"{ capabilities, onSelect }\">\r\n          <div class=\"canvas-context-menu\" @click.stop>\r\n            <div class=\"canvas-context-menu__header\">\r\n              <span class=\"canvas-context-menu__title\">画布菜单</span>\r\n            </div>\r\n\r\n            <!-- 全选 -->\r\n            <div\r\n              v-if=\"capabilities.canSelectAll && capabilities.canMultipleSelect\"\r\n              class=\"canvas-context-menu__item\"\r\n              @click=\"handleMenuClick('selectAll', onSelect)\"\r\n            >\r\n              <span class=\"canvas-context-menu__icon\">☑</span>\r\n              <span class=\"canvas-context-menu__text\">全选节点</span>\r\n              <span class=\"canvas-context-menu__shortcut\">Ctrl+A</span>\r\n            </div>\r\n\r\n            <!-- 分隔线 -->\r\n            <div\r\n              v-if=\"(capabilities.canSelectAll && capabilities.canMultipleSelect) && (capabilities.canUndo || capabilities.canRedo)\"\r\n              class=\"canvas-context-menu__divider\"\r\n            />\r\n\r\n            <!-- 撤销/重做 -->\r\n            <div\r\n              v-if=\"capabilities.canUndo\"\r\n              class=\"canvas-context-menu__item\"\r\n              @click=\"handleMenuClick('undo', onSelect)\"\r\n            >\r\n              <span class=\"canvas-context-menu__icon\">↶</span>\r\n              <span class=\"canvas-context-menu__text\">撤销</span>\r\n              <span class=\"canvas-context-menu__shortcut\">Ctrl+Z</span>\r\n            </div>\r\n            <div\r\n              v-if=\"capabilities.canRedo\"\r\n              class=\"canvas-context-menu__item\"\r\n              @click=\"handleMenuClick('redo', onSelect)\"\r\n            >\r\n              <span class=\"canvas-context-menu__icon\">↷</span>\r\n              <span class=\"canvas-context-menu__text\">重做</span>\r\n              <span class=\"canvas-context-menu__shortcut\">Ctrl+Y</span>\r\n            </div>\r\n\r\n            <!-- 分隔线 -->\r\n            <div\r\n              v-if=\"(capabilities.canUndo || capabilities.canRedo) && (capabilities.canZoom || capabilities.canFitView)\"\r\n              class=\"canvas-context-menu__divider\"\r\n            />\r\n\r\n            <!-- 视图操作 -->\r\n            <div\r\n              v-if=\"capabilities.canZoom\"\r\n              class=\"canvas-context-menu__item\"\r\n              @click=\"handleMenuClick('zoomIn', onSelect)\"\r\n            >\r\n              <span class=\"canvas-context-menu__icon\">🔍+</span>\r\n              <span class=\"canvas-context-menu__text\">放大</span>\r\n              <span class=\"canvas-context-menu__shortcut\">Ctrl+=</span>\r\n            </div>\r\n            <div\r\n              v-if=\"capabilities.canZoom\"\r\n              class=\"canvas-context-menu__item\"\r\n              @click=\"handleMenuClick('zoomOut', onSelect)\"\r\n            >\r\n              <span class=\"canvas-context-menu__icon\">🔍-</span>\r\n              <span class=\"canvas-context-menu__text\">缩小</span>\r\n              <span class=\"canvas-context-menu__shortcut\">Ctrl+-</span>\r\n            </div>\r\n            <div\r\n              v-if=\"capabilities.canFitView\"\r\n              class=\"canvas-context-menu__item\"\r\n              @click=\"handleMenuClick('fitView', onSelect)\"\r\n            >\r\n              <span class=\"canvas-context-menu__icon\">⛶</span>\r\n              <span class=\"canvas-context-menu__text\">适应窗口</span>\r\n              <span class=\"canvas-context-menu__shortcut\">Ctrl+0</span>\r\n            </div>\r\n            <div\r\n              v-if=\"capabilities.canResetView\"\r\n              class=\"canvas-context-menu__item\"\r\n              @click=\"handleMenuClick('resetView', onSelect)\"\r\n            >\r\n              <span class=\"canvas-context-menu__icon\">⌖</span>\r\n              <span class=\"canvas-context-menu__text\">重置视图</span>\r\n              <span class=\"canvas-context-menu__shortcut\">Ctrl+Shift+H</span>\r\n            </div>\r\n\r\n            <!-- 分隔线 -->\r\n            <div\r\n              v-if=\"(capabilities.canZoom || capabilities.canFitView) && (capabilities.canImport || capabilities.canExport)\"\r\n              class=\"canvas-context-menu__divider\"\r\n            />\r\n\r\n            <!-- 导入导出 -->\r\n            <div\r\n              v-if=\"capabilities.canPaste\"\r\n              class=\"canvas-context-menu__item\"\r\n              @click=\"handleMenuClick('paste', onSelect)\"\r\n            >\r\n              <span class=\"canvas-context-menu__icon\">📋</span>\r\n              <span class=\"canvas-context-menu__text\">粘贴</span>\r\n              <span class=\"canvas-context-menu__shortcut\">Ctrl+V</span>\r\n            </div>\r\n            <div\r\n              v-if=\"capabilities.canImport\"\r\n              class=\"canvas-context-menu__item\"\r\n              @click=\"handleMenuClick('import', onSelect)\"\r\n            >\r\n              <span class=\"canvas-context-menu__icon\">📥</span>\r\n              <span class=\"canvas-context-menu__text\">导入 JSON</span>\r\n            </div>\r\n            <div\r\n              v-if=\"capabilities.canExport\"\r\n              class=\"canvas-context-menu__item\"\r\n              @click=\"handleMenuClick('export', onSelect)\"\r\n            >\r\n              <span class=\"canvas-context-menu__icon\">📤</span>\r\n              <span class=\"canvas-context-menu__text\">导出 JSON</span>\r\n            </div>\r\n\r\n            <!-- 分隔线 -->\r\n            <div\r\n              v-if=\"(capabilities.canImport || capabilities.canExport) && capabilities.canDelete\"\r\n              class=\"canvas-context-menu__divider\"\r\n            />\r\n\r\n            <!-- 危险操作 -->\r\n            <div\r\n              v-if=\"capabilities.canDelete\"\r\n              class=\"canvas-context-menu__item canvas-context-menu__item--danger\"\r\n              @click=\"handleMenuClick('clear', onSelect)\"\r\n            >\r\n              <span class=\"canvas-context-menu__icon\">🗑</span>\r\n              <span class=\"canvas-context-menu__text\">清空画布</span>\r\n            </div>\r\n          </div>\r\n        </template>\r\n      </FlowDesignerLayout>\r\n    </div>\r\n  </div>\r\n</template>\r\n\r\n<script setup lang=\"ts\">\r\nimport { ref } from 'vue'\r\nimport FlowDesignerLayout from '@/components/FlowDesigner/FlowDesignerLayout.vue'\r\nimport type { FlowDesigner, FlowDesignerOptions } from '@/components/FlowDesigner/core'\r\nimport { Graph } from '@antv/x6'\r\n\r\nconst logs = ref<string[]>([])\r\nlet designerInstance: FlowDesigner | null = null\r\nlet graphInstance: Graph | null = null\r\n\r\nfunction addLog(message: string) {\r\n  const timestamp = new Date().toLocaleTimeString()\r\n  logs.value.push(`[${timestamp}] ${message}`)\r\n  // 自动滚动到底部\r\n  setTimeout(() => {\r\n    const logContent = document.querySelector('.demo-slot-canvas-menu__log-content')\r\n    if (logContent) {\r\n      logContent.scrollTop = logContent.scrollHeight\r\n    }\r\n  }, 0)\r\n}\r\n\r\nfunction clearLogs() {\r\n  logs.value = []\r\n}\r\n\r\n/**\r\n * Graph 初始化前注册自定义节点\r\n */\r\nfunction handleBeforeGraphInit(options: FlowDesignerOptions) {\r\n  addLog('🔧 初始化自定义节点样式...')\r\n\r\n  // 注册自定义节点：蓝色圆形\r\n  Graph.registerNode('custom-circle', {\r\n    inherit: 'circle',\r\n    width: 100,\r\n    height: 100,\r\n    attrs: {\r\n      body: {\r\n        fill: '#5F95FF',\r\n        stroke: '#2563EB',\r\n        strokeWidth: 2,\r\n      },\r\n      label: {\r\n        fill: '#fff',\r\n        fontSize: 14,\r\n        fontWeight: 500,\r\n      },\r\n    },\r\n  }, true)\r\n\r\n  Graph.registerNode('custom-rect', {\r\n    inherit: 'rect',\r\n    width: 140,\r\n    height: 70,\r\n    attrs: {\r\n      body: {\r\n        fill: '#47C769',\r\n        stroke: '#27AE60',\r\n        strokeWidth: 2,\r\n        rx: 8,\r\n        ry: 8,\r\n      },\r\n      label: {\r\n        fill: '#fff',\r\n        fontSize: 14,\r\n        fontWeight: 500,\r\n      },\r\n    },\r\n  }, true)\r\n\r\n  addLog('✅ 节点样式注册完成')\r\n}\r\n\r\n/**\r\n * 处理菜单项点击\r\n * @param action 操作类型\r\n * @param onSelect 插槽提供的 onSelect 方法\r\n */\r\nfunction handleMenuClick(action: string, onSelect: (action: string) => void) {\r\n  addLog(`🖱️ 菜单点击: ${getActionName(action)}`)\r\n  onSelect(action)\r\n}\r\n\r\n/**\r\n * 获取操作名称（用于日志显示）\r\n */\r\nfunction getActionName(action: string): string {\r\n  const actionMap: Record<string, string> = {\r\n    'selectAll': '全选节点',\r\n    'undo': '撤销',\r\n    'redo': '重做',\r\n    'zoomIn': '放大',\r\n    'zoomOut': '缩小',\r\n    'fitView': '适应窗口',\r\n    'resetView': '重置视图',\r\n    'paste': '粘贴',\r\n    'import': '导入 JSON',\r\n    'export': '导出 JSON',\r\n    'clear': '清空画布',\r\n  }\r\n  return actionMap[action] || action\r\n}\r\n\r\nfunction handleReady(designer: FlowDesigner, graph: Graph) {\r\n  designerInstance = designer\r\n  graphInstance = graph\r\n  addLog('✅ 画布初始化完成')\r\n\r\n  // 初始化测试数据\r\n  initTestData(graph)\r\n  addLog('💡 提示: 在画布空白处点击右键打开菜单')\r\n}\r\nfunction initTestData(graph) {\r\n\r\n  // 添加初始节点\r\n  const node1 = graph.addNode({\r\n    shape: 'custom-circle',\r\n    x: 100,\r\n    y: 100,\r\n    label: '开始',\r\n    data: {\r\n      description: '流程开始节点',\r\n      owner: '张三',\r\n      priority: 'high',\r\n    },\r\n  })\r\n\r\n  const node2 = graph.addNode({\r\n    shape: 'custom-rect',\r\n    x: 300,\r\n    y: 100,\r\n    label: '处理',\r\n    data: {\r\n      description: '执行业务处理',\r\n      owner: '李四',\r\n      priority: 'medium',\r\n    },\r\n  })\r\n\r\n  const node3 = graph.addNode({\r\n    shape: 'custom-circle',\r\n    x: 500,\r\n    y: 100,\r\n    label: '结束',\r\n    data: {\r\n      description: '流程结束',\r\n      owner: '王五',\r\n      priority: 'low',\r\n    },\r\n  })\r\n\r\n  // 添加连线\r\n  graph.addEdge({\r\n    source: node1,\r\n    target: node2,\r\n    shape: 'flow-edge',\r\n    labels: [{ attrs: { text: { text: '通过' } } }],\r\n    data: {\r\n      lineType: 'normal',\r\n      condition: 'status === \"approved\"',\r\n      description: '审批通过后的流转',\r\n      isDefault: false,\r\n    },\r\n  })\r\n\r\n  graph.addEdge({\r\n    source: node2,\r\n    target: node3,\r\n    shape: 'flow-edge',\r\n    labels: [{ attrs: { text: { text: '完成' } } }],\r\n    data: {\r\n      lineType: 'normal',\r\n      condition: '',\r\n      description: '处理完成后结束',\r\n      isDefault: true,\r\n    },\r\n  })\r\n}\r\n</script>\r\n\r\n<style scoped>\r\n.demo-slot-canvas-menu {\r\n  display: flex;\r\n  height: 100%;\r\n  min-height: 500px;\r\n  gap: 16px;\r\n}\r\n\r\n.demo-slot-canvas-menu__log {\r\n  width: 320px;\r\n  border: 1px solid #e8e8e8;\r\n  border-radius: 8px;\r\n  padding: 16px;\r\n  background: #fafafa;\r\n  overflow: hidden;\r\n  display: flex;\r\n  flex-direction: column;\r\n}\r\n\r\n.demo-slot-canvas-menu__log-header {\r\n  display: flex;\r\n  justify-content: space-between;\r\n  align-items: center;\r\n  margin-bottom: 12px;\r\n}\r\n\r\n.demo-slot-canvas-menu__log h4 {\r\n  margin: 0;\r\n  font-size: 14px;\r\n  color: #1a1a2e;\r\n  font-weight: 600;\r\n}\r\n\r\n.demo-slot-canvas-menu__clear-btn {\r\n  padding: 2px 8px;\r\n  font-size: 12px;\r\n  color: #666;\r\n  background: #fff;\r\n  border: 1px solid #d9d9d9;\r\n  border-radius: 4px;\r\n  cursor: pointer;\r\n  transition: all 0.2s;\r\n  user-select: none;\r\n}\r\n\r\n.demo-slot-canvas-menu__clear-btn:hover {\r\n  color: #1890ff;\r\n  border-color: #1890ff;\r\n}\r\n\r\n.demo-slot-canvas-menu__log-content {\r\n  flex: 1;\r\n  overflow-y: auto;\r\n  font-size: 12px;\r\n  line-height: 1.8;\r\n}\r\n\r\n.demo-slot-canvas-menu__log-item {\r\n  padding: 4px 0;\r\n  color: #555;\r\n  font-family: 'Monaco', 'Menlo', 'Consolas', monospace;\r\n  border-bottom: 1px solid #f0f0f0;\r\n}\r\n\r\n.demo-slot-canvas-menu__log-item:last-child {\r\n  border-bottom: none;\r\n}\r\n\r\n.demo-slot-canvas-menu__canvas {\r\n  flex: 1;\r\n  border: 1px solid #e8e8e8;\r\n  border-radius: 8px;\r\n  overflow: hidden;\r\n  background: #fff;\r\n  position: relative;\r\n}\r\n\r\n/* ==================== 画布右键菜单样式 ==================== */\r\n.canvas-context-menu {\r\n  background: #ffffff;\r\n  border-radius: 8px;\r\n  box-shadow: 0 4px 16px rgba(0, 0, 0, 0.15);\r\n  min-width: 220px;\r\n  overflow: hidden;\r\n  user-select: none;\r\n}\r\n\r\n.canvas-context-menu__header {\r\n  padding: 10px 16px;\r\n  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);\r\n  border-bottom: 1px solid #f0f0f0;\r\n}\r\n\r\n.canvas-context-menu__title {\r\n  font-size: 13px;\r\n  font-weight: 600;\r\n  color: #ffffff;\r\n  display: flex;\r\n  align-items: center;\r\n  gap: 6px;\r\n}\r\n\r\n.canvas-context-menu__item {\r\n  display: flex;\r\n  align-items: center;\r\n  gap: 10px;\r\n  padding: 10px 16px;\r\n  cursor: pointer;\r\n  transition: all 0.2s;\r\n  position: relative;\r\n}\r\n\r\n.canvas-context-menu__item:hover {\r\n  background: #f5f7fa;\r\n}\r\n\r\n.canvas-context-menu__item:active {\r\n  background: #e8ecf1;\r\n}\r\n\r\n.canvas-context-menu__item--danger {\r\n  color: #ff4d4f;\r\n}\r\n\r\n.canvas-context-menu__item--danger:hover {\r\n  background: #fff1f0;\r\n}\r\n\r\n.canvas-context-menu__icon {\r\n  font-size: 16px;\r\n  width: 20px;\r\n  display: flex;\r\n  align-items: center;\r\n  justify-content: center;\r\n  flex-shrink: 0;\r\n}\r\n\r\n.canvas-context-menu__text {\r\n  flex: 1;\r\n  font-size: 13px;\r\n  color: inherit;\r\n}\r\n\r\n.canvas-context-menu__shortcut {\r\n  font-size: 11px;\r\n  color: #8c8c8c;\r\n  background: #f5f5f5;\r\n  padding: 2px 6px;\r\n  border-radius: 3px;\r\n  font-family: 'Monaco', 'Menlo', 'Consolas', monospace;\r\n  flex-shrink: 0;\r\n}\r\n\r\n.canvas-context-menu__divider {\r\n  height: 1px;\r\n  background: #f0f0f0;\r\n  margin: 4px 0;\r\n}\r\n\r\n/* 自定义滚动条 */\r\n.demo-slot-canvas-menu__log-content::-webkit-scrollbar {\r\n  width: 6px;\r\n}\r\n\r\n.demo-slot-canvas-menu__log-content::-webkit-scrollbar-track {\r\n  background: #f0f0f0;\r\n  border-radius: 3px;\r\n}\r\n\r\n.demo-slot-canvas-menu__log-content::-webkit-scrollbar-thumb {\r\n  background: #bfbfbf;\r\n  border-radius: 3px;\r\n}\r\n\r\n.demo-slot-canvas-menu__log-content::-webkit-scrollbar-thumb:hover {\r\n  background: #999;\r\n}\r\n</style>\r\n"