<script setup lang="ts">
import { ref, reactive, computed } from 'vue'
import { message } from 'ant-design-vue'
import { FlowDesigner } from '@/components/FlowDesigner/core'
import FlowDesignerLayout from '@/components/FlowDesigner/FlowDesignerLayout.vue'
import Toolbar from '@/views/Toolbar.vue'
import NodePalette from '@/views/NodePalette.vue'
import PropertiesPanel from '@/views/PropertiesPanel.vue'
import ModeSelection from '@/views/ModeSelection.vue'

import node30 from '/testfile/node-30.json'


const layoutRef = ref<InstanceType<typeof FlowDesignerLayout> | null>(null)
// 测试用：搜索框插槽内的 input 引用（用于自动聚焦）
const searchInputRef = ref<HTMLInputElement | null>(null);

// ─── Designer 实例（从 layoutRef 中提取，传递给 ModeSelection）──────────────
const designer = computed(() => layoutRef.value?.designer || null)

// ─── 当前模式状态 ─────────────────────────────────────────────────────────────
const currentMode = ref('design')

// ─── 权限配置（简化版：只配置需要覆盖默认值的权限）────────────────────────────
/**
 * 用户权限配置
 *
 * 说明：
 * 1. 只需配置需要覆盖默认值的权限项
 * 2. 未配置的权限项会自动使用 defaultPermissionConfig.ts 中的默认值
 * 3. 扩展模式会自动继承 design 模式的配置
 * 4. Designer 类内部会自动合并默认配置
 *
 * 默认值规则：
 * - design 模式：所有权限默认开启（true）
 * - readonly 模式：禁用编辑权限，保留查看权限
 * - preview 模式：最小化界面，只保留基本查看
 */
const permissionConfig = reactive({
  // ─── 设计模式 ───
  design: {
    // UI 显示
    showToolbar: true,
    showNodePalette: true,
    showPropertiesPanel: true,
    showContextMenu: true,
    showMinimap: true,

    // 编辑能力
    canDrag: true,
    canConnect: true,
    canDelete: true,
    canCopy: true,
    canPaste: true,
    canGroup: true,
    canToFront: true,
    canToBack: true,
    canAddNode: true,

    // 选择能力
    canMultipleSelect: true,
    canSelectAll: true,

    // 对齐能力
    canAlign: true,
    canAlignLeft: true,
    canAlignRight: true,
    canAlignTop: true,
    canAlignBottom: true,

    // 操作能力
    canImport: true,
    canExport: true,
    canUndo: true,
    canRedo: true,

    // 视图能力
    canZoom: true,
    canPan: true,
    canFitView: true,
    canResetView: true,

    // 交互反馈能力
    canHoverNode: true,
    canHoverEdge: true,
    canSelectNode: true,
    canSelectEdge: true,
    canNodeTooltip: true,
    canEdgeTooltip: true,
  }
})
const userRole = ref('admin')
//注意：通过getPermissions函数完全接管权限，permissionConfig参数配置的权限将会失效，所有权限默认都为false, 需要对应的权限必须显式地置为true
const getPermissionsByRole = (mode) => {
  const base = {
    canSelectNode: true,
    canZoom: true,
    canPan: true
  }

  if (userRole.value === 'admin') {
    return { ...base, canAddNode: false, canDrag: true, canDelete: true }
  }

  if (userRole.value === 'editor') {
    return { ...base, canAddNode: true, canDrag: true, canDelete: false }
  }

  return { ...base, canAddNode: false, canDrag: false }
}


// ─── ready 回调：拿到 designer 实例后加载本地数据 ─────────────────────────────
function handleReady(designer: FlowDesigner) {
  // ─── 加载测试数据 ──────────────────────────────────────────────────────
  if (node30) {
    try {
      designer.load(node30)
      //message.success('加载成功！')
    } catch {
      message.error('加载失败')
    }
  }
}


// ─── mode-change 事件 ─────────────────────────────────────────────────────────
function handleModeChange(mode) {
  message.success(`已切换至${{ design: '设计', readonly: '只读', preview: '预览' }[mode]}模式`)
  currentMode.value = mode
}

// ─── 从 ModeSelection 组件触发的模式切换 ─────────────────────────────────────
function handleModeChangeFromSelector(mode) {
  // 🎯 调用 designer.setMode() 更新 designer 内部状态
  if (designer.value) {
    console.log('[FlowDesignerTest] 调用 designer.setMode()', mode)
    designer.value.setMode(mode)
  } else {
    console.warn('[FlowDesignerTest] designer 实例不存在，无法切换模式')
  }

  // 更新本地状态（保持同步）
  currentMode.value = mode

  //message.success(`已切换至${{ design: '设计', readonly: '只读', preview: '预览' }[mode]}模式`)
}

defineExpose({ layoutRef })
</script>

