<template>
  <div class="code-previewer" ref="previewerRef" :class="{ 'code-previewer--fullscreen': isFullscreen }">

    <!-- 左侧预览区 -->
    <div class="code-previewer__right">
      <!-- 预览工具栏 -->
      <div class="code-previewer__preview-toolbar">
        <span class="code-previewer__preview-title">效果预览</span>
        <button
            class="code-previewer__btn"
            :title="isFullscreen ? '退出全屏' : '全屏预览'"
            @click="toggleFullscreen"
        >
          {{ isFullscreen ? '退出全屏' : '全屏' }}
        </button>
      </div>

      <!-- 动态组件渲染 -->
      <div class="code-previewer__preview-content">
        <component :is="finalComponent" v-if="finalComponent" />
        <div v-else class="code-previewer__preview-empty">
          暂无预览内容
        </div>
      </div>

      <!-- 展开按钮：仅在代码区隐藏时显示，位于预览区右侧边缘 -->
      <button
        v-if="!isCodeVisible"
        class="code-previewer__expand-btn"
        title="展开代码"
        @click="toggleCodeVisibility"
      >
        <svg
          width="16"
          height="16"
          viewBox="0 0 16 16"
          fill="currentColor"
        >
          <!-- 向左箭头 -->
          <path d="M10 2L4 8l6 6V2z"/>
        </svg>
      </button>
    </div>


    <!-- 拖拽分隔条 -->
    <div
      class="code-previewer__divider-wrapper"
      :style="{ width: isCodeVisible ? '4px' : '0' }"
    >
      <div
        class="code-previewer__divider"
        @mousedown="startResize"
        v-show="isCodeVisible"
      />
    </div>

    <!-- 右侧代码区 -->
    <div
      class="code-previewer__left"
      :style="{ width: isCodeVisible ? leftWidth : '0' }"
      v-show="isCodeVisible"
    >
      <!-- 顶部操作栏 -->
      <div class="code-previewer__toolbar">
        <div class="code-previewer__tabs">
          <div
              v-for="(snippet, index) in finalCodeSnippets"
              :key="index"
              class="code-previewer__tab"
              :class="{ 'code-previewer__tab--active': activeTab === index }"
              @click="activeTab = index"
          >
            {{ snippet.label }}
          </div>
        </div>
        <div class="code-previewer__actions">
          <button
              class="code-previewer__btn"
              title="收起代码"
              @click="toggleCodeVisibility"
          >
            收起
          </button>
          <button
              class="code-previewer__btn"
              title="复制代码"
              @click="copyCode"
          >
            {{ copyStatus }}
          </button>
        </div>
      </div>

      <!-- 代码内容区 -->
      <div
          class="code-previewer__code-wrapper"
          :class="{ 'code-previewer__code-wrapper--collapsed': !isCodeExpanded }"
      >
        <pre class="code-previewer__code"><code class="code-previewer__code-content" ref="codeRef">{{ currentCode }}</code></pre>
      </div>
    </div>
  </div>
</template>

<script setup lang="ts">
import { ref, computed, watch, onMounted, onBeforeUnmount } from 'vue'
import type { Component } from 'vue'

// ─── Demo 映射表 ─────────────────────────────────────────────────────────────
// 预定义所有可用的 demo 组件和源码
import demo1 from '../chapters/examples/demo1.vue'
import demo1Raw from '../chapters/examples/demo1.vue?raw'
import demoReady from '../chapters/examples/demo-ready.vue'
import demoReadyRaw from '../chapters/examples/demo-ready.vue?raw'
import demoModeChange from '../chapters/examples/demo-mode-change.vue'
import demoModeChangeRaw from '../chapters/examples/demo-mode-change.vue?raw'
import demoSelectionChange from '../chapters/examples/demo-selection-change.vue'
import demoSelectionChangeRaw from '../chapters/examples/demo-selection-change.vue?raw'
import demoNodeLifecycle from '../chapters/examples/demo-node-lifecycle.vue'
import demoNodeLifecycleRaw from '../chapters/examples/demo-node-lifecycle.vue?raw'
import demoEdgeLifecycle from '../chapters/examples/demo-edge-lifecycle.vue'
import demoEdgeLifecycleRaw from '../chapters/examples/demo-edge-lifecycle.vue?raw'
import demoDataLoaded from '../chapters/examples/demo-data-loaded.vue'
import demoDataLoadedRaw from '../chapters/examples/demo-data-loaded.vue?raw'
import demoSlotToolbar from '../chapters/examples/demo-slot-toolbar.vue'
import demoSlotToolbarRaw from '../chapters/examples/demo-slot-toolbar.vue?raw'
import demoSlotToolbarComponentRaw from '../chapters/examples/components/Toolbar.vue?raw'
import demoSlotPattle from '../chapters/examples/demo-slot-palette.vue'
import demoSlotPattleRaw from '../chapters/examples/demo-slot-palette.vue?raw'

import demoSlotProperties from '../chapters/examples/demo-slot-properties.vue'
import demoSlotPropertiesRaw from '../chapters/examples/demo-slot-properties.vue?raw'

import demoSlotSearchbox from '../chapters/examples/demo-slot-searchbox.vue'
import demoSlotSearchboxRaw from '../chapters/examples/demo-slot-searchbox.vue?raw'

import demoSlotCanvasMenu from '../chapters/examples/demo-slot-canvasMenu.vue'
import demoSlotCanvasMenuRaw from '../chapters/examples/demo-slot-canvasMenu.vue?raw'

import demoSlotNodeMenu from '../chapters/examples/demo-slot-nodeMenu.vue'
import demoSlotNodeMenuRaw from '../chapters/examples/demo-slot-nodeMenu.vue?raw'

import demoSlotEdgeMenu from '../chapters/examples/demo-slot-edgeMenu.vue'
import demoSlotEdgeMenuRaw from '../chapters/examples/demo-slot-edgeMenu.vue?raw'

import demoSlotNodeTooltip from '../chapters/examples/demo-slot-nodeTooltip.vue'
import demoSlotNodeTooltipRaw from '../chapters/examples/demo-slot-nodeTooltip.vue?raw'

import demoSlotEdgeTooltip from '../chapters/examples/demo-slot-edgeTooltip.vue'
import demoSlotEdgeTooltipRaw from '../chapters/examples/demo-slot-edgeTooltip.vue?raw'

import demoSlotEdgeLabel from '../chapters/examples/demo-slot-edgeLabel.vue'
import demoSlotEdgeLabelRaw from '../chapters/examples/demo-slot-edgeLabel.vue?raw'

import demoSlotNode from '../chapters/examples/demo-slot-node.vue'
import demoSlotNodeRaw from '../chapters/examples/demo-slot-node.vue?raw'

import demoPermissionDesign from '../chapters/examples/demo-permission-01.vue'
import demoPermissionDesignRaw from '../chapters/examples/demo-permission-01.vue?raw'

import demoPermissionReadonly from '../chapters/examples/demo-permission-readonly.vue'
import demoPermissionReadonlyRaw from '../chapters/examples/demo-permission-readonly.vue?raw'

import demoPermissionPreview from '../chapters/examples/demo-permission-preview.vue'
import demoPermissionPreviewRaw from '../chapters/examples/demo-permission-preview.vue?raw'

import demoPermissionGetPermission from '../chapters/examples/demo-permission-getPermission.vue'
import demoPermissionGetPermissionRaw from '../chapters/examples/demo-permission-getPermission.vue?raw'

import demoFlowDesignerTest from '@/views/FlowDesignerTest.vue'
import demoFlowDesignerTestRaw from '@/views/FlowDesignerTest.vue?raw'

import demoNodeSvg from '../chapters/examples/demo-node-svg.vue'
import demoNodeSvgRaw from '../chapters/examples/demo-node-svg.vue?raw'

import demoNodeHtml from '../chapters/examples/demo-node-html.vue'
import demoNodeHtmlRaw from '../chapters/examples/demo-node-html.vue?raw'

import demoNodeVue from '../chapters/examples/demo-node-vue.vue'
import demoNodeVueRaw from '../chapters/examples/demo-node-vue.vue?raw'
import StartNodeRaw from '../chapters/examples/components/StartNode.vue?raw'
import ApproverNodeRaw from '../chapters/examples/components/ApproverNode.vue?raw'

import demoNodeDesigner from '../chapters/examples/demo-node-designer.vue'
import demoNodeDesignerRaw from '../chapters/examples/demo-node-designer.vue?raw'

import demoEdgeSvg from '../chapters/examples/demo-edge-svg.vue'
import demoEdgeSvgRaw from '../chapters/examples/demo-edge-svg.vue?raw'

import demoShortcut from '../chapters/examples/demo-shortcut-keymap.vue'
import demoShortcutRaw from '../chapters/examples/demo-shortcut-keymap.vue?raw'

import demoNodeState from '../chapters/examples/demo-node-state.vue'
import demoNodeStateRaw from '../chapters/examples/demo-node-state.vue?raw'

import demoEdgeState from '../chapters/examples/demo-edge-state.vue'
import demoEdgeStateRaw from '../chapters/examples/demo-edge-state.vue?raw'

import demoPerformance from '../chapters/examples/demo-performance.vue'
import demoPerformanceRaw from '../chapters/examples/demo-performance.vue?raw'

// CodeSnippet 接口定义（提前声明以供 DEMO_MAP 使用）
interface CodeSnippet {
  label: string       // Tab 标签名
  language: string    // 代码语言（vue, ts, js 等）
  code: string        // 代码内容
}

const DEMO_MAP: Record<string, { component: Component; code: string | CodeSnippet[] }> = {
  'demoSimple': {
    component: demo1,
    code: demo1Raw,
  },
  'demo-ready': {
    component: demoReady,
    code: demoReadyRaw,
  },
  'demo-mode-change': {
    component: demoModeChange,
    code: demoModeChangeRaw,
  },
  'demo-selection-change': {
    component: demoSelectionChange,
    code: demoSelectionChangeRaw,
  },
  'demo-node-lifecycle': {
    component: demoNodeLifecycle,
    code: demoNodeLifecycleRaw,
  },
  'demo-edge-lifecycle': {
    component: demoEdgeLifecycle,
    code: demoEdgeLifecycleRaw,
  },
  'demo-data-loaded': {
    component: demoDataLoaded,
    code: demoDataLoadedRaw,
  },
  'demo-slot-toolbar': {
    component: demoSlotToolbar,
    code: [
      {
        label: 'index.vue',
        language: 'vue',
        code: demoSlotToolbarRaw,
      },
      {
        label: 'Toolbar.vue',
        language: 'vue',
        code: demoSlotToolbarComponentRaw,
      },
    ],
  },
  'demo-slot-pattle': {
    component: demoSlotPattle,
    code: [
      {
        label: 'index.vue',
        language: 'vue',
        code: demoSlotPattleRaw,
      },
    ],
  },
  'demo-slot-properties': {
    component: demoSlotProperties,
    code: demoSlotPropertiesRaw,
  },
  'demo-slot-searchbox': {
    component: demoSlotSearchbox,
    code: demoSlotSearchboxRaw,
  },
  'demo-slot-canvasMenu': {
    component: demoSlotCanvasMenu,
    code: demoSlotCanvasMenuRaw,
  },
  'demo-slot-nodeMenu': {
    component: demoSlotNodeMenu,
    code: demoSlotNodeMenuRaw,
  },
  'demo-slot-edgeMenu': {
    component: demoSlotEdgeMenu,
    code: demoSlotEdgeMenuRaw,
  },
  'demo-slot-nodeTooltip': {
    component: demoSlotNodeTooltip,
    code: demoSlotNodeTooltipRaw,
  },
  'demo-slot-edgeTooltip': {
    component: demoSlotEdgeTooltip,
    code: demoSlotEdgeTooltipRaw,
  },
  'demo-slot-edgeLabel': {
    component: demoSlotEdgeLabel,
    code: demoSlotEdgeLabelRaw,
  },
  'demo-slot-node': {
    component: demoSlotNode,
    code: demoSlotNodeRaw,
  },
  'demo-permission-design': {
    component: demoPermissionDesign,
    code: demoPermissionDesignRaw,
  },
  'demo-permission-readonly': {
    component: demoPermissionReadonly,
    code: demoPermissionReadonlyRaw,
  },
  'demo-permission-preview': {
    component: demoPermissionPreview,
    code: demoPermissionPreviewRaw,
  },
  'demo-permission-getPermission': {
    component: demoPermissionGetPermission,
    code: demoPermissionGetPermissionRaw,
  },
  'demo-permission-all': {
    component: demoFlowDesignerTest,
    code: demoFlowDesignerTestRaw,
  },
  'demo-node-svg': {
    component: demoNodeSvg,
    code: demoNodeSvgRaw,
  },
  'demo-node-html': {
    component: demoNodeHtml,
    code: demoNodeHtmlRaw,
  },
  'demo-node-vue': {
    component: demoNodeVue,
    //code: demoNodeVueRaw,
    code: [
      {
        label: 'index.vue',
        language: 'vue',
        code: demoNodeVueRaw,
      },
      {
        label: 'StartNode.vue',
        language: 'vue',
        code: StartNodeRaw,
      },
      {
        label: 'ApproverNode.vue',
        language: 'vue',
        code: ApproverNodeRaw,
      },
    ],
  },
  'demo-node-designer': {
    component: demoNodeDesigner,
    code: demoNodeDesignerRaw,
  },
  'demo-edge-svg': {
    component: demoEdgeSvg,
    code: demoEdgeSvgRaw,
  },
  'demo-shortcut-keymap': {
    component: demoShortcut,
    code: demoShortcutRaw,
  },
  'demo-node-state': {
    component: demoNodeState,
    code: demoNodeStateRaw,
  },
  'demo-edge-state': {
    component: demoEdgeState,
    code: demoEdgeStateRaw,
  },
  'demo-performance': {
    component: demoPerformance,
    code: demoPerformanceRaw,
  },
}

// ─── Props ──────────────────────────────────────────────────────────────────

interface Props {
  // 新 API：传入 demo 名称（推荐使用）
  demoName?: string

  // 代码内容：支持字符串或代码片段数组
  code?: string | CodeSnippet[]

  // 旧 API：手动传入代码和组件（向后兼容）
  codeSnippets?: CodeSnippet[]
  demoComponent?: Component

  // 其他配置
  defaultActiveTab?: number
  defaultLeftWidth?: string
}

const props = withDefaults(defineProps<Props>(), {
  defaultActiveTab: 0,
  defaultLeftWidth: '20%',  // ✅ 修改：代码区默认占 20%
})

// ─── State ──────────────────────────────────────────────────────────────────

const activeTab = ref(props.defaultActiveTab)
const isCodeExpanded = ref(true)
const isCodeVisible = ref(true)  // ✅ 修改：代码区默认展开
const isFullscreen = ref(false)
const copyStatus = ref('复制')
const codeRef = ref<HTMLElement>()
const previewerRef = ref<HTMLElement>()  // ✅ 添加容器 ref

// 左侧宽度（可拖拽调整）
const leftWidth = ref(props.defaultLeftWidth)
const isResizing = ref(false)

// ─── Computed ───────────────────────────────────────────────────────────────

/**
 * 最终使用的代码片段
 * 优先级：
 * 1. demoName 从映射表加载
 * 2. code 属性（字符串或数组）
 * 3. codeSnippets 属性（向后兼容）
 */
const finalCodeSnippets = computed<CodeSnippet[]>(() => {
  // 优先使用新 API（demoName）
  if (props.demoName && DEMO_MAP[props.demoName]) {
    const demoCode = DEMO_MAP[props.demoName].code

    // 如果 DEMO_MAP 中的 code 是数组，直接返回
    if (Array.isArray(demoCode)) {
      return demoCode
    }

    // 如果是字符串，包装成单个代码片段
    return [
      {
        label: 'Vue',
        language: 'vue',
        code: demoCode,
      },
    ]
  }

  // 其次使用 code 属性
  if (props.code) {
    // 如果 code 是数组，直接返回
    if (Array.isArray(props.code)) {
      return props.code
    }
    // 如果 code 是字符串，包装成单个代码片段
    return [
      {
        label: 'Code',
        language: 'vue',
        code: props.code,
      },
    ]
  }

  // 兜底使用旧 API（codeSnippets）
  return props.codeSnippets || []
})

/**
 * 最终使用的组件
 * 优先使用 demoName 从映射表加载，否则使用手动传入的 demoComponent
 */
const finalComponent = computed<Component | undefined>(() => {
  // 优先使用新 API（demoName）
  if (props.demoName && DEMO_MAP[props.demoName]) {
    return DEMO_MAP[props.demoName].component
  }

  // 兜底使用旧 API（demoComponent）
  return props.demoComponent
})

const currentCode = computed(() => {
  const snippet = finalCodeSnippets.value[activeTab.value]
  if (!snippet) return ''

  // 确保 snippet.code 是字符串
  const code = typeof snippet.code === 'string' ? snippet.code : String(snippet.code || '')

  return addLineNumbers(code)
})

// ─── Methods ────────────────────────────────────────────────────────────────

/**
 * 为代码添加行号
 */
function addLineNumbers(code: string): string {
  // 添加类型检查，防止 code 不是字符串
  if (typeof code !== 'string') {
    console.error('addLineNumbers: code must be a string, received:', typeof code, code)
    return String(code || '')
  }

  const lines = code.split('\n')
  const maxLineNum = lines.length
  const padding = String(maxLineNum).length

  return lines
    .map((line, index) => {
      const lineNum = String(index + 1).padStart(padding, ' ')
      return `${lineNum}  ${line}`
    })
    .join('\n')
}

/**
 * 复制代码到剪贴板
 */
async function copyCode() {
  const snippet = finalCodeSnippets.value[activeTab.value]
  if (!snippet) return

  try {
    await navigator.clipboard.writeText(snippet.code)
    copyStatus.value = '已复制'
    setTimeout(() => {
      copyStatus.value = '复制'
    }, 2000)
  } catch (err) {
    console.error('复制失败:', err)
    copyStatus.value = '复制失败'
    setTimeout(() => {
      copyStatus.value = '复制'
    }, 2000)
  }
}

/**
 * 切换代码展开/折叠
 */
function toggleCodeExpand() {
  isCodeExpanded.value = !isCodeExpanded.value
}

/**
 * 切换代码区显示/隐藏
 */
function toggleCodeVisibility() {
  isCodeVisible.value = !isCodeVisible.value
}

/**
 * 切换全屏预览
 */
function toggleFullscreen() {
  isFullscreen.value = !isFullscreen.value
}

/**
 * 开始拖拽调整宽度
 */
function startResize(e: MouseEvent) {
  isResizing.value = true
  e.preventDefault()
}

/**
 * 拖拽中调整宽度
 */
function handleResize(e: MouseEvent) {
  if (!isResizing.value) return

  // ✅ 方案 A：使用 ref 获取容器
  const container = previewerRef.value
  if (!container) return

  const containerRect = container.getBoundingClientRect()
  // ✅ 修复：代码区在右侧，计算从鼠标到右边缘的距离
  const newWidth = containerRect.right - e.clientX
  const percentage = (newWidth / containerRect.width) * 100

  // 限制宽度范围 20% - 80%
  if (percentage >= 20 && percentage <= 80) {
    leftWidth.value = `${percentage}%`
  }
}

/**
 * 停止拖拽
 */
function stopResize() {
  isResizing.value = false
}

// ─── Lifecycle ──────────────────────────────────────────────────────────────

onMounted(() => {
  document.addEventListener('mousemove', handleResize)
  document.addEventListener('mouseup', stopResize)
})

onBeforeUnmount(() => {
  document.removeEventListener('mousemove', handleResize)
  document.removeEventListener('mouseup', stopResize)
})
</script>

<style scoped>
/* ═══ 根容器 ═══ */
.code-previewer {
  display: flex;
  width: 100%;
  height: 100%;
  background: #fff;
  border: 1px solid #e8e8e8;
  border-radius: 4px;
  overflow: hidden; /* 修改为 hidden，避免 flex 布局计算问题 */
  position: relative;
  max-height: 360px;
}

.code-previewer--fullscreen {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  z-index: 9999;
  border-radius: 0;
  max-height: none; /* 全屏时移除高度限制 */
}

/* ═══ 左侧代码区 ═══ */
.code-previewer__left {
  display: flex;
  flex-direction: column;
  border-right: 1px solid #e8e8e8;
  background: #fafafa;
  overflow: hidden;
  transition: width 0.3s ease;
  flex-shrink: 0; /* 防止代码区被压缩 */
}

/* ═══ 工具栏 ═══ */
.code-previewer__toolbar {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 8px 12px;
  background: #fff;
  border-bottom: 1px solid #e8e8e8;
  flex-shrink: 0;
}

.code-previewer__tabs {
  display: flex;
  gap: 4px;
}

.code-previewer__tab {
  padding: 4px 12px;
  font-size: 13px;
  color: #666;
  background: #f5f5f5;
  border-radius: 4px;
  cursor: pointer;
  transition: all 0.2s;
  user-select: none;
}

.code-previewer__tab:hover {
  color: #1890ff;
  background: #e6f7ff;
}

.code-previewer__tab--active {
  color: #1890ff;
  background: #e6f7ff;
  font-weight: 500;
}

.code-previewer__actions {
  display: flex;
  gap: 8px;
}

.code-previewer__btn {
  padding: 4px 12px;
  font-size: 12px;
  color: #666;
  background: #fff;
  border: 1px solid #d9d9d9;
  border-radius: 4px;
  cursor: pointer;
  transition: all 0.2s;
  user-select: none;
}

.code-previewer__btn:hover {
  color: #1890ff;
  border-color: #1890ff;
}

/* ═══ 代码内容区 ═══ */
.code-previewer__code-wrapper {
  flex: 1;
  overflow: auto;
  background: #fafafa;
  transition: max-height 0.3s;
}

.code-previewer__code-wrapper--collapsed {
  max-height: 200px;
  overflow: hidden;
  position: relative;
}

.code-previewer__code-wrapper--collapsed::after {
  content: '';
  position: absolute;
  bottom: 0;
  left: 0;
  right: 0;
  height: 60px;
  background: linear-gradient(to bottom, transparent, #fafafa);
  pointer-events: none;
}

.code-previewer__code {
  margin: 0;
  padding: 16px;
  font-family: 'Consolas', 'Monaco', 'Courier New', monospace;
  font-size: 13px;
  line-height: 1.6;
  color: #333;
  background: #fafafa;
  overflow-x: auto;
}

.code-previewer__code-content {
  display: block;
  white-space: pre;
  word-wrap: normal;
  overflow-wrap: normal;
}

/* ═══ 拖拽分隔条 ═══ */
.code-previewer__divider-wrapper {
  position: relative;
  display: flex;
  align-items: stretch;
  flex-shrink: 0;
  width: 4px;
}

.code-previewer__divider {
  width: 100%;
  height: 100%;
  background: #e8e8e8;
  cursor: col-resize;
  transition: background 0.2s;
}

.code-previewer__divider:hover {
  background: #1890ff;
}

/* ═══ 右侧预览区 ═══ */
.code-previewer__right {
  position: relative;
  flex: 1;
  display: flex;
  flex-direction: column;
  overflow: hidden;
  min-width: 0; /* 确保 flex 子元素能够正确收缩 */
}

/* 展开按钮：位于预览区右侧边缘中间 */
.code-previewer__expand-btn {
  position: absolute;
  right: 0;
  top: 50%;
  transform: translateY(-50%);
  z-index: 10;
  width: 24px;
  height: 48px;
  background: #fff;
  border: 1px solid #d9d9d9;
  border-right: none;
  border-radius: 12px 0 0 12px;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  color: #666;
  transition: all 0.2s;
  padding: 0;
  outline: none;
  box-shadow: -2px 0 4px rgba(0, 0, 0, 0.1);
}

.code-previewer__expand-btn:hover {
  color: #1890ff;
  border-color: #1890ff;
  background: #f0f7ff;
}

.code-previewer__preview-toolbar {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 8px 12px;
