export default "<template>\r\n  <div class=\"demo-ready\">\r\n    <!-- 事件日志面板 -->\r\n    <div class=\"demo-ready__log\">\r\n      <div class=\"demo-ready__log-header\">\r\n        <h4>事件日志</h4>\r\n        <button class=\"demo-ready__clear-btn\" @click=\"clearLogs\" title=\"清除日志\">\r\n          清除\r\n        </button>\r\n      </div>\r\n      <div class=\"demo-ready__log-content\">\r\n        <div v-for=\"(log, index) in logs\" :key=\"index\" class=\"demo-ready__log-item\">\r\n          {{ log }}\r\n        </div>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- 画布容器 -->\r\n    <div class=\"demo-ready__canvas\">\r\n      <FlowDesignerLayout @ready=\"handleReady\" />\r\n    </div>\r\n  </div>\r\n</template>\r\n\r\n<script setup lang=\"ts\">\r\nimport { ref } from 'vue'\r\nimport FlowDesignerLayout from '@/components/FlowDesigner/FlowDesignerLayout.vue'\r\nimport type { FlowDesigner } from '@/components/FlowDesigner/core'\r\nimport type { Graph } from '@antv/x6'\r\n\r\nconst logs = ref<string[]>([])\r\n\r\nfunction addLog(message: string) {\r\n  const timestamp = new Date().toLocaleTimeString()\r\n  logs.value.push(`[${timestamp}] ${message}`)\r\n}\r\n\r\nfunction clearLogs() {\r\n  logs.value = []\r\n}\r\n\r\n/**\r\n * @ready 事件处理函数\r\n * 参数：{ designer, graph } - FlowDesigner 实例和 X6 Graph 实例\r\n */\r\nfunction handleReady(designer:FlowDesigner, graph: Graph) {\r\n  addLog('✅ ready 事件触发')\r\n  addLog(`📦 designer 实例ID: ${designer.id}`)\r\n  addLog(`📊 graph 节点数: ${graph.getNodes().length}`)\r\n  addLog(`🔗 graph 连线数: ${graph.getEdges().length}`)\r\n\r\n  // 演示：添加几个节点\r\n  const node1 = graph.addNode({\r\n    shape: 'rect',\r\n    x: 100,\r\n    y: 100,\r\n    width: 100,\r\n    height: 60,\r\n    label: '节点1',\r\n    attrs: {\r\n      body: {\r\n        fill: '#5F95FF',\r\n        stroke: '#2563EB',\r\n        strokeWidth: 2,\r\n      },\r\n      label: {\r\n        fill: '#ffffff',\r\n        fontSize: 14,\r\n        fontWeight: 'bold',\r\n      },\r\n    },\r\n  })\r\n\r\n  const node2 = graph.addNode({\r\n    shape: 'rect',\r\n    x: 300,\r\n    y: 100,\r\n    width: 100,\r\n    height: 60,\r\n    label: '节点2',\r\n    attrs: {\r\n      body: {\r\n        fill: '#10B981',\r\n        stroke: '#059669',\r\n        strokeWidth: 2,\r\n      },\r\n      label: {\r\n        fill: '#ffffff',\r\n        fontSize: 14,\r\n        fontWeight: 'bold',\r\n      },\r\n    },\r\n  })\r\n\r\n  graph.addEdge({\r\n    shape: 'flow-edge',\r\n    source: node1,\r\n    target: node2,\r\n    labels: ['连接'],\r\n  })\r\n\r\n  addLog('✨ 已添加 2 个节点和 1 条连线')\r\n\r\n  // 演示：调用 designer 方法\r\n  graph.centerContent()\r\n  addLog('🎯 已居中显示内容')\r\n\r\n  // 额外信息：演示 designer 的其他 API\r\n  addLog(`🔧 designer.getMode(): ${designer.getMode()}`)\r\n  addLog(`🔐 designer.can('canDrag'): ${designer.can('canDrag')}`)\r\n}\r\n</script>\r\n\r\n<style scoped>\r\n.demo-ready {\r\n  display: flex;\r\n  height: 100%; /* 修改：从固定高度改为 100%，支持全屏 */\r\n  min-height: 400px; /* 添加：最小高度，非全屏时保持合理尺寸 */\r\n  gap: 16px;\r\n}\r\n\r\n.demo-ready__log {\r\n  width: 300px;\r\n  border: 1px solid #e8e8e8;\r\n  border-radius: 8px;\r\n  padding: 16px;\r\n  background: #fafafa;\r\n  overflow: hidden;\r\n  display: flex;\r\n  flex-direction: column;\r\n}\r\n\r\n.demo-ready__log-header {\r\n  display: flex;\r\n  justify-content: space-between;\r\n  align-items: center;\r\n  margin-bottom: 12px;\r\n}\r\n\r\n.demo-ready__log h4 {\r\n  margin: 0;\r\n  font-size: 14px;\r\n  color: #1a1a2e;\r\n  font-weight: 600;\r\n}\r\n\r\n.demo-ready__clear-btn {\r\n  padding: 2px 8px;\r\n  font-size: 12px;\r\n  color: #666;\r\n  background: #fff;\r\n  border: 1px solid #d9d9d9;\r\n  border-radius: 4px;\r\n  cursor: pointer;\r\n  transition: all 0.2s;\r\n  user-select: none;\r\n}\r\n\r\n.demo-ready__clear-btn:hover {\r\n  color: #1890ff;\r\n  border-color: #1890ff;\r\n}\r\n\r\n.demo-ready__log-content {\r\n  flex: 1;\r\n  overflow-y: auto;\r\n  font-size: 12px;\r\n  line-height: 1.8;\r\n}\r\n\r\n.demo-ready__log-item {\r\n  padding: 4px 0;\r\n  color: #555;\r\n  font-family: 'Monaco', 'Menlo', 'Consolas', monospace;\r\n  border-bottom: 1px solid #f0f0f0;\r\n}\r\n\r\n.demo-ready__log-item:last-child {\r\n  border-bottom: none;\r\n}\r\n\r\n.demo-ready__canvas {\r\n  flex: 1;\r\n  border: 1px solid #e8e8e8;\r\n  border-radius: 8px;\r\n  overflow: hidden;\r\n  background: #fff;\r\n}\r\n</style>\r\n"