export default "<template>\r\n  <div class=\"demo-data-loaded\">\r\n    <!-- 事件日志面板 -->\r\n    <div class=\"demo-data-loaded__log\">\r\n      <div class=\"demo-data-loaded__log-header\">\r\n        <h4>事件日志</h4>\r\n        <button class=\"demo-data-loaded__clear-btn\" @click=\"clearLogs\" title=\"清除日志\">\r\n          清除\r\n        </button>\r\n      </div>\r\n      <div class=\"demo-data-loaded__log-content\">\r\n        <div v-for=\"(log, index) in logs\" :key=\"index\" class=\"demo-data-loaded__log-item\">\r\n          {{ log }}\r\n        </div>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- 画布容器 -->\r\n    <div class=\"demo-data-loaded__canvas\">\r\n      <div class=\"demo-data-loaded__controls\">\r\n        <button class=\"demo-data-loaded__btn\" @click=\"loadData\">\r\n          📥 加载示例数据\r\n        </button>\r\n        <button class=\"demo-data-loaded__btn\" @click=\"clearCanvas\">\r\n          🗑 清空画布\r\n        </button>\r\n      </div>\r\n      <FlowDesignerLayout\r\n        @ready=\"handleReady\"\r\n        :after-data-loaded=\"handleAfterDataLoaded\"\r\n      />\r\n    </div>\r\n  </div>\r\n</template>\r\n\r\n<script setup lang=\"ts\">\r\nimport { ref } from 'vue'\r\nimport FlowDesignerLayout from '@/components/FlowDesigner/FlowDesignerLayout.vue'\r\nimport type { FlowDesigner } from '@/components/FlowDesigner/core'\r\nimport type { Graph } from '@antv/x6'\r\nimport type { FlowData } from '@/components/FlowDesigner/types'\r\n\r\nconst logs = ref<string[]>([])\r\nconst designerRef = ref<FlowDesigner>()\r\n\r\n// 示例流程数据\r\nconst sampleData = {\r\n  meta: {\r\n    name: '示例流程',\r\n    version: '1.0.0',\r\n  },\r\n  nodes: [\r\n    {\r\n      id: 'start',\r\n      shape: 'rect',\r\n      x: 100,\r\n      y: 100,\r\n      width: 100,\r\n      height: 60,\r\n      data: { label: '开始' },\r\n      attrs: {\r\n        body: { fill: '#10B981', stroke: '#059669' },\r\n        label: { text: '开始', fill: '#fff' },\r\n      },\r\n    },\r\n    {\r\n      id: 'process1',\r\n      shape: 'rect',\r\n      x: 250,\r\n      y: 100,\r\n      width: 100,\r\n      height: 60,\r\n      data: { label: '处理1' },\r\n      attrs: {\r\n        body: { fill: '#5F95FF', stroke: '#2563EB' },\r\n        label: { text: '处理1', fill: '#fff' },\r\n      },\r\n    },\r\n    {\r\n      id: 'process2',\r\n      shape: 'rect',\r\n      x: 400,\r\n      y: 100,\r\n      width: 100,\r\n      height: 60,\r\n      data: { label: '处理2' },\r\n      attrs: {\r\n        body: { fill: '#F59E0B', stroke: '#D97706' },\r\n        label: { text: '处理2', fill: '#fff' },\r\n      },\r\n    },\r\n    {\r\n      id: 'end',\r\n      shape: 'rect',\r\n      x: 250,\r\n      y: 220,\r\n      width: 100,\r\n      height: 60,\r\n      data: { label: '结束' },\r\n      attrs: {\r\n        body: { fill: '#EF4444', stroke: '#DC2626' },\r\n        label: { text: '结束', fill: '#fff' },\r\n      },\r\n    },\r\n  ],\r\n  edges: [\r\n    {\r\n      id: 'edge1',\r\n      shape: 'flow-edge',\r\n      source: { cell: 'start' },\r\n      target: { cell: 'process1' },\r\n      data: { label: '步骤1' },\r\n      labels: ['步骤1'],\r\n    },\r\n    {\r\n      id: 'edge2',\r\n      shape: 'flow-edge',\r\n      source: { cell: 'process1' },\r\n      target: { cell: 'process2' },\r\n      data: { label: '步骤2' },\r\n      labels: ['步骤2'],\r\n    },\r\n    {\r\n      id: 'edge3',\r\n      shape: 'flow-edge',\r\n      source: { cell: 'process2' },\r\n      target: { cell: 'end' },\r\n      data: { label: '步骤3' },\r\n      labels: ['步骤3'],\r\n    },\r\n  ],\r\n  viewport: {\r\n    tx: 0,\r\n    ty: 0,\r\n    scale: 1,\r\n  },\r\n}\r\n\r\nfunction addLog(message: string) {\r\n  const timestamp = new Date().toLocaleTimeString()\r\n  logs.value.push(`[${timestamp}] ${message}`)\r\n}\r\n\r\nfunction clearLogs() {\r\n  logs.value = []\r\n}\r\n\r\nfunction handleReady(designer, graph) {\r\n  designerRef.value = designer\r\n  addLog('✅ 画布初始化完成')\r\n  addLog('💡 点击\"加载示例数据\"按钮')\r\n}\r\n\r\n/**\r\n * :after-data-loaded 钩子函数\r\n * 在 designer.load() 完成后触发\r\n */\r\nfunction handleAfterDataLoaded(data: FlowData): void {\r\n  addLog(`🟢 afterDataLoaded 钩子触发`)\r\n  addLog(`📦 流程名称: ${data.meta?.name || '未命名'}`)\r\n  addLog(`📊 节点数量: ${data.nodes?.length || 0}`)\r\n  addLog(`🔗 连线数量: ${data.edges?.length || 0}`)\r\n  addLog(`✅ 数据加载完成，画布已渲染`)\r\n\r\n  // 演示：可以在数据加载后执行额外操作\r\n  if (designerRef.value) {\r\n    const graph = designerRef.value.getGraph()\r\n    setTimeout(() => {\r\n      graph.centerContent()\r\n      addLog(`🎯 已自动居中显示`)\r\n    }, 100)\r\n  }\r\n}\r\n\r\nfunction loadData() {\r\n  if (!designerRef.value) {\r\n    addLog('⚠️ 画布尚未初始化')\r\n    return\r\n  }\r\n\r\n  addLog(`👆 用户点击\"加载示例数据\"`)\r\n  addLog(`📥 调用 designer.load()...`)\r\n\r\n  // 加载数据\r\n  designerRef.value.load(sampleData)\r\n}\r\n\r\nfunction clearCanvas() {\r\n  if (!designerRef.value) return\r\n\r\n  addLog(`👆 用户点击\"清空画布\"`)\r\n  const graph = designerRef.value.getGraph()\r\n  graph.clearCells()\r\n  addLog(`🗑 画布已清空`)\r\n}\r\n</script>\r\n\r\n<style scoped>\r\n.demo-data-loaded {\r\n  display: flex;\r\n  height: 100%; /* 修改：从固定高度改为 100%，支持全屏 */\r\n  min-height: 400px; /* 添加：最小高度，非全屏时保持合理尺寸 */\r\n  gap: 16px;\r\n}\r\n\r\n.demo-data-loaded__log {\r\n  width: 320px;\r\n  border: 1px solid #e8e8e8;\r\n  border-radius: 8px;\r\n  padding: 16px;\r\n  background: #fafafa;\r\n  overflow: hidden;\r\n  display: flex;\r\n  flex-direction: column;\r\n}\r\n\r\n.demo-data-loaded__log-header {\r\n  display: flex;\r\n  justify-content: space-between;\r\n  align-items: center;\r\n  margin-bottom: 12px;\r\n}\r\n\r\n.demo-data-loaded__log h4 {\r\n  margin: 0;\r\n  font-size: 14px;\r\n  color: #1a1a2e;\r\n  font-weight: 600;\r\n}\r\n\r\n.demo-data-loaded__clear-btn {\r\n  padding: 2px 8px;\r\n  font-size: 12px;\r\n  color: #666;\r\n  background: #fff;\r\n  border: 1px solid #d9d9d9;\r\n  border-radius: 4px;\r\n  cursor: pointer;\r\n  transition: all 0.2s;\r\n  user-select: none;\r\n}\r\n\r\n.demo-data-loaded__clear-btn:hover {\r\n  color: #1890ff;\r\n  border-color: #1890ff;\r\n}\r\n\r\n.demo-data-loaded__log-content {\r\n  flex: 1;\r\n  overflow-y: auto;\r\n  font-size: 12px;\r\n  line-height: 1.8;\r\n}\r\n\r\n.demo-data-loaded__log-item {\r\n  padding: 4px 0;\r\n  color: #555;\r\n  font-family: 'Monaco', 'Menlo', 'Consolas', monospace;\r\n  border-bottom: 1px solid #f0f0f0;\r\n}\r\n\r\n.demo-data-loaded__log-item:last-child {\r\n  border-bottom: none;\r\n}\r\n\r\n.demo-data-loaded__canvas {\r\n  flex: 1;\r\n  border: 1px solid #e8e8e8;\r\n  border-radius: 8px;\r\n  overflow: hidden;\r\n  background: #fff;\r\n  display: flex;\r\n  flex-direction: column;\r\n}\r\n\r\n.demo-data-loaded__controls {\r\n  display: flex;\r\n  gap: 12px;\r\n  padding: 12px;\r\n  background: #fff;\r\n  border-bottom: 1px solid #e8e8e8;\r\n}\r\n\r\n.demo-data-loaded__btn {\r\n  padding: 6px 16px;\r\n  font-size: 13px;\r\n  color: #fff;\r\n  background: #1677ff;\r\n  border: none;\r\n  border-radius: 4px;\r\n  cursor: pointer;\r\n  transition: all 0.2s;\r\n}\r\n\r\n.demo-data-loaded__btn:hover {\r\n  background: #0958d9;\r\n}\r\n</style>\r\n"