export default "<template>\n  <FlowDesignerLayout\n    @ready=\"handleReady\"\n  />\n</template>\n\n<script setup lang=\"ts\">\nimport { message } from 'ant-design-vue'\nimport FlowDesignerLayout from '../../../../components/FlowDesigner/FlowDesignerLayout.vue'\nimport type { FlowDesigner } from '../../../../components/FlowDesigner/core'\nimport type { Node } from '@antv/x6'\n\n/**\n * ready 回调：覆盖内置节点状态并初始化画布\n */\nfunction handleReady(designer: FlowDesigner) {\n  const graph = designer.getGraph()\n\n  // ========== 覆盖 3 种内置节点状态 ==========\n\n  // 1. 覆盖 default 状态：淡蓝色边框\n  designer.registerNodeStateHandler('default', {\n    apply(node) {\n      node.setAttrs({\n        body: {\n          stroke: '#3b82f6',\n          strokeWidth: 2,\n          fill: '#dbeafe',\n        },\n        label: {\n          fill: '#1e40af',\n          fontWeight: 'normal',\n        }\n      })\n    }\n  })\n\n  // 2. 覆盖 hover 状态：紫色加粗 + 阴影\n  designer.registerNodeStateHandler('hover', {\n    apply(node) {\n      node.setAttrs({\n        body: {\n          stroke: '#8b5cf6',\n          strokeWidth: 3,\n          fill: '#ede9fe',\n          filter: {\n            name: 'dropShadow',\n            args: { dx: 0, dy: 2, blur: 6, color: 'rgba(139, 92, 246, 0.4)' }\n          }\n        },\n        label: {\n          fill: '#5b21b6',\n          fontWeight: 'bold',\n        }\n      })\n    },\n    cleanup(node) {\n      node.setAttrs({\n        body: {\n          filter: null\n        }\n      })\n    }\n  })\n\n  // 3. 覆盖 selected 状态：青色粗边框 + 光晕\n  designer.registerNodeStateHandler('selected', {\n    apply(node) {\n      node.setAttrs({\n        body: {\n          stroke: '#06b6d4',\n          strokeWidth: 4,\n          fill: '#cffafe',\n          filter: {\n            name: 'dropShadow',\n            args: { dx: 0, dy: 0, blur: 8, color: 'rgba(6, 182, 212, 0.6)' }\n          }\n        },\n        label: {\n          fill: '#164e63',\n          fontWeight: 'bold',\n          fontSize: 14,\n        }\n      })\n    },\n    cleanup(node) {\n      node.setAttrs({\n        body: {\n          filter: null\n        }\n      })\n    }\n  })\n\n  // ========== 新增自定义状态 ==========\n\n  // 4. error 状态：红色粗边框 + 错误图标\n  designer.registerNodeStateHandler('error', {\n    apply(node) {\n      node.setAttrs({\n        body: {\n          stroke: '#ef4444',\n          strokeWidth: 4,\n          fill: '#fee2e2',\n          filter: {\n            name: 'dropShadow',\n            args: { dx: 0, dy: 2, blur: 8, color: 'rgba(239, 68, 68, 0.5)' }\n          }\n        },\n        label: {\n          fill: '#991b1b',\n          fontWeight: 'bold',\n        }\n      })\n\n      // 设置错误标记（可在插槽中使用）\n      const currentData = node.getData() || {}\n      node.setData({\n        ...currentData,\n        hasError: true,\n        errorMessage: '节点验证失败'\n      })\n    },\n    cleanup(node) {\n      // 恢复默认样式\n      node.setAttrs({\n        body: {\n          filter: null\n        }\n      })\n\n      // 清除错误标记\n      const currentData = node.getData() || {}\n      node.setData({\n        ...currentData,\n        hasError: false,\n        errorMessage: undefined\n      })\n    }\n  })\n\n  // ========== 创建演示节点 ==========\n\n  const node1 = graph.addNode({\n    id: 'node1',\n    shape: 'rect',\n    x: 80,\n    y: 80,\n    width: 140,\n    height: 70,\n    label: '默认状态',\n    attrs: {\n      label: {\n        fontSize: 14,\n      },\n    },\n  })\n  // 设置初始状态为 default\n  designer.setNodeState(node1, 'default')\n\n  const node2 = graph.addNode({\n    id: 'node2',\n    shape: 'rect',\n    x: 280,\n    y: 80,\n    width: 140,\n    height: 70,\n    label: '默认状态',\n    attrs: {\n      label: {\n        fontSize: 14,\n      },\n    },\n  })\n  designer.setNodeState(node2, 'default')\n\n  const node3 = graph.addNode({\n    id: 'node3',\n    shape: 'rect',\n    x: 480,\n    y: 80,\n    width: 140,\n    height: 70,\n    label: '默认状态',\n    attrs: {\n      label: {\n        fontSize: 14,\n      },\n    },\n  })\n  designer.setNodeState(node3, 'default')\n\n  const node4 = graph.addNode({\n    id: 'node4',\n    shape: 'rect',\n    x: 80,\n    y: 200,\n    width: 140,\n    height: 70,\n    label: '默认状态',\n    attrs: {\n      label: {\n        fontSize: 14,\n      },\n    },\n  })\n  designer.setNodeState(node4, 'default')\n\n  const node5 = graph.addNode({\n    id: 'node5',\n    shape: 'rect',\n    x: 280,\n    y: 200,\n    width: 140,\n    height: 70,\n    label: '默认状态',\n    attrs: {\n      label: {\n        fontSize: 14,\n      },\n    },\n  })\n  designer.setNodeState(node5, 'default')\n\n  const node6 = graph.addNode({\n    id: 'node6',\n    shape: 'rect',\n    x: 480,\n    y: 200,\n    width: 140,\n    height: 70,\n    label: '默认状态',\n    attrs: {\n      label: {\n        fontSize: 14,\n      },\n    },\n  })\n  designer.setNodeState(node6, 'default')\n\n  // ========== 添加连线 ==========\n\n  graph.addEdge({\n    id: 'edge1',\n    shape: 'flow-edge',\n    source: node1,\n    target: node2,\n    labels: ['流程1'],\n  })\n\n  graph.addEdge({\n    id: 'edge2',\n    shape: 'flow-edge',\n    source: node2,\n    target: node3,\n    labels: ['流程2'],\n  })\n\n  graph.addEdge({\n    id: 'edge3',\n    shape: 'flow-edge',\n    source: node1,\n    target: node4,\n    labels: ['流程3'],\n  })\n\n  graph.addEdge({\n    id: 'edge4',\n    shape: 'flow-edge',\n    source: node4,\n    target: node5,\n    labels: ['流程4'],\n  })\n\n  graph.addEdge({\n    id: 'edge5',\n    shape: 'flow-edge',\n    source: node5,\n    target: node6,\n    labels: ['流程5'],\n  })\n\n  // 居中显示\n  graph.centerContent()\n\n  // ========== 添加交互：单击切换内置状态，双击切换到 error 状态 ==========\n\n  const builtinStates = ['default', 'hover', 'selected']\n  const stateMap = new Map<string, number>() // 记录每个节点的当前状态索引\n\n  // 双击事件：切换到 error 状态或恢复到 default 状态\n  graph.on('node:dblclick', ({ node }) => {\n    const currentState = node.getProp('_state') || 'default'\n\n    if (currentState === 'error') {\n      // 如果已经是 error，恢复到 default\n      designer.setNodeState(node, 'default')\n      stateMap.set(node.id, 0) // 重置索引\n      message.success('节点已恢复到默认状态')\n    } else {\n      // 切换到 error 状态\n      designer.setNodeState(node, 'error')\n      message.error('节点已设置为错误状态（双击可恢复）')\n    }\n  })\n\n  console.log('[Demo] 节点状态管理示例已加载（覆盖内置状态）')\n  message.success('已覆盖 3 种内置节点状态，单击切换状态，双击切换 error 状态')\n}\n</script>\n"