export default "<template>\r\n  <div class=\"demo-slot-toolbar\">\r\n    <!-- 事件日志面板 -->\r\n    <div class=\"demo-slot-toolbar__log\">\r\n      <div class=\"demo-slot-toolbar__log-header\">\r\n        <h4>事件日志</h4>\r\n        <button class=\"demo-slot-toolbar__clear-btn\" @click=\"clearLogs\" title=\"清除日志\">\r\n          清除\r\n        </button>\r\n      </div>\r\n      <div class=\"demo-slot-toolbar__log-content\">\r\n        <div v-for=\"(log, index) in logs\" :key=\"index\" class=\"demo-slot-toolbar__log-item\">\r\n          {{ log }}\r\n        </div>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- 画布容器 -->\r\n    <div class=\"demo-slot-toolbar__canvas\">\r\n      <FlowDesignerLayout\r\n        mode=\"design\"\r\n        @ready=\"handleReady\"\r\n      >\r\n        <!-- 顶部工具栏 -->\r\n        <template #toolbar=\"scope\">\r\n          <Toolbar\r\n              :zoom-percent=\"scope.zoomPercent\"\r\n              :has-selection=\"scope.hasSelection\"\r\n              :can-paste=\"scope.canPaste\"\r\n              :can-group=\"scope.canGroup\"\r\n              :can-ungroup=\"scope.canUngroup\"\r\n              :can-undo=\"scope.canUndo\"\r\n              :can-redo=\"scope.canRedo\"\r\n              :designer-mode=\"scope.currentMode\"\r\n              @undo=\"scope.onUndo\"\r\n              @redo=\"scope.onRedo\"\r\n              @zoom-in=\"scope.onZoomIn\"\r\n              @zoom-out=\"scope.onZoomOut\"\r\n              @zoom-to=\"scope.onZoomTo\"\r\n              @fit-view=\"scope.onFitView\"\r\n              @reset-view=\"scope.onResetView\"\r\n              @copy=\"scope.onCopy\"\r\n              @paste=\"scope.onPaste\"\r\n              @to-front=\"scope.onToFront\"\r\n              @to-back=\"scope.onToBack\"\r\n              @align-left=\"scope.onAlignLeft\"\r\n              @align-right=\"scope.onAlignRight\"\r\n              @align-top=\"scope.onAlignTop\"\r\n              @align-bottom=\"scope.onAlignBottom\"\r\n              @group=\"scope.onGroup\"\r\n              @ungroup=\"scope.onUngroup\"\r\n              @export=\"scope.onExport\"\r\n              @import=\"scope.onImport\"\r\n              @open-settings=\"scope.onOpenSettings\"\r\n              @mode-change=\"scope.onModeChange\"\r\n          />\r\n        </template>\r\n      </FlowDesignerLayout>\r\n    </div>\r\n  </div>\r\n</template>\r\n\r\n<script setup lang=\"ts\">\r\nimport { ref } from 'vue'\r\nimport FlowDesignerLayout from '@/components/FlowDesigner/FlowDesignerLayout.vue'\r\nimport type { FlowDesigner } from '@/components/FlowDesigner/core'\r\nimport type { Graph } from '@antv/x6'\r\nimport Toolbar from './components/Toolbar.vue'\r\n\r\nconst logs = ref<string[]>([])\r\n\r\nfunction addLog(message: string) {\r\n  const timestamp = new Date().toLocaleTimeString()\r\n  logs.value.push(`[${timestamp}] ${message}`)\r\n}\r\n\r\nfunction clearLogs() {\r\n  logs.value = []\r\n}\r\n\r\nfunction getModeLabel(mode: string): string {\r\n  const labels: Record<string, string> = {\r\n    design: '✏️ 设计',\r\n    readonly: '👁 只读',\r\n    preview: '📺 预览',\r\n  }\r\n  return labels[mode] || mode\r\n}\r\n\r\nfunction handleReady(designer: FlowDesigner, graph: Graph) {\r\n  addLog('✅ 画布初始化完成')\r\n  addLog('🎨 自定义工具栏已渲染')\r\n\r\n  // 添加初始节点\r\n  const node1 = graph.createNode({\r\n    shape: 'rect',\r\n    x: 30,\r\n    y: 30,\r\n    width: 100,\r\n    height: 60,\r\n    label: `节点1`,\r\n    attrs: {\r\n      body: {\r\n        fill: '#5F95FF',\r\n        stroke: '#2563EB',\r\n        strokeWidth: 2,\r\n        rx: 6,\r\n        ry: 6,\r\n      },\r\n      label: {\r\n        fill: '#fff',\r\n        fontSize: 14,\r\n        fontWeight: 500,\r\n      },\r\n    },\r\n  });\r\n  designer.addCell(node1)\r\n  addLog(`➕ 添加节点1`);\r\n\r\n  const node2 = graph.createNode({\r\n    shape: 'rect',\r\n    x: 130,\r\n    y: 130,\r\n    width: 100,\r\n    height: 60,\r\n    label: `节点2  `,\r\n    attrs: {\r\n      body: {\r\n        fill: '#fc01b4',\r\n        stroke: '#7c0073',\r\n        strokeWidth: 2,\r\n        rx: 6,\r\n        ry: 6,\r\n      },\r\n      label: {\r\n        fill: '#fff',\r\n        fontSize: 14,\r\n        fontWeight: 500,\r\n      },\r\n    },\r\n  });\r\n  designer.addCell(node2)\r\n  addLog(`➕ 添加节点2`);\r\n\r\n\r\n\r\n  //graph.centerContent()\r\n}\r\n\r\nfunction handleUndo(undoFn: () => void) {\r\n  addLog('↶ 执行撤销操作')\r\n  undoFn()\r\n}\r\n\r\nfunction handleRedo(redoFn: () => void) {\r\n  addLog('↷ 执行重做操作')\r\n  redoFn()\r\n}\r\n\r\nfunction handleZoomIn(zoomInFn: () => void) {\r\n  addLog('🔍 放大画布')\r\n  zoomInFn()\r\n}\r\n\r\nfunction handleZoomOut(zoomOutFn: () => void) {\r\n  addLog('🔍 缩小画布')\r\n  zoomOutFn()\r\n}\r\n\r\nfunction handleZoomToFit(zoomToFitFn: () => void) {\r\n  addLog('⊡ 适应画布')\r\n  zoomToFitFn()\r\n}\r\n</script>\r\n\r\n<style scoped>\r\n.demo-slot-toolbar {\r\n  display: flex;\r\n  height: 100%;\r\n  min-height: 450px;\r\n  gap: 16px;\r\n}\r\n\r\n.demo-slot-toolbar__log {\r\n  width: 280px;\r\n  border: 1px solid #e8e8e8;\r\n  border-radius: 8px;\r\n  padding: 16px;\r\n  background: #fafafa;\r\n  overflow: hidden;\r\n  display: flex;\r\n  flex-direction: column;\r\n}\r\n\r\n.demo-slot-toolbar__log-header {\r\n  display: flex;\r\n  justify-content: space-between;\r\n  align-items: center;\r\n  margin-bottom: 12px;\r\n}\r\n\r\n.demo-slot-toolbar__log h4 {\r\n  margin: 0;\r\n  font-size: 14px;\r\n  color: #1a1a2e;\r\n  font-weight: 600;\r\n}\r\n\r\n.demo-slot-toolbar__clear-btn {\r\n  padding: 2px 8px;\r\n  font-size: 12px;\r\n  color: #666;\r\n  background: #fff;\r\n  border: 1px solid #d9d9d9;\r\n  border-radius: 4px;\r\n  cursor: pointer;\r\n  transition: all 0.2s;\r\n  user-select: none;\r\n}\r\n\r\n.demo-slot-toolbar__clear-btn:hover {\r\n  color: #1890ff;\r\n  border-color: #1890ff;\r\n}\r\n\r\n.demo-slot-toolbar__log-content {\r\n  flex: 1;\r\n  overflow-y: auto;\r\n  font-size: 12px;\r\n  line-height: 1.8;\r\n}\r\n\r\n.demo-slot-toolbar__log-item {\r\n  padding: 4px 0;\r\n  color: #555;\r\n  font-family: 'Monaco', 'Menlo', 'Consolas', monospace;\r\n  border-bottom: 1px solid #f0f0f0;\r\n}\r\n\r\n.demo-slot-toolbar__log-item:last-child {\r\n  border-bottom: none;\r\n}\r\n\r\n.demo-slot-toolbar__canvas {\r\n  flex: 1;\r\n  border: 1px solid #e8e8e8;\r\n  border-radius: 8px;\r\n  overflow: hidden;\r\n  background: #fff;\r\n}\r\n\r\n/* ==================== 自定义工具栏样式 ==================== */\r\n.custom-toolbar {\r\n  display: flex;\r\n  align-items: center;\r\n  gap: 12px;\r\n  padding: 8px 16px;\r\n  background: linear-gradient(to bottom, #ffffff, #f9fafb);\r\n  border-bottom: 1px solid #e8e8e8;\r\n  box-shadow: 0 1px 4px rgba(0, 0, 0, 0.04);\r\n}\r\n\r\n.custom-toolbar__section {\r\n  display: flex;\r\n  align-items: center;\r\n  gap: 8px;\r\n}\r\n\r\n.custom-toolbar__divider {\r\n  width: 1px;\r\n  height: 20px;\r\n  background: #e8e8e8;\r\n}\r\n\r\n.custom-toolbar__label {\r\n  font-size: 13px;\r\n  color: #666;\r\n  font-weight: 500;\r\n}\r\n\r\n.custom-toolbar__badge {\r\n  padding: 3px 10px;\r\n  border-radius: 12px;\r\n  font-size: 12px;\r\n  font-weight: 500;\r\n  background: #f0f0f0;\r\n  color: #555;\r\n}\r\n\r\n.custom-toolbar__badge--design {\r\n  background: #e6f7ff;\r\n  color: #1677ff;\r\n}\r\n\r\n.custom-toolbar__badge--readonly {\r\n  background: #fff7e6;\r\n  color: #fa8c16;\r\n}\r\n\r\n.custom-toolbar__badge--preview {\r\n  background: #f6ffed;\r\n  color: #52c41a;\r\n}\r\n\r\n.custom-toolbar__btn {\r\n  display: flex;\r\n  align-items: center;\r\n  gap: 4px;\r\n  padding: 5px 12px;\r\n  font-size: 13px;\r\n  color: #555;\r\n  background: #fff;\r\n  border: 1px solid #d9d9d9;\r\n  border-radius: 4px;\r\n  cursor: pointer;\r\n  transition: all 0.2s;\r\n  font-weight: 500;\r\n  user-select: none;\r\n}\r\n\r\n.custom-toolbar__btn:hover:not(:disabled) {\r\n  color: #1677ff;\r\n  border-color: #1677ff;\r\n  background: #f0f7ff;\r\n}\r\n\r\n.custom-toolbar__btn:active:not(:disabled) {\r\n  transform: translateY(1px);\r\n}\r\n\r\n.custom-toolbar__btn:disabled {\r\n  color: #bbb;\r\n  border-color: #e8e8e8;\r\n  background: #f5f5f5;\r\n  cursor: not-allowed;\r\n  opacity: 0.6;\r\n}\r\n\r\n.custom-toolbar__btn--icon {\r\n  padding: 5px 10px;\r\n  min-width: 32px;\r\n  justify-content: center;\r\n}\r\n\r\n.custom-toolbar__icon {\r\n  font-size: 16px;\r\n  line-height: 1;\r\n  font-weight: bold;\r\n}\r\n\r\n.custom-toolbar__zoom-display {\r\n  min-width: 50px;\r\n  text-align: center;\r\n  font-size: 13px;\r\n  font-weight: 600;\r\n  color: #1677ff;\r\n  padding: 4px 8px;\r\n  border-radius: 4px;\r\n  background: #f0f7ff;\r\n  cursor: pointer;\r\n  user-select: none;\r\n  transition: all 0.2s;\r\n}\r\n\r\n.custom-toolbar__zoom-display:hover {\r\n  background: #e6f0ff;\r\n}\r\n</style>\r\n"